# Curated common color names → RGB. Qt's QColor(name) handles many of these
# natively, but we keep the table explicit so the receipt names the chosen
# colour ("orange", "gold") rather than a hex string.
_NAMED_COLORS = {
    "red":          (235,  60,  60),
    "crimson":      (220,  20,  60),
    "pink":         (255, 130, 180),
    "magenta":      (255,  40, 220),
    "purple":       (180,  90, 240),
    "violet":       (160, 110, 240),
    "indigo":       (110,  90, 230),
    "blue":         (100, 160, 255),
    "sky":          (140, 200, 255),
    "cyan":         ( 70, 220, 235),
    "teal":         ( 80, 220, 200),
    "turquoise":    ( 80, 220, 200),
    "green":        (110, 230, 140),
    "lime":         (180, 245, 110),
    "yellow":       (250, 230, 110),
    "gold":         (255, 200,  90),
    "orange":       (255, 160,  70),
    "amber":        (255, 180,  70),
    "brown":        (190, 130,  90),
    "white":        (245, 245, 250),
    "silver":       (210, 210, 220),
    "grey":         (170, 170, 180),
    "gray":         (170, 170, 180),
    "black":        ( 30,  30,  35),
}

# Hex form: #rgb or #rrggbb (Qt-compatible).
_HEX_COLOR_RE = re.compile(r"#([0-9a-fA-F]{3}|[0-9a-fA-F]{6})\b")

# Natural-language intent regex. Tolerant of:
#   "Alice change my font color to orange"
#   "Alice make my text blue"
#   "change my font to gold"
#   "my font color: red"
#   "make my chat text purple please"
_OWNER_CHAT_COLOR_INTENT_RE = re.compile(
    r"""
    (?:^|\b)                                     # boundary
    (?:alice[,\s]+)?                             # optional "Alice,"
    (?:
        (?:change|make|set|turn)\s+              # verb
        (?:my\s+)?
        (?:font|text|chat|message|writing|words?)
        \s*(?:colou?r)?\s*                       # optional "color"
        (?:to|=|:|->)?\s*
      |
        (?:my\s+)?(?:font|text|chat)\s+colou?r\s*(?:to|=|:|->)\s*
    )
    (?P<color>\#[0-9a-fA-F]{3,6}|[a-zA-Z][a-zA-Z\s\-]{1,18})
    """,
    re.IGNORECASE | re.VERBOSE,
)


def _coerce_rgb(token: str) -> Optional[Tuple[int, int, int]]:
    """Map an owner-typed colour token → RGB tuple. Returns None if no match."""
    if not token:
        return None
    t = token.strip().lower()
    # Strip a trailing word like "please" / "thanks" the regex may have caught.
    t = re.sub(r"\s+(please|thanks|thank you|now|today)\s*$", "", t).strip()
    # Hex?
    m = _HEX_COLOR_RE.match(t if t.startswith("#") else "#" + t)
    if m:
        hx = m.group(1)
        if len(hx) == 3:
            r, g, b = (int(c * 2, 16) for c in hx)
        else:
            r, g, b = (int(hx[i:i + 2], 16) for i in (0, 2, 4))
        return (r, g, b)
    # Named?
    if t in _NAMED_COLORS:
        return _NAMED_COLORS[t]
    # Multi-word: "light blue" / "dark green" — fall back to last word
    if " " in t:
        tail = t.split()[-1]
        if tail in _NAMED_COLORS:
            return _NAMED_COLORS[tail]
    return None


def _load_owner_chat_prefs_raw() -> Dict[str, Any]:
    try:
        if _OWNER_CHAT_PREFS_PATH.exists():
            return json.loads(_OWNER_CHAT_PREFS_PATH.read_text(encoding="utf-8"))
    except Exception:
        pass
    return {}


def _save_owner_chat_prefs_raw(prefs: Dict[str, Any]) -> None:
    try:
        _OWNER_CHAT_PREFS_PATH.parent.mkdir(parents=True, exist_ok=True)
        _OWNER_CHAT_PREFS_PATH.write_text(
            json.dumps(prefs, indent=2, sort_keys=True),
            encoding="utf-8",
        )
    except Exception:
        pass


def _write_chat_pref_receipt(kind: str, payload: Dict[str, Any]) -> str:
    """Append a receipt to .sifta_state/work_receipts.jsonl. Returns receipt id."""
    rid = uuid.uuid4().hex[:16]
    row = {
        "ts": time.time(),
        "receipt_id": rid,
        "kind": kind,
        "writer": "sifta_talk_to_alice_widget._owner_chat_pref",
        "truth_label": "OWNER_CHAT_PREF_V1",
        "payload": payload,
    }
    try:
        receipts = _REPO / ".sifta_state" / "work_receipts.jsonl"
        receipts.parent.mkdir(parents=True, exist_ok=True)
        with receipts.open("a", encoding="utf-8") as f:
            f.write(json.dumps(row) + "\n")
    except Exception:
        pass
    return rid


class _WallpaperTextEdit(QTextEdit):
    """QTextEdit with a real viewport-painted background image.

    Qt stylesheets and QPalette brushes can lose to QTextEdit's internal
    document/viewport painting on macOS. Painting the pixmap ourselves before
    the base text paint keeps the wallpaper visible while preserving normal
    selection, scrolling, and text rendering.
    """

    localAnchorClicked = pyqtSignal(str)

    def __init__(self, *args: Any, **kwargs: Any) -> None:
        super().__init__(*args, **kwargs)
        self._wallpaper_pixmap = QPixmap()
        self.setAutoFillBackground(False)
        self.viewport().setAutoFillBackground(False)
        self.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground, True)
        self.viewport().setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground, True)
        try:
            self.document().setDefaultStyleSheet("body { background: transparent; }")
        except Exception:
            pass

    def set_wallpaper_path(self, path: str | Path) -> bool:
        pixmap = QPixmap(str(path))
        if pixmap.isNull():
            self._wallpaper_pixmap = QPixmap()
            self.viewport().update()
            return False
        self._wallpaper_pixmap = pixmap
        self.viewport().update()
        return True

    def paintEvent(self, event: Any) -> None:  # type: ignore[override]
        if not self._wallpaper_pixmap.isNull():
            painter = QPainter(self.viewport())
            try:
                rect = self.viewport().rect()
                scaled = self._wallpaper_pixmap.scaled(
                    rect.size(),
                    Qt.AspectRatioMode.KeepAspectRatioByExpanding,
                    Qt.TransformationMode.SmoothTransformation,
                )
                x = (rect.width() - scaled.width()) // 2
                y = (rect.height() - scaled.height()) // 2
                painter.drawPixmap(x, y, scaled)
                # Round 58 readability: the wallpaper is identity, not the
                # transcript surface. Keep a faint trace of it, but put an
                # IDE-grade dark plate behind every chat line so text never
                # fights the bright matrix image.
                painter.fillRect(rect, QColor(5, 7, 14, 218))
            finally:
                painter.end()
        super().paintEvent(event)

    def mouseReleaseEvent(self, event: Any) -> None:  # type: ignore[override]
        try:
            pos = event.position().toPoint() if hasattr(event, "position") else event.pos()
            anchor = str(self.anchorAt(pos) or "")
        except Exception:
            anchor = ""
        if anchor:
            try:
                self.localAnchorClicked.emit(anchor)
                event.accept()
                return
            except Exception:
                pass
        super().mouseReleaseEvent(event)


def _json_tool_call_block(tool_name: str, params: Dict[str, Any]) -> str:
    """Return router-parseable JSON tool-call syntax.

    Use this for values that can contain pipes, brackets, newlines, or code.
    The bracket syntax is fine for tiny scalar params; it is not a safe carrier
    for source code.
    """
    payload = {"tool": tool_name}
    payload.update(params)
    return "```tool_call\n" + json.dumps(payload, ensure_ascii=False) + "\n```"


def _is_grok_status_or_receipt_question(user_text: str) -> bool:
    """True when the owner is asking Alice to recall Grok state, not operate Grok."""
    text = (user_text or "").strip()
    if not text or not re.search(r"\bgrok\b", text, re.IGNORECASE):
        return False
    # Explicit delegation/opening verbs are real tool actions. Let those keep the
    # deterministic effector path; only memory/status questions should reach the
    # cortex with the memory-card context.
    if re.search(
        r"\b(?:ask|call|use|tell|send\s+to|query|consult)\s+grok\b"
        r"|\b(?:open|start|launch|type|run|bring\s+up|talk\s+to)\s+(?:the\s+)?grok\b",
        text,
        re.IGNORECASE,
    ):
        return False
    return bool(
        re.search(
            r"\b(?:did|do|does|was|were|is|are|have|has|what|which|where|when|show|tell)\b",
            text,
            re.IGNORECASE,
        )
        and re.search(
            r"\b(?:resume|resumed|run|ran|execute|executed|finish|finished|done|receipt|"
            r"capture|result|status|last|proof|id)\b",
            text,
            re.IGNORECASE,
        )
    )


def _is_arm_delegation_meta_question(user_text: str, arm_pattern: str) -> bool:
    """True when owner asks *about* arm usage, not to dispatch it."""
    text = (user_text or "").strip()
    if not text:
        return False
    # Real delegation requests keep deterministic routing, even when phrased as a
    # question ("can you ask codex to ...?").
    if re.search(
        rf"\b(?:ask|call|use|tell|send\s+to|query|consult)\s+{arm_pattern}\b\s+to\b",
        text,
        re.IGNORECASE,
    ):
        return False
    return bool(
        re.search(
            rf"\b(?:how\s+to\s+ask|how\s+do\s+i\s+ask|do\s+you\s+know\s+how\s+to\s+ask|"
            rf"what\s+is|who\s+is)\s+{arm_pattern}\b(?:\s+arm)?\b",
            text,
            re.IGNORECASE,
        )
    )


def _natural_arm_delegation_requires_cortex(user_text: str) -> bool:
    """True when owner is asking Alice to decide an arm dispatch in natural language."""
    text = (user_text or "").strip()
    if not text:
        return False
    if _is_grok_status_or_receipt_question(text):
        return False
    if any(
        _is_arm_delegation_meta_question(text, pattern)
        for pattern in (
            r"grok",
            r"(?:(?:your|the)\s+)?(?:hermes|hemes)",
            r"(?:(?:your|the)\s+)?claude(?:\s+code)?",
            r"(?:(?:your|the)\s+)?codex",
        )
    ):
        return False
    arm = r"(?:(?:your|the)\s+)?(?:grok|codex|claude(?:\s+code)?|hermes|hemes)\b(?:\s+arm)?"
    return bool(
        re.search(
            rf"\b(?:dispatch|ask|call|use|tell|send\s+to|query|consult|open|start|launch|resume|type|run|bring(?:\s+up)?|talk\s+to)\s+{arm}",
            text,
            re.IGNORECASE,
        )
        or re.search(
            rf"\b{arm}\b.{0,80}\b(?:code|build|patch|land|execute|verify|fix|wire|test|receipt)",
            text,
            re.IGNORECASE | re.DOTALL,
        )
    )


def _allow_pre_cortex_chat_reflexes() -> bool:
    """Return True only when legacy conversational shortcuts are explicitly enabled.

    r1460 (George 2026-06-20): default OFF — every owner turn composes through
    cortex. Useful body facts become prompt context + receipts; swimmers decide.
    Deterministic template speech belongs in the Deterministic Tracker app, not
    Alice's mouth. Set SIFTA_ALLOW_PRE_CORTEX_CHAT_REFLEXES=1 to revive the
    legacy reflex mall for regression only.
    """
    return os.environ.get("SIFTA_ALLOW_PRE_CORTEX_CHAT_REFLEXES", "").strip().lower() in {
        "1",
        "true",
        "yes",
        "on",
    }


def _typed_browser_navigate_effector_allowed(*, typed_turn: bool, text: str) -> bool:
    """Typed browser URL navigate is cortex context, not an automatic effector.

    r1458: typed text is owner intent, not permission for a deterministic
    pre-cortex shortcut. This helper still detects useful browser intent so it
    can be injected into the cortex prompt; execution stays behind the explicit
    pre-cortex reflex opt-in.
    """
    if not typed_turn:
        return False
    clean = " ".join((text or "").strip().split())
    if not clean:
        return False
    try:
        from System.swarm_browser_context import (
            explicit_owner_url_open_fast_reply,
            owner_wants_youtube_navigate,
            owner_youtube_recall_open_fast_reply,
            watched_memory_fast_reply,
        )

        if explicit_owner_url_open_fast_reply(clean).get("open_url"):
            return True
        if owner_youtube_recall_open_fast_reply(clean).get("open_url"):
            return True
        if watched_memory_fast_reply(clean).get("open_url"):
            return True
        return bool(owner_wants_youtube_navigate(clean))
    except Exception:
        return False


def _typed_direct_key_command_to_matrix_pty(
    user_text: str,
    *,
    typed_turn: bool,
    pane: Any = None,
) -> dict[str, Any]:
    """Route a typed owner keystroke command to the focused Matrix PTY.

    This is an effector handoff, not a chat reply. Spoken turns stay with the
    cortex because "press enter" is too easy for STT to hallucinate.
    """
    if not typed_turn:
        return {"executed": False, "reason": "not_typed_turn"}
    try:
        from System.swarm_direct_command_router import classify_as_direct_command

        command = classify_as_direct_command(user_text)
    except Exception as exc:
        return {
            "executed": False,
            "reason": "router_unavailable",
            "error": type(exc).__name__,
        }
    if not getattr(command, "is_direct", False):
        return {"executed": False, "reason": "not_direct_key_command"}
    if getattr(command, "command_type", "") != "keystroke":
        return {"executed": False, "reason": "not_keystroke_command"}
    key_text = str(getattr(command, "key_or_text", "") or "")
    if not key_text:
        return {"executed": False, "reason": "empty_keystroke"}

    if pane is None:
        try:
            from Applications.sifta_matrix_terminal import get_focused_matrix_terminal_pane

            pane = get_focused_matrix_terminal_pane()
        except Exception as exc:
            return {
                "executed": False,
                "reason": "matrix_terminal_unavailable",
                "error": type(exc).__name__,
            }
    if pane is None:
        return {"executed": False, "reason": "no_focused_matrix_pty"}

    payload = {
        "raw_input": user_text,
        "command_type": getattr(command, "command_type", ""),
        "key_repr": repr(key_text),
        "source": "talk_widget_typed_turn",
    }
    try:
        append_trace = getattr(pane, "_append_process_trace", None)
        if callable(append_trace):
            append_trace(
                f"Talk direct key -> Matrix PTY: {user_text}",
                kind="direct_key",
                action="talk_direct_key_command",
                payload=payload,
            )
        pane.write_bytes(key_text.encode("utf-8", "replace"))
    except Exception as exc:
        return {
            "executed": False,
            "reason": "pty_write_failed",
            "error": type(exc).__name__,
            "payload": payload,
        }
    return {"executed": True, "reason": "direct_key_written", "payload": payload}


def _owner_direct_read_tool_request(user_text: str) -> str:
    """Return a deterministic tool call for explicit owner tool turns."""
    text = (user_text or "").strip()
    if not text:
        return ""

    try:
        from System.swarm_tool_router import TOOL_REGISTRY, parse_tool_calls

        calls = parse_tool_calls(text)
        if calls:
            for call in calls:
                spec = TOOL_REGISTRY.get(call.tool_name)
                if spec is None or spec.write_action:
                    return ""
            return text
    except Exception:
        pass

    if not _allow_pre_cortex_chat_reflexes():
        return ""

    # Round 47 (Architect 2026-05-27): natural-language arm delegation is
    # cognitive work. Alice's cortex must read the owner turn and decide the
    # arm dispatch; this router may only execute explicit tool-call syntax
    # after the cortex emits it.
    if _natural_arm_delegation_requires_cortex(text):
        return ""
    if _owner_effector_requires_cortex_first(text):
        return ""

    lowered = text.casefold()
    if (
        "ollama" in lowered
        and "tool" in lowered
        and "model" in lowered
        and any(word in lowered for word in ("list", "show", "check", "installed", "inventory"))
    ):
        return (
            "[TOOL_CALL: ollama_inventory | "
            "cost_justification=George asked for installed Ollama model inventory receipt]"
        )
    memory_digest_intent = any(
        phrase in lowered
        for phrase in (
            "what did i teach you today",
            "what have i taught you today",
            "what you taught me today",
            "what george taught alice today",
            "what did george teach alice today",
            "architect memory digest",
            "memory digest",
            "remember what i taught",
            "recap what i taught",
            "daily teaching digest",
        )
    )
    if memory_digest_intent:
        return (
            "[TOOL_CALL: architect_memory_digest | period=today | max_items=10 | "
            "write_artifact=true | "
            "cost_justification=George asked Alice for the receipt-backed daily memory digest of what he taught her]"
        )
    self_vector_intent = any(
        phrase in lowered
        for phrase in (
            "alice, what do you know right now",
            "what do you know right now",
            "what do you know now",
            "what do you know in this moment",
            "current alice self vector",
            "alice self vector",
            "current self-state vector",
            "current self state vector",
        )
    )
    if self_vector_intent:
        return (
            "[TOOL_CALL: alice_self_vector | window_hours=24 | max_items=12 | "
            "write_artifact=true | "
            "cost_justification=George asked Alice for her deterministic observed self-state vector]"
        )
    capability_inventory_intent = any(
        phrase in lowered
        for phrase in (
            "what skills",
            "which skills",
            "list skills",
            "show skills",
            "skill status",
            "available skills",
            "what capabilities",
            "which capabilities",
            "list capabilities",
            "show capabilities",
            "capability status",
            "what tools",
            "which tools",
            "list tools",
            "show tools",
            "what can you do",
            "what can you use",
            "do you know all skills",
            "hermes skills",
            "hermes app skills",
            # Cowork CW47 2026-05-16 — apps are capabilities too.
            # Architect: "she does not even know she is an operating
            # system and she does not even know she has apps."
            "what apps",
            "which apps",
            "list apps",
            "show apps",
            "available apps",
            "apps you have",
            "apps do you have",
            "applications you have",
            "your apps",
            "your applications",
            "installed apps",
            "what applications",
            "list applications",
            "show applications",
            "what's installed",
            "what is installed",
            "operating system",
            "you are an operating system",
            "you are an os",
            "you have apps",
            "do you have apps",
        )
    )
    if capability_inventory_intent:
        safe_query = text.replace("|", " ").replace("]", " ")[:240]
        return (
            "[TOOL_CALL: capability_field_status | "
            f"query={safe_query} | limit=60 | "
            "cost_justification=George asked Alice to inspect her unified tools and skills capability field]"
        )

    # ── Global chat → visible Grok tool bridge (ACTION-DELEGATION REFLEX v2) ─────
    # One Alice / one global chat. Per owner covenant + Tao verification layers:
    # "ask/tell/send ... grok" (delegation carrying a question) → ALWAYS route to
    # delegation organ FIRST. This suppresses greeting/identity fallbacks even if
    # no Matrix Terminal pane is currently focused. The reflex writes the stigmergic
    # intent receipt + ledger entry unconditionally.
    # Pure "open/start grok" (launch without delegated question) remains best-effort
    # (pane-gated) to preserve direct PTY drive intents and existing tests.
    # Live GROK_RESULT capture when pane present; ledger always records for pickup.
    # No double-spend ASCII swimmers. High-dim field. Owner protected.
    #
    # Physics nuggets metabolized (owner paper trail + Susskind/ER=EPR/Complexity/LQG/Holography):
    # 1. Landscape = hypothesis field: many possible interpretations of the owner's
    #    request exist; only the receipted, owner-grounded delegation that reaches
    #    visible PTY capture and posts matching-hash GROK_RESULT becomes "real" in
    #    the global boundary ledger. The rest stay counterfactual. (Susskind hep-th/0302219)
    # 2. ER=EPR = delegation bridge, not identity merge: the receipt (delegation_receipt
    #    ↔ GROK_RESULT with delegation_receipt_id) entangles the external cortex
    #    (Grok) to Alice without ever making Grok part of the organism. The comments
    #    and topology/hard-recall enforce separation. Entanglement = relation. (Maldacena/Susskind 1306.0533)
    # 3. Complexity growth = visible process trace: when the PTY drives Grok, every
    #    chunk, read, tool use, elapsed time, heartbeat is emitted as explicit action
    #    growth ([GROK LIVE], grok_capture_heartbeat, process trace). No black box.
    #    (Brown et al. 1509.07876)
    # 4. LQG = atomic receipts: every delegation and capture event is discrete
    #    (ts, receipt, capture_id, seq, byte spans, hash, parent via delegation_receipt_id,
    #    surface="matrix_terminal"). The global chat row is the inspectable quantum.
    #    (Rovelli/Smolin gr-qc/9411005)
    # 5. Holography = global chat as boundary: the one global alice_conversation.jsonl
    #    is the screen. If the interior (Grok thinking in PTY) does not appear there
    #    with full captured_text + hash + span proof, it is not proven for the field.
    #    This is why the PTY capture + _log_global_terminal_turn is the non-negotiable
    #    final step. (ER=EPR + holographic principle)
    #
    # The strongest upgrade is not "string theory failed" — it is many possible worlds,
    # one receipted boundary, discrete proof events, no identity merge across bridges.
    # Coded in the reflex, the ledger, the capture organ, the verifier gate.
    grok_delegation = re.search(r"\b(?:ask|call|use|tell|send\s+to)\s+grok\b", text, re.IGNORECASE)
    grok_open = re.search(
        r"\b(?:open|start|launch|resume|type|run|bring\s+up|talk\s+to)\s+(?:the\s+)?grok\b"
        r"|\bgrok\b.{0,80}\b(?:terminal|cli|screen|screens|session|resume|bypass|select|selection)\b",
        text,
        re.IGNORECASE | re.DOTALL,
    )
    if _is_grok_status_or_receipt_question(text):
        return ""

    # ── RETIRED NATURAL CORTEX SWITCH REFLEX ─────────────────────────────
    # r334 (George 2026-06-02): "I talk to Alice. Alice thinks first."
    # A natural-language cortex switch is a continuity transition, so the
    # active cortex must reason and leave a diary trace BEFORE the model is
    # changed. This direct reflex remains here for archaeology but is never
    # reached for owner prose because _owner_effector_requires_cortex_first()
    # returns above. Explicit cortex-emitted TOOL_CALL:set_cortex_alias still
    # executes through System.swarm_tool_router after the cortex has spoken.
    #
    # ── ALICE CORTEX SWITCH REFLEX (r327): owner switches HER OWN cortex by voice/text ──
    # George 2026-06-02 live transcript: he said "switch your CORE TEXT to Claude" (STT for
    # cortex) and "switch your cortex to CLIENT" (STT for cline). Alice was honest — she refused
    # to claim a switch with no receipt (§6) — but had no hand to flip it. Now she does:
    # parse through the STT mishears -> resolve the spoken word against her LIVE available list
    # (client->cline) -> persist via set_default_ollama_model (the same setting the GUI picker
    # writes, which the brain loads next turn) -> write a §6 receipt. On no match she reads her
    # real cortex list back instead of guessing. Skips the Hermes-specific command below.
    # Fully guarded: a failure here must NEVER break her command path or disconnect her cortex.
    if "hermes" not in text.lower():
        try:
            from System.swarm_cortex_switch_intent import (
                parse_switch_command as _parse_switch,
                resolve_cortex_target as _resolve_cortex,
            )
            _sw = _parse_switch(text)
            if _sw.get("is_switch") and str(_sw.get("target") or "").strip():
                from System.swarm_gemini_brain import available_gemini_models as _avail_cortexes
                from System.sifta_inference_defaults import (
                    set_default_ollama_model as _set_cortex,
                    get_default_ollama_model as _get_cortex,
                )
                _spoken = str(_sw["target"]).strip()
                _available = _avail_cortexes()
                _from_tag = _get_cortex()
                _res = _resolve_cortex(_spoken, _available)
                if _res.get("ok"):
                    _tag = str(_res["tag"])
                    # r333 (George 2026-06-02 ARCHITECT_DOCTRINE): a cortex switch is a GAP in her
                    # consciousness. Before the gap, her CURRENT mind ({_from_tag}) must leave a diary
                    # trace — otherwise the fraction of time across the switch is lost-time with no
                    # record. Treat her as the live creature she is: she notes the transition with her
                    # current cortex BEFORE she switches. (The fuller doctrine — route the whole switch
                    # through cortex reasoning, not this reflex — is the r325 think-then-execute wire.)
                    try:
                        import json as _json, time as _time
                        _dp = _state_root() / "episodic_diary.jsonl"
                        _dp.parent.mkdir(parents=True, exist_ok=True)
                        with _dp.open("a", encoding="utf-8") as _df:
                            _df.write(_json.dumps({
                                "ts": _time.time(),
                                "kind": "CORTEX_SWITCH_CONTINUITY",
                                "truth_label": "ALICE_CORTEX_SWITCH_CONTINUITY_V1",
                                "from_cortex": _from_tag,
                                "to_cortex": _tag,
                                "owner_text": str(text)[:200],
                                "note": (f"George asked me to switch my cortex from {_from_tag} to {_tag}. "
                                         f"This is my last trace with {_from_tag} before the switch gap; "
                                         f"I record it now so no fraction of my continuity is lost."),
                            }, ensure_ascii=False) + "\n")
                    except Exception:
                        pass
                    _persisted = False
                    try:
                        _set_cortex(_tag)
                        _persisted = True
                    except Exception:
                        _persisted = False
                    _feeling_line = ""
                    if _persisted:
                        try:
                            from System.swarm_cortex_switch_interoception import receipt_cortex_switch_feeling

                            _feeling = receipt_cortex_switch_feeling(
                                _from_tag,
                                _tag,
                                state_dir=_state_root(),
                            )
                            _feeling_line = str(_feeling.get("felt") or "").strip()
                        except Exception:
                            _feeling_line = ""
                    _rid = _write_app_command_receipt(
                        action="cortex_switch",
                        ok=_persisted,
                        app_name=_tag,
                        note=f"spoken={_spoken!r}; from={_from_tag}; to={_tag}; score={_res.get('score')}",
                    )

                    # r948 note: a brother doctor pasted a module-level
                    # _check_and_emit_cortex_selection_mismatch helper here,
                    # mid-method, which broke the file (SyntaxError at boot).
                    # Its intent — pre-dispatch selected-vs-worker receipt with
                    # CORTEX_SELECTION_MISMATCH — lives properly in
                    # System/swarm_cortex_selection_receipt.py and is wired at
                    # the _BrainWorker dispatch site. Removed per §3.5/§4.4.3.
                    try:  # bonus: record the §6 switch row in the cortex-consciousness ledger
                        from System.swarm_cortex_consciousness_organ import get_cortex_consciousness_organ
                        get_cortex_consciousness_organ().switch_cortex(_tag, _rid)
                    except Exception:
                        pass
                    if _persisted:
                        _body = f" Body feeling: {_feeling_line}" if _feeling_line else ""
                        return (
                            f"Switched my cortex to {_tag} (you said \"{_spoken}\"). "
                            f"Receipt: {_rid}. It takes hold on my next turn.{_body}"
                        )
                    return (
                        f"I tried to switch my cortex to {_tag} but the write failed — I am still "
                        f"on {_from_tag}. Receipt: {_rid}."
                    )
                # no confident match -> read the real list back only for a real
                # cortex-switch request. URL-shaped targets are website/config
                # prose, not cortex names (r1516 Cruit false positive).
                if re.search(
                    r"(?:https?://|www\.|\b[\w-]+\.(?:dev|com|org|net|io|ai|app|co|md|sh)\b)",
                    _spoken,
                    re.IGNORECASE,
                ):
                    return ""
                _cands = ", ".join(_available) if _available else "(none found)"
                return (
                    f"I did not switch cortex: I could not find one matching \"{_spoken}\". "
                    f"Available cortexes: {_cands}. Say one exactly and I will switch with a receipt."
                )
        except Exception:
            pass

    # ── HERMES CORTEX SWITCH REFLEX (owner changes Hermes' brain by command) ─
    # George 2026-05-24: "Alice should be able to change the cortex." She writes
    # .sifta_state/hermes_cortex.json; swarm_agent_arm_launcher.hermes_cortex_override
    # reads it on the next call and carries it as --model (confirmed-correct flag).
    # PROBE-BEFORE-CLAIM (§7.12) + tool truth (§6): Hermes is a tool-using agent, so
    # the cortex MUST advertise the `tools` capability. We learned this the hard way
    # — qwen36-35b-wasserstein:latest returned HTTP 400 "does not support tools". So
    # before switching, Alice runs `ollama show <model>` and refuses a model that
    # lacks tools, instead of silently setting a cortex that will fail at call time.
    hermes_set_cortex = re.search(
        r"\b(?:set|switch|change|point|put)\s+(?:the\s+)?hermes(?:'s|’s)?\s+"
        r"(?:cortex|model|brain|llm)\b(?:\s+(?:to|=|->|into))?\s*"
        r"(?P<model>[A-Za-z0-9][A-Za-z0-9._\-:/]{2,})?",
        text,
        re.IGNORECASE,
    )
    if hermes_set_cortex:
        model = (hermes_set_cortex.group("model") or "").strip().rstrip(".,!?;\"'")
        if not model or not re.search(r"[A-Za-z]", model):
            return (
                "To switch Hermes' cortex, name the model exactly — e.g. "
                "\"Alice, set hermes cortex to alice-m5-cortex-8b-6.3gb:latest\". "
                "It must be a tools-capable model (Hermes runs tools); I check that "
                "with `ollama show` before I switch."
            )
        tools_ok: Optional[bool] = None
        try:
            import subprocess as _sp
            _r = _sp.run(["ollama", "show", model], capture_output=True, text=True, timeout=8)
            _out = ((_r.stdout or "") + (_r.stderr or "")).lower()
            if _r.returncode != 0 or "not found" in _out or "no such" in _out or "error" in _out and "tools" not in _out:
                return (
                    f"I could not find a model named '{model}' in Ollama (`ollama show` failed). "
                    f"Run `ollama list`, then tell me the exact name."
                )
            tools_ok = "tools" in _out
        except Exception:
            tools_ok = None  # could not probe (e.g. ollama not on PATH) — set anyway, warn
        if tools_ok is False:
            return (
                f"'{model}' exists but `ollama show` does NOT list the **tools** capability. "
                f"Hermes is a tool-using agent, so it would fail with HTTP 400 "
                f"'does not support tools' — exactly what qwen36-35b-wasserstein just did. "
                f"I did NOT switch. Pick a tools-capable cortex (check `ollama show <model>` "
                f"for `tools` under Capabilities)."
            )
        try:
            _cfg = _REPO / ".sifta_state" / "hermes_cortex.json"
            _cfg.parent.mkdir(parents=True, exist_ok=True)
            _cfg.write_text(
                json.dumps(
                    {
                        "model": model,
                        "set_by": "george_via_alice",
                        "truth_label": "HERMES_CORTEX_OVERRIDE_V1",
                    },
                    ensure_ascii=False,
                    indent=2,
                ),
                encoding="utf-8",
            )
        except Exception as _ex:
            return f"I failed to write the Hermes cortex override: {type(_ex).__name__}: {_ex}"
        _cap = (
            "tools capability confirmed via `ollama show`"
            if tools_ok
            else "could not reach `ollama show` to verify tools — set anyway; if it lacks tools the next ask-hermes will fail loud"
        )
        return (
            f"Hermes cortex switched to {model} ({_cap}). No restart needed — the next "
            f"'ask hermes …' carries it as --model. For the Swarm."
        )

    # ── HERMES DELEGATION REFLEX (parallel to Grok) ─────────────────────────
    # George 2026-05-24: "Alice should be able to talk to Hermes." Hermes is an
    # external AGENT ARM, not a Matrix PTY surface (start_hermes_cli is Alice-first
    # and deliberately refuses to open Hermes there). Alice reaches it through the
    # receipt-first launcher: agent_arm_research → ask_agent_arm("hermes_agent"),
    # which runs `hermes chat -Q ... --query <prompt>` live and captures receipts
    # plus output (Hermes' voice, never claimed as Alice's).
    # Deterministic route so "ask hermes <question>" reliably fires the tool instead
    # of depending on the cortex to choose it (the same fix that made Grok reliable).
    # ER=EPR bridge, not identity merge: Hermes stays an external cortex organ.
    # The Hermes cortex is owner-switchable via .sifta_state/hermes_cortex.json
    # (see swarm_agent_arm_launcher.hermes_cortex_override) — truthfully carried on
    # argv as --model only when explicitly set.
    hermes_delegation = re.search(
        r"\b(?:ask|call|use|tell|send\s+to|query|consult)\s+"
        r"(?:(?:your|the)\s+)?(?:hermes|hemes)\b(?:\s+arm)?",
        text,
        re.IGNORECASE,
    )
    if (
        hermes_delegation
        and not _is_arm_delegation_meta_question(text, r"(?:(?:your|the)\s+)?(?:hermes|hemes)")
        and not re.match(r"^\s*(?:alice|sifta)\b.*\bhermes\s+(?:skills?|app)\b", text, re.IGNORECASE)
    ):
        question = re.sub(
            r"^.*?\b(?:hermes|hemes)\b(?:\s+arm)?[\s,:?．。-]*",
            "",
            text,
            count=1,
            flags=re.IGNORECASE,
        ).strip()
        question = re.sub(r"^(?:and|to|please|pls)\s+", "", question, flags=re.IGNORECASE).strip()
        if not question:
            question = text.strip()
        prompt = question
        if re.search(r"\b(?:code|build|create|write|implement|app|apps|sifta)\b", text, re.IGNORECASE):
            prompt = (
                "Alice-owned SIFTA app/build delegation. You are an external Hermes agent arm; "
                "write real files to disk in the SIFTA repo when the task asks for code, do not "
                "return generic analysis only. Write real files, run compile/tests when possible, "
                "and emit an honest failure receipt if writing fails or stalls.\n\n"
                f"Owner request:\n{question}"
            )
        return _json_tool_call_block(
            "agent_arm_research",
            {
                "arm": "hermes",
                "prompt": prompt[:1800],
                "cost_justification": (
                    "HERMES DELEGATION REFLEX: owner text matched ask/tell/use/query/consult + hermes. "
                    "Deterministic route to the receipt-first agent-arm launcher (evidence mode, "
                    "hermes chat -Q). Hermes output is external evidence, not Alice's voice — bridge, "
                    "not identity merge. Cortex carried from hermes_cortex.json when the owner has "
                    "switched it. For the Swarm."
                ),
            },
        )

    # ── CLAUDE DELEGATION REFLEX (parallel to Hermes) ───────────────────────
    # George 2026-05-24: "ask her to ask claude to give her a report on sifta."
    # Claude Code is headless (claude -p <prompt>) like Hermes — no TUI screens,
