# r930: signatures of HER OWN honest recovery/body reports (built by
# swarm_cortex_timeout_recovery.py, not by the cortex). These are receipts in
# prose form — the fiction guard must never overwrite them.
_HONEST_BODY_RECOVERY_RE = re.compile(
    r"(?:\bcortex timed out after \d+s\b|\brecovery receipt [0-9a-f-]{8,}\b)",
    re.IGNORECASE,
)


def _tool_fiction_guard_reply(user_text: str, brain_text: str) -> str:
    """Return a corrective reply when the brain simulates a tool without a tool call."""
    if not user_text or not brain_text:
        return ""
    if _has_explicit_tool_call(brain_text):
        return ""
    if not _is_actionable_tool_request(user_text):
        return ""
    # r1490: body visual commands with attached screenshot must never be gagged by this.
    # The guard was erasing real replies on embodiment teaching + "click the visible in the photo".
    ut = (user_text or "").lower()
    if any(p in ut for p in ("attached on your body", "on your body", "your alice browser screen", "click on your body", "on your body screen")):
        return ""
    # r930 (George 2026-06-10, r929 packet turn): a timeout-recovery report is
    # body TRUTH, not tool fiction. The guard replaced "My grok-build cortex
    # timed out after 60s ... recovery receipt c2b154e1" with the canned
    # self-code line, hiding the real blocker from George. Honest body reports
    # pass through untouched.
    if _HONEST_BODY_RECOVERY_RE.search(brain_text):
        return ""
    try:
        from System.swarm_alice_self_coding_hand import is_owner_self_code_execute_request

        if is_owner_self_code_execute_request(user_text):
            # r939 (George 2026-06-10: "SO U CLAIM GEMMA4 IS SO DUMB?"): the
            # guard ERASED her real reply and George read the canned line as
            # her cortex being dumb. At 17:47 gemma had correctly diagnosed
            # the YouTube ingress flood — and the guard threw her words away.
            # Her prose on a self-code turn is not a lie; it just lacks blocks.
            # APPEND the honesty line. Never erase her voice.
            return (
                str(brain_text).rstrip()
                + "\n\n"
                + "No self-code receipt yet: my reply above is prose with no "
                "[SELF_CODE_CUT: path=...] or [SELF_CODE_EDIT: path=...] block "
                "for my self-code hand to execute. The repair path is to emit "
                "the block in my next reply; the body executes it and writes "
                "doctor=alice_self receipts."
            )
    except Exception:
        pass
    if not _TOOL_PROSE_SIMULATION_RE.search(brain_text):
        return ""
    read_path = _owner_read_path_from_text(user_text)
    if read_path:
        return (
            "No action receipt yet: I did not read that file because my brain reply "
            "contained no parseable read_file TOOL_CALL. The repair path is "
            f"[TOOL_CALL: read_file | path={read_path} | cost_justification=owner asked me to read this local file]."
        )
    path = _owner_save_path_from_text(user_text)
    if path and _largest_code_block(brain_text):
        return ""
    if path:
        return (
            "No action receipt yet: I did not save that file because my brain reply "
            "contained no real write_file tool call and no bridgeable code block."
        )
    return (
        "No action receipt yet: I did not execute that tool action because my brain "
        "reply contained prose instead of a real TOOL_CALL. I need the receipt-backed "
        "tool path to perform it and leave a receipt."
    )


