    r"|\b(?:youtube|watch\?v=|youtu\.be|playback|play\s+button|pause\s+button|skip\s+ad|current\s+time)\b"
    r"|\b(?:link|url|address|page)\b.{0,80}\b(?:inside\s+your\s+body|in\s+your\s+body|on\s+your\s+screen)\b",
