def _current_ace_word_for_routing() -> str:
    """Return the live Ace table word if the Ace word surface is active."""
    try:
        from System.swarm_ace_consent_bridge import current_word as _ace_current_word

        return str(_ace_current_word() or "").strip()
    except Exception:
        return ""


def _ace_surface_active_for_routing(text: str = "") -> bool:
    """Only let terse word commands bind to Ace when Ace is actually the focused surface."""
    raw = str(text or "")
    if _ACE_EXPLICIT_CONTEXT_RE.search(raw):
        return True
    try:
        app = _active_sifta_app_name_for_prompt().strip().lower()
    except Exception:
        app = ""
    return app in {"ace", "wordace", "acer"} or "wordace" in app or app.startswith("ace")


def _is_ace_word_action_query(text: str) -> bool:
    """Route focused Ace word commands before the generic browser next-photo reflex."""
    raw = str(text or "")
    if not raw or not _current_ace_word_for_routing():
        return False
    if not _ace_surface_active_for_routing(raw):
        return False
    try:
        from System.swarm_ace_consent_bridge import detect_change_directive

        if detect_change_directive(raw):
            return True
    except Exception:
        pass
    return bool(_ACE_WORD_ACTION_RE.search(raw))


def _execute_ace_word_action(text: str) -> str:
    """Drive the Ace app surface, then answer from the screen-change receipt lane."""
    raw = str(text or "")
    requested = ""
    try:
        from System.swarm_ace_consent_bridge import detect_change_directive

        requested = detect_change_directive(raw)
    except Exception:
        requested = requested or ""

    try:
        from Applications.sifta_teach_ace_to_read import TeachAceToReadWidget

        live = getattr(TeachAceToReadWidget, "_live_instance", None)
        if live is not None:
            if requested:
                applied = bool(live._apply_direct_word_command(requested, raw_text=raw))
                if applied:
                    return (
                        f"Changed the Ace card to {requested}. "
                        f"I will trust the app receipt, not just my words."
                    )
            else:
                live._on_next_word_button_clicked()
                now_word = str(getattr(live, "_current_word", "") or "").strip()
                if now_word:
                    return (
                        f"Next Ace word. The card now shows {now_word}. "
                        f"I advanced the app surface, not just my sentence."
                    )
                return "Next Ace word. I pressed the Ace app's next-word effector."
    except Exception:
        pass

    if requested:
        try:
            from System.swarm_ace_consent_bridge import write_consent, write_proposal

            prop = write_proposal(
                proposer="user",
                proposed_word=requested,
                context=f"talk_direct_ace_action: {raw[:180]}",
            )
            write_consent(
                consenter="alice",
                proposal_id=str(prop.get("proposal_id") or ""),
                agreed=True,
                context=f"auto: direct Ace screen command '{requested}'",
            )
        except Exception:
            pass
        return (
            f"I queued the Ace card change to {requested}, but I could not touch "
            f"the live Ace surface directly from this turn. The consent receipt is written."
        )
    return "Ace is active, but I could not reach the live next-word effector from this turn."


def _is_direct_command_sized(text: str) -> bool:
    """r940: a spoken direct command ('next slide', 'previous slide') is a few
    words. George pasted a long IDE message that merely QUOTED the phrase
    'Previous slide' and the matcher pressed the arrow three times on a page
    with no slides (receipts c144e642, b750a33c, 7fafff87, edaf3030). A turn
    longer than 120 chars, or one carrying surgery markers, is conversation or
    a pasted packet — never a one-step browser command."""
    raw = (text or "").strip()
    if len(raw) > 120:
        return False
    if re.search(r"\[SELF_READ\b|\[SELF_CODE_(?:CUT|EDIT)\b|\bwrite_plan\s*\(|\br\d{3,4}-[a-z0-9-]+", raw):
        return False
    return True


def _is_next_photo_query(text: str) -> bool:
    if not _is_direct_command_sized(text):
        return False
    return bool(_NEXT_PHOTO_RE.search(text or "")) and not _STOP_SLIDESHOW_RE.search(text or "")


def _is_stop_slideshow_query(text: str) -> bool:
    if not _is_direct_command_sized(text):
        return False
    return bool(_STOP_SLIDESHOW_RE.search(text or ""))


def _is_slideshow_query(text: str) -> bool:
    if not _is_direct_command_sized(text):
        return False
    return bool(_SLIDESHOW_RE.search(text or "")) and not _STOP_SLIDESHOW_RE.search(text or "")


def _is_slide_nav_query(text: str) -> bool:
    """One-step next/previous navigation on a blown-up image ('next slide',
    'previous slide'). Distinct from the auto-advance slideshow and from 'stop'."""
    raw = text or ""
    if not _is_direct_command_sized(raw):
        return False
    if _STOP_SLIDESHOW_RE.search(raw):
        return False
    return bool(_SLIDE_NEXT_RE.search(raw) or _SLIDE_PREV_RE.search(raw))


def _slide_nav_direction(text: str) -> str:
    """'prev' if the turn names the previous/back direction, else 'next'."""
    raw = text or ""
    if _SLIDE_PREV_RE.search(raw):
        return "prev"
    return "next"


def _extract_slideshow_interval(text: str) -> float:
    m = re.search(r"every\s+(\d+)\s*seconds?", text or "", re.IGNORECASE)
    if m:
        return float(m.group(1))
    try:
        from System.swarm_search_engine_registry import SLIDESHOW_DEFAULT_INTERVAL_S
        return float(SLIDESHOW_DEFAULT_INTERVAL_S)
    except Exception:
        return 3.5


def _browser_clean_domain(url: str) -> str:
    try:
        from urllib.parse import urlparse
        host = urlparse(url or "").netloc.lower()
    except Exception:
        host = ""
    return host[4:] if host.startswith("www.") else host


def _browser_clean_address(url: str, *, max_chars: int = 120) -> str:
    """Display a human-readable browser address without tracking parameters."""
    try:
        from urllib.parse import urlparse
        parsed = urlparse(url or "")
        host = (parsed.netloc or "").lower()
        if host.startswith("www."):
            host = host[4:]
        path = parsed.path or ""
        address = f"{host}{path}" if host else (url or "").split("?", 1)[0].split("#", 1)[0]
    except Exception:
        address = (url or "").split("?", 1)[0].split("#", 1)[0]
    address = " ".join(str(address or "").split()).rstrip("/")
    if len(address) > max_chars:
        return address[: max_chars - 3].rstrip("/ ") + "..."
    return address


def _browser_source_label_for_url(url: str) -> str:
    host = _browser_clean_domain(url)
    if not host:
        return ""
    if host.endswith("berkeley.edu"):
        return "UC Berkeley"
    if host.endswith("instagram.com"):
        return "Instagram"
    if host.endswith("tiktok.com"):
        return "TikTok"
    if host.endswith("youtube.com") or host.endswith("youtu.be"):
        return "YouTube"
    if host.endswith("wikipedia.org"):
        return "Wikipedia"
    if host in {"x.com", "twitter.com"} or host.endswith(".x.com") or host.endswith(".twitter.com"):
        return "X"
    return ""


def _clean_browser_title_for_human(title: str, *, source_label: str = "", domain: str = "") -> str:
    clean = " ".join(str(title or "").split()).strip()
    if not clean:
        return ""
    for sep in (" | ", " - ", " :: "):
        if sep not in clean:
            continue
        parts = clean.split(sep)
        tail = parts[-1].strip().casefold()
        source_low = source_label.casefold()
        domain_low = domain.casefold()
        if (
            (source_low and source_low in tail)
            or (domain_low and domain_low in tail)
            or tail in {"instagram", "tiktok", "youtube", "wikipedia", "x"}
        ):
            clean = sep.join(parts[:-1]).strip()
            break
    return clean.strip(" -|")


