def _extract_youtube_playback_control(text: str) -> Dict[str, Any]:
    """Parse owner control of the current YouTube/video player.

    This owns commands like "click play, then after 30 seconds click pause".
    They are current-player controls, not result-selection requests.
    "play the first video in youtube browser" or similar must not short-circuit here
    (owner typed "DETERMINISTIC ALREADY BAD I TOLD YOU, MUST PROCESS WITH CORTEX";
    "first" implies selection/awareness, not pure current-player click).
    """
    clean = " ".join((text or "").strip().split())
    if not clean or not _VIDEO_PLAYBACK_CONTROL_RE.search(clean):
        return {}
    low = clean.lower()
    # r706: "first" or "in youtube browser" with play means select/open the first, not
    # assume a current player and click play on it. Let it fall to search/cortex path.
    if "first" in low or "in youtube browser" in low:
        return {}
    wants_play = bool(re.search(r"\b(?:play|start|resume|continue|unpause|un-?pause)\b", low))
    # "stop" / "halt" map to pause — an HTML5/YouTube web player has no true stop,
    # so the honest body action for "stop the video" is pause (George: play/stop/pause).
    wants_pause = bool(re.search(r"\b(?:pause|stop|halt)\b", low))
    if "play" in low and "pause" in low:
        wants_play = True
    after_s = 0
    m = re.search(r"\bafter\s+(\d{1,4})\s*(?:sec|secs|second|seconds|s)\b", low)
    if m:
        try:
            after_s = max(1, min(3600, int(m.group(1))))
        except Exception:
            after_s = 0
    if not wants_play and not wants_pause:
        return {}
    return {
        "kind": "browser_action",
        "app_name": "Alice Browser",
        "action": "youtube_playback_control",
        "play": "1" if wants_play else "",
        "pause": "1" if wants_pause and not after_s else "",
        "pause_after_s": str(after_s) if after_s else "",
    }


def _extract_youtube_visible_result_query(text: str) -> str:
    """Extract a title-like target for a visible YouTube result click.

    This intentionally requires browser/screen/result/video context so generic
    app commands do not get stolen by the browser limb. It covers George's live
    phrasing: "select Halsey - without me ... screenshot of your screen arm".
    """
    clean = " ".join((text or "").strip().split())
    if not clean:
        return ""
    try:
        if _PRAISE_ACK_RE.search(clean) and not re.search(r"\b(?:youtube|video|result)\b", clean, re.IGNORECASE):
            return ""
    except Exception:
        pass
    if _extract_youtube_playback_control(clean):
        return ""
    if re.search(
        r"\b(?:captcha|recaptcha|duck\s+square|squares?\s+containing|"
        r"select\s+all\s+squares|3x\s+duck|three\s+duck)\b",
        clean,
        re.IGNORECASE,
    ):
        return ""
    if not re.search(r"\b(?:click|press|select|open|choose|tap|pick)\b", clean, re.IGNORECASE):
        return ""
    if re.search(r"\b(?:open|load|browse|navigate|go\s+(?:to|on|in))\b.{0,80}\byoutube(?:\.com)?\b", clean, re.IGNORECASE):
        return ""
    if not re.search(r"\b(?:youtube|result)\b", clean, re.IGNORECASE):
        return ""
    # Explicitly do not treat body screenshot commands or "alice browser screen" as YouTube result clicks
    if re.search(r"\b(?:alice\s+browser\s+screen|on\s+your\s+(?:own\s+)?body|your\s+body|click\s+on\s+your\s+(?:alice\s+)?browser)\b", clean, re.IGNORECASE):
        return ""
    # r1481 (George live: "I meant good... so let's try. please click on the
    # grok button on the screen" got read as one long YouTube-result query
    # because the old strip only matched a click-verb phrase anchored at the
    # very START of the turn). Owners often preamble before the actual
    # instruction; the real command is the LAST click-verb phrase in the
    # turn, not necessarily the first word. Search anywhere, take the last
    # match, and start the tail from there.
    _click_lead_re = re.compile(
        r"(?:^\s*|[.!?]\s+|,\s+|\bso\s+let'?s\s+try[,.]?\s+)"
        r"(?:(?:hey|ok|okay|yo|hi|hello|now)\s+)?(?:alice[,\s]+)?"
        r"(?:(?:can|could|would|will)\s+you\s+|please\s+|pls\s+|plz\s+)?"
        r"(?:click|press|select|open|choose|tap|pick)\s+(?:on\s+|the\s+)?",
        flags=re.IGNORECASE,
    )
    _lead_matches = list(_click_lead_re.finditer(clean))
    if _lead_matches:
        tail = clean[_lead_matches[-1].end():].strip()
    else:
        tail = clean
    tail = re.split(
        r"\b(?:i\s+attached|attached|screenshot|screen\s+arm\s+display|that\s+is\s+how|"
        r"with\s+this\s+screen|on\s+(?:the\s+)?screen|from\s+(?:the\s+)?screen|"
        r"in\s+(?:the\s+)?screenshot|on\s+(?:this\s+)?page)\b",
        tail,
        1,
        flags=re.IGNORECASE,
    )[0]
    tail = re.sub(
        r"\b(?:body|artwork|picture|thumbnail|visible|result|video|link|please|pls|alice|alyssa)\b",
        " ",
        tail,
        flags=re.IGNORECASE,
    )
    tail = " ".join(tail.strip(" .?!,;:\"'“”‘’`").split())
    try:
        if _subject_is_word_salad(tail):
            return ""
    except Exception:
        pass
    return tail[:140].strip()
