def _browser_video_state_reply(*, state_dir: Optional[Path | str] = None) -> str:
    try:
        from System.swarm_browser_page_state import latest_page_state

        state = latest_page_state(state_dir=state_dir or _state_root(), max_age_s=900.0)
    except Exception:
        state = {}
    if not isinstance(state, Mapping) or not state:
        return (
            "I do not have a fresh Alice Browser page-state receipt yet. To sense the exact "
            "YouTube state, my browser arm must keep publishing URL, title, media status, "
            "current_time, and duration."
        )
    media = state.get("media_playback") if isinstance(state.get("media_playback"), Mapping) else {}
    url = str(state.get("url") or "")
    title = str(state.get("title") or url or "the current page").strip()
    status = str(media.get("status") or ("playing" if media.get("playing") else "") or "unknown").strip()
    current = _format_browser_media_time(media.get("current_time"))
    duration = _format_browser_media_time(media.get("duration"))
    current_page = bool(state.get("is_current_page"))
    fresh = bool(state.get("fresh"))
    if media:
        codec_status = media.get("codec_status") if isinstance(media.get("codec_status"), Mapping) else {}
        diagnosis = codec_status.get("diagnosis") if isinstance(codec_status.get("diagnosis"), Mapping) else {}
        recent_errors = codec_status.get("recent_errors") if isinstance(codec_status.get("recent_errors"), list) else []
        native_handoff = bool(
            diagnosis.get("native_handoff_recommended")
            or codec_status.get("native_handoff_available")
        )
        if diagnosis.get("code") or recent_errors:
            label = str(diagnosis.get("label") or "media decoder error").strip()
            if label == "NO_MEDIA_ERROR" and recent_errors:
                try:
                    from System.swarm_media_codec_bridge import diagnose_media_error_code

                    first_code = recent_errors[0].get("code") if isinstance(recent_errors[0], Mapping) else None
                    label = str(diagnose_media_error_code(first_code).get("label") or "media decoder error")
                except Exception:
                    label = "media decoder error"
            raw_error = ""
            if recent_errors and isinstance(recent_errors[0], Mapping):
                raw_error = str(recent_errors[0].get("error") or "").strip()
            site = _browser_source_label_for_url(url) or "this page"
            bits = [
                f"I can read my Alice Browser page-state receipt: {title}",
                f"URL {url}" if url else "",
                f"media status is {status}" if status else "",
                f"but the embedded browser hit {label}",
            ]
            if raw_error:
                bits.append(raw_error)
            if native_handoff:
                bits.append(
                    "to play it inside SIFTA OS, use Alice's in-place native decode surface over the failed video frame (🎬)"
                )
            if not current_page:
                bits.append("this receipt is not confirmed as the current browser URL")
            return "; ".join(bit for bit in bits if bit) + f". This is a {site} playback-body error, not a cortex answer."
        bits = [f"I can read my Alice Browser page-state receipt: {title}"]
        if url:
            bits.append(f"URL {url}")
        if status:
            bits.append(f"media status is {status}")
        if current:
            when = f"at {current}"
            if duration:
                when += f" of {duration}"
            bits.append(when)
        if not current_page:
            bits.append("but this receipt is not confirmed as the current browser URL")
        elif not fresh:
            bits.append("but the receipt is stale")
        return "; ".join(bits) + "."
    if current_page or fresh:
        return (
            f"I know the current Alice Browser page is {title} ({url}), but this receipt "
            "does not yet include a media_playback object. The missing code is the browser "
            "arm publishing the video element's paused/playing status and currentTime on each scan."
        )
    return (
        f"I only have a stale browser receipt for {title} ({url}). I should re-read Alice Browser "
        "before claiming whether the video is paused."
    )


def _search_url_for_site(site: str, query: str) -> str:
    raw_q = (query or "").strip()
    q = quote_plus(raw_q)
    if not q:
        return ""
    site_norm = (site or "").casefold()
    if "wiki" in site_norm:
        return f"https://en.wikipedia.org/w/index.php?search={q}"
    if "youtube" in site_norm:
        return f"https://www.youtube.com/results?search_query={q}"
    if "tiktok" in site_norm:
        return f"https://www.tiktok.com/search?q={q}"
    if "instagram" in site_norm:
        return f"https://www.instagram.com/explore/search/keyword/?q={q}"
    if "ebay" in site_norm:
        return f"https://www.ebay.com/sch/i.html?_nkw={q}"
    # r1325/r1326: when owner names a search engine/site, honor that engine key — do not
    # silently substitute the configured default (DuckDuckGo opened while reply said Google).
    if site_norm:
        try:
            from System.swarm_search_engine_registry import resolve_engine, search_url as _reg_search_url

            resolved = resolve_engine(site_norm)
            if resolved.get("ok"):
                return _reg_search_url(raw_q, engine=resolved["key"]) or ""
        except Exception:
            pass
    # Use Alice's own search engine registry (default Alice Browser + Google, owner-switchable)
    try:
        from System.swarm_search_engine_registry import search_url as _reg_search_url
        return _reg_search_url(raw_q) or f"https://www.google.com/search?q={q}"
    except Exception:
        return f"https://www.google.com/search?q={q}"


_NATIVE_MACOS_BROWSER_REQUEST_RE = re.compile(
    r"\b(?:in|with|using|through|on|open\s+in|load\s+in)\s+"
    r"(?:the\s+)?(?:(?:mac\s*os|macos)\s+)?safari\b"
    r"|\b(?:in|with|using|through|on|open\s+in|load\s+in)\s+"
    r"(?:the\s+)?(?:native|external|mac\s*os|macos)\s+browser\b"
    r"|\b(?:safari|native\s+browser|external\s+browser|mac\s*os\s+browser|macos\s+browser)\b"
    r".{0,50}\b(?:instead\s+of\s+alice\s+browser|not\s+alice\s+browser|mac\s*os)\b",
    re.IGNORECASE,
)


_ALICE_BROWSER_NEW_TAB_REQUEST_RE = re.compile(
    r"\b(?:separate|new|another|fresh)\s+(?:alice\s+)?browser\s+tab\b"
    r"|\b(?:separate|new|another|fresh)\s+tab\b"
    r"|\b(?:open|load|show|display|navigate|go\s+to)\b.{0,80}\b(?:in|into|on)\s+"
    r"(?:a\s+)?(?:separate|new|another|fresh)\s+(?:alice\s+)?browser\s+tab\b",
    re.IGNORECASE,
)


def _wants_native_macos_browser(text: str) -> bool:
    """True when George explicitly asks to leave Alice Browser and use Safari/Mac OS.

    Default web work stays inside Alice Browser so that limb keeps learning from
    its own receipts. This only flips the lane when the owner names Safari/native
    Mac browser as the target for a URL/search.
    """
    clean = " ".join(str(text or "").strip().split())
    if not clean:
        return False
    # r991: "open in alice browser" must never route to Safari even if OAuth/IdP
    # words appear elsewhere in the turn.
    if re.search(r"\balice\s+browser\b", clean, re.IGNORECASE):
        return False
    if not re.search(
        r"\b(?:open|load|show|display|search|find|look\s+up|go\s+to|navigate|pull\s+up|bring\s+up)\b",
        clean,
        re.IGNORECASE,
    ):
        return False
    return bool(_NATIVE_MACOS_BROWSER_REQUEST_RE.search(clean))


def _wants_alice_browser_new_tab(text: str) -> bool:
    """True when George asks Alice Browser to preserve the current tab.

    This is still Alice Browser, not Safari. It only changes the handoff mode
    from "navigate current tab" to "open/focus a new Alice Browser tab".
    """
    clean = " ".join(str(text or "").strip().split())
    if not clean:
        return False
    if not re.search(
        r"\b(?:open|load|show|display|navigate|go\s+to|pull\s+up|bring\s+up|visit|search|find|look\s+up)\b",
        clean,
        re.IGNORECASE,
    ):
        return False
    return bool(_ALICE_BROWSER_NEW_TAB_REQUEST_RE.search(clean))


def _maybe_native_browser_command(command: Dict[str, str], owner_text: str) -> Dict[str, str]:
    if not command or command.get("kind") != "browser_url":
        return command
    if not _wants_native_macos_browser(owner_text):
        if _wants_alice_browser_new_tab(owner_text):
            out = dict(command)
            out["new_tab"] = "1"
            out["tab_mode"] = "new_alice_browser_tab"
            out["owner_text"] = " ".join(str(owner_text or "").split())
            return out
        return command
    out = dict(command)
    # r1316: Alice's web limb stays Alice Browser while the body learns.
    # Even explicit Safari/Chrome/Mac-browser wording is routed into her own
    # QWebEngine limb instead of spawning a foreign macOS browser.
    out["kind"] = "browser_url"
    out["app_name"] = "Alice Browser"
    out["browser_app"] = "Alice Browser"
    out["native_browser_blocked"] = "1"
    out["owner_text"] = " ".join(str(owner_text or "").split())
    return out


