def _strip_outer_search_quotes(text: str) -> str:
    q = str(text or "").strip()
    q = re.sub(r"\s*📋\s*Copy\s*$", "", q, flags=re.IGNORECASE).strip()
    if len(q) >= 2 and q[0] in ("'", '"'):
        opener = q[0]
        if q[-1] == opener:
            q = q[1:-1]
        else:
            q = q[1:]
    return " ".join(q.strip(" \t\r\n").split())


def _extract_explicit_search_query(text: str) -> str | None:
    """Owner can force literal query with 'SEARCH ON GOOGLE PLS "exact here"' or similar.
    This wins over any vision-derived or contextual query to prevent search drift (r491 fix).
    """
    if not text:
        return None
    if _is_search_audit_or_routing_correction(text):
        return None
    try:
        from System.swarm_search_provider_reality import parse_explicit_engine_pls_search

        parsed = parse_explicit_engine_pls_search(text)
        if parsed and parsed.get("query"):
            return str(parsed["query"])
    except Exception:
        pass
    raw = str(text).strip()
    m = re.search(
        r"(?:search (?:on google )?(?:for |pls )?|google (?:search )?)(?:pls )?(?P<query>[\"'].+[\"'])",
        raw,
        re.IGNORECASE | re.DOTALL,
    )
    if m:
        q = _strip_outer_search_quotes(m.group("query"))
        if q and len(q) > 2:
            return q
    return None


def _extract_explicit_engine_search_command(text: str, *, history=None) -> Dict[str, str]:
    """`SEARCH ON PERPLEXITY PLS foo` → browser command with named engine + verbatim query."""
    if not text or _is_search_audit_or_routing_correction(text):
        return {}
    try:
        from System.swarm_search_provider_reality import (
            build_explicit_engine_search_url,
            parse_explicit_engine_pls_search,
        )

        parsed = parse_explicit_engine_pls_search(text, history=history)
        if not parsed:
            return {}
        engine = str(parsed.get("engine") or "google")
        if engine == "duckai":
            # r1360: Duck.ai chat queries use the web-AI bridge, not provider search URLs.
            return {}
        query = str(parsed.get("query") or "").strip()
        if not query or _search_query_is_contextual_or_junk(query):
            return {}
        url = build_explicit_engine_search_url(engine, query)
        return {
            "kind": "browser_url",
            "app_name": "Alice Browser",
            "url": url,
            "search_site": engine,
            "query": query,
            "owner_text": str(text).strip(),
            "explicit_owner_query": "1",
            "contextual_search_source": "explicit_engine_pls_r1340",
        }
    except Exception:
        return {}


_SEARCH_JUNK_QUERIES = {
    "", "on", "in", "it", "google", "on google", "the web", "web", "online",
    "this", "that", "these", "those", "this one", "that one", "them",
    "correct", "the web, correct", "the web correct", "web, correct", "web correct",
}
# Anaphora: a query that points back at the conversation (the photo Alice just
# described) rather than naming a concrete thing — must be resolved by the cortex.
_SEARCH_ANAPHORA_RE = re.compile(
    r"\b(?:this|that|these|those|it|her|his|same)\b"
    # optional trailing noun is category-AGNOSTIC (r235): any body/product type, not just
    # clothing — the bare this/that/it already triggers regardless.
    r"(?:\s+(?:type|kind|one|outfit|dress|swimsuit|thing|item|product|style|look|"
    r"wardrobe|clothing|clothes|garment|accessory|legwear|leg\s+warmer|boot\s+cover|"
    r"car|vehicle|watch|bag|shoe|phone|gadget|device|model|piece|animal|building|food|plant))?\b",
    re.IGNORECASE,
)
_CONTEXTUAL_BROWSER_SEARCH_RE = re.compile(
    r"\b(?:where\s+can\s+i\s+buy|where\s+to\s+buy|buy|shop|shopping|search|look\s+up|find)\b"
    r".{0,140}\b(?:this|that|these|those|it|same|type|kind|style|look|outfit|swimsuit|dress|top|shoes|"
    r"wardrobe|clothing|clothes|garment|accessory|piece|pieces|thing|things|item|items|legwear|leg\s+warmer|leg\s+warmers|boot\s+cover|boot\s+covers)\b"
    r"|\b(?:this|that|these|those|it|same)\s+(?:type|kind|style|look|outfit|swimsuit|dress|top|shoes|"
    r"wardrobe|clothing|clothes|garment|accessory|piece|pieces|thing|things|item|items|legwear|leg\s+warmer|leg\s+warmers|boot\s+cover|boot\s+covers)\b"
    r".{0,140}\b(?:buy|shop|shopping|search|look\s+up|find|google)\b",
    re.IGNORECASE,
)
_OWNER_META_ROUTING_CORRECTION_RE = re.compile(
    r"\b(?:can(?:not|'?t)|should(?:\s+not|n't)|don['’]?t|do\s+not)\s+"
    r"(?:just\s+)?(?:take|use|literal(?:ly)?\s+take)\b.{0,140}\b"
    r"(?:all\s+)?(?:this|that|the)\s+text\b.{0,100}\b(?:search|execute|click|open)\b"
    r"|\bwithout\s+(?:thinking\s+)?cortex\b"
    r"|\b(?:deterministic\s+search\s+error|no\s+more\s+deterministic)\b"
    r"|\b(?:cortex\s+first|thinking\s+cortex)\b.{0,120}\b"
    r"(?:can(?:not|'?t)|should(?:\s+not|n't)|don['’]?t|do\s+not|without|instead\s+of)\b"
    # r807 (George 2026-06-08 live): "deterministic grok cortex WRONG" + pasted
    # screenshot audit must reach the active cortex — not a browser-photo reflex.
    r"|\bdeterministic\s+(?:grok\s+|codex\s+|claude\s+)?cortex\s+wrong\b"
    r"|\b(?:add\s+to\s+)?deterministic\b.{0,100}\b(?:all\s+to\s+)?cortex\b",
    re.IGNORECASE,
)
_OWNER_DOCTRINE_CORRECTION_RE = re.compile(
    r"\b(?:deterministic|hardcoded|pre-?cortex|reflex)\b.{0,100}\b(?:wrong|error|asleep|bypass|broken|kills?)\b"
    r"|\b(?:cortex|grok|brain|gemma)\b.{0,80}\b(?:wrong|error)\b"
    r"|\bfix\s+(?:your|the)\s+code\b"
    r"|\b(?:honesty\s+guard|fiction\s+guard)\b.{0,120}\b(?:asleep|build|fix|cut)\b"
    r"|\bsay\s+go\s+and\s+i'?ll\s+cut\b",
    re.IGNORECASE,
)
_SEARCH_AUDIT_OR_CORRECTION_RE = re.compile(
    r"\b(?:did|why\s+did|do|are|were|was|have|has)\s+"
    r"(?:you|u|alice)\s+(?:actually\s+)?"
    r"(?:search(?:ing)?|google|look\s+up|browse|open)\b"
    r"|\b(?:why\s+are\s+you|you\s+are|you're)\s+searching\b"
    r"|\b(?:i\s+)?did\s+not\s+ask(?:ed)?\s+(?:you\s+)?to\s+search\b"
    r"|\b(?:i\s+)?did\s+not\s+ask(?:ed)?\s+(?:you\s+)?for\b.{0,80}\b(?:search|web|google|internet)\b"
    r"|\b(?:i\s+)?did\s+not\s+ask(?:ed)?\s+for\s+search\b"
    r"|\brecurring\s+search\s+bug\b"
    r"|\bremove\b.{0,120}\b(?:search|google\.com/search)\b"
    r"|\bsearch(?:ing)?\s+without\s+(?:me|my)\b"
    r"|\bwithout\s+me\s+telling\s+you\s+to\s+search\b"
    r"|\bunless\s+(?:i\s+)?(?:tell|ask|told|asked)\s+(?:you\s+)?to\s+search\b"
    r"|\bunless\b.{0,80}\bsearch\s+google\b"
    r"|\b(?:deterministic|hardcoded)\b.{0,120}\b(?:search|browser|duckduckgo|google|images?)\b"
    r"|\b(?:search|browser|duckduckgo|google|images?)\b.{0,120}\b(?:deterministic|hardcoded)\b"
    # r1339 live probe: meta routing questions must not become browser searches.
    r"|\b(?:you\s+just\s+)?(?:picked|used|chose|chosen)\s+(?:duck\s*duck\s*go|ddg|duckduckgo)\b"
    r"|\b(?:previous\s+prompt|last\s+prompt)\b.{0,80}\b(?:google|duck\s*duck\s*go|ddg)\b"
    r"|\b(?:difference|diff)\s+between\b.{0,60}\b(?:duck\s*duck\s*go|ddg|google)\b"
    r"|\b(?:unconsciously|without\s+thinking)\b.{0,80}\b(?:search|google|duck\s*duck\s*go)\b"
    r"|\bsearch\s+the\s+web\s*,?\s*correct\b",
    re.IGNORECASE,
)
_OWNER_DETERMINISTIC_DETECTOR_DIRECTIVE_RE = re.compile(
    r"\b(?:deterministic|hardcoded|pre[-\s]?cortex|reflex)\b.{0,120}"
    r"\b(?:unacceptable|wrong|error|bad|mistake|bypass|detector|detect)\b"
    r"|\b(?:send|add|route|log|register)\b.{0,120}\bdeterministic\b.{0,80}"
    r"\b(?:detector|tracker|mistakes?|app)\b",
    re.IGNORECASE,
)
_EXPLICIT_BROWSER_BACK_COMMAND_RE = re.compile(
    r"\b(?:hit back|go back|back one page|previous page|go to previous|back in (?:the )?browser"
    r"|browser back|(?:click|press|tap)\s+(?:the\s+)?back(?:\s+button)?|back button)\b",
    re.IGNORECASE,
)


def _search_query_is_contextual_or_junk(query: str) -> bool:
    """George 2026-05-31: a literal browser search must NOT fire when the query is junk
    ('on Google', 'google', empty) or context-referential ('this type of swimsuit', 'it',
    'that one') — the real target lives in the conversation (e.g. the image Alice just
    described). Such turns route to the CORTEX so it composes the query from context."""
    q = " ".join((query or "").strip(" .?!,;:").split()).casefold()
    try:
        from System.swarm_youtube_search_intent import is_bogus_search_query
        if is_bogus_search_query(q):
            return True
    except Exception:
        pass
    if q in _SEARCH_JUNK_QUERIES or len(q) < 3:
        return True
    if _OWNER_DETERMINISTIC_DETECTOR_DIRECTIVE_RE.search(q):
        return True
    if _SEARCH_ANAPHORA_RE.search(q):
        return True
    return False


def _is_contextual_browser_search_request(text: str) -> bool:
    clean = " ".join((text or "").strip().split())
    if not clean:
        return False
    return bool(_CONTEXTUAL_BROWSER_SEARCH_RE.search(clean))


def _is_owner_meta_routing_correction(text: str) -> bool:
    """Owner is teaching routing doctrine, not asking the browser to move."""
    clean = " ".join((text or "").strip().split())
    return bool(clean and _OWNER_META_ROUTING_CORRECTION_RE.search(clean))


def _is_owner_doctrine_correction_turn(text: str) -> bool:
    """Owner is correcting deterministic/reflex behavior — cortex must hear it."""
    clean = " ".join((text or "").strip().split())
    return bool(clean and _OWNER_DOCTRINE_CORRECTION_RE.search(clean))


def _is_search_audit_or_routing_correction(text: str) -> bool:
    """Owner is questioning/correcting a search, not asking Alice Browser to search."""
    clean = " ".join((text or "").strip().split())
    return bool(clean and (_SEARCH_AUDIT_OR_CORRECTION_RE.search(clean) or _is_owner_meta_routing_correction(clean)))


def _is_owner_deterministic_detector_directive(text: str) -> bool:
    """Owner is sending a bad deterministic answer to the detector, not asking web search."""
    clean = " ".join((text or "").strip().split())
    return bool(clean and _OWNER_DETERMINISTIC_DETECTOR_DIRECTIVE_RE.search(clean))


def _deterministic_detector_directive_reply(text: str) -> str:
    """Write a deterministic tracker receipt for an owner detector directive."""
    try:
        from Applications.sifta_stigmergic_deterministic_tracker import (
            record_deterministic_visible_short_reply,
        )

        row = record_deterministic_visible_short_reply(
            owner_text=text or "",
            alice_reply="",
            source="talk_to_alice_widget.owner_deterministic_detector_directive",
            bypass_type="deterministic_visible_in_talk",
            details={
                "owner_requested": "deterministic_detector_app",
                "blocked_browser_search": True,
            },
        )
        rid = str(row.get("receipt_id") or "").strip()
        return f"Receipt: {rid}" if rid else "Receipt written to deterministic detector."
    except Exception as exc:
        return f"Deterministic detector write failed: {type(exc).__name__}: {exc}"


def _has_explicit_browser_back_command(text: str) -> bool:
    """True when George explicitly asks Alice Browser to go back."""
    clean = " ".join((text or "").strip().split())
    return bool(clean and _EXPLICIT_BROWSER_BACK_COMMAND_RE.search(clean))


def _is_contextual_browser_search_effector_request(text: str) -> bool:
    """True only when contextual visual memory should mutate the browser.

    The broad contextual detector is useful for recognizing that a phrase may
    need visual/cortex context. It must not be enough to move Alice Browser.
    r556: co-watch transcript language such as "let's find out" is learning
    context for cortex, not an implicit Google search.

    Owner rule: FUCK GOOGLE. No search paths unless explicitly commanded
    or genuinely needed for unknown info outside current visual receipts.
    Direct "click X button" on body UI (with screenshot) wins and blocks search.
    """
    clean = " ".join((text or "").strip().split())
    if not clean or not _is_contextual_browser_search_request(clean):
        return False
    # Hard owner rule: if this turn is a direct click on a visible body control
    # (Premium, Grok, RETRY, etc. from screenshot), never route to search.
    if re.search(r"\b(?:click|press|tap)\s+(?:the\s+|on\s+)?\w+", clean, re.IGNORECASE) and re.search(r"\b(button|control|icon|pill|Premium|Grok|RETRY)\b", clean, re.IGNORECASE):
        return False
    if _is_owner_deterministic_detector_directive(clean):
        return False
    if _is_search_audit_or_routing_correction(clean):
        return False
    if _is_owner_browser_button_visibility_correction(clean):
        return False
    if re.search(
        r"\b(?:search|look\s+up|google|where\s+can\s+i\s+buy|where\s+to\s+buy|buy|shop|shopping)\b",
        clean,
        re.IGNORECASE,
    ):
        return True
    if re.search(
        r"\bfind\s+(?:me\s+)?(?:this|that|these|those|same)\b.{0,100}\b(?:online|web|internet|google|buy|shop|shopping)\b",
        clean,
        re.IGNORECASE,
    ):
        return True
    return False


def _owner_explicitly_requested_web_search(text: str) -> bool:
    """True only when the owner turn is an explicit search/buy command.

    r1397: cortex TOOL_CALL browser_search must not fire from stale wardrobe
    receipts when the owner is discussing LLMs, anchors, /sc, etc.

    Owner rule: FUCK GOOGLE. No search unless explicitly told or genuinely
    needed for unknown info not in current body visual receipts.
    """
    clean = " ".join((text or "").strip().split())
    if not clean:
        return False
    # Hard owner rule: direct UI click commands on the body (from screenshot)
    # must never be treated as search requests.
    if re.search(r"\b(?:click|press|tap)\s+(?:the\s+|on\s+)?\w+", clean, re.IGNORECASE) and re.search(r"\b(button|control|icon|pill|Premium|Grok|RETRY)\b", clean, re.IGNORECASE):
        return False
    if _is_search_audit_or_routing_correction(clean):
        return False
    if _is_owner_doctrine_correction_turn(clean):
        return False
    if _extract_explicit_search_query(clean):
        return True
    if _extract_explicit_engine_search_command(clean):
        return True
    if _extract_explicit_internet_search_command(clean):
        return True
    if _is_contextual_browser_search_effector_request(clean):
        return True
    if _extract_visual_image_search_command(clean):
        return True
    try:
        from System.swarm_youtube_search_intent import parse_explicit_youtube_search

        yt = parse_explicit_youtube_search(clean)
        if yt.get("is_search") and yt.get("query"):
            return True
    except Exception:
        pass
    return False


def _clean_contextual_search_query(query: str) -> str:
    q = " ".join(str(query or "").strip().strip("`'\"“”‘’ .?!,;:").split())
    q = re.sub(
        r"^(?:search|google|look\s+up|find)\s+(?:google\s+)?(?:for\s+)?",
        "",
        q,
        flags=re.IGNORECASE,
    ).strip()
    q = q.strip("`'\"“”‘’ .?!,;:")
    if _search_query_is_contextual_or_junk(q):
        return ""
    # Keep the effector URL readable and bounded; Google will handle the rest.
    return q[:120].strip()


def _parse_contextual_search_query(raw: str) -> str:
    text = str(raw or "").strip()
    if not text:
        return ""
    try:
        start, end = text.find("{"), text.rfind("}")
        if start >= 0 and end > start:
            data = json.loads(text[start:end + 1])
            if isinstance(data, dict):
                q = _clean_contextual_search_query(str(data.get("query") or ""))
                if q:
                    return q
    except Exception:
        pass
    for line in text.splitlines():
        line = re.sub(r"^\s*(?:query|search_query)\s*[:=-]\s*", "", line, flags=re.IGNORECASE)
        q = _clean_contextual_search_query(line)
        if q:
            return q
    return _clean_contextual_search_query(text)


def _latest_contextual_search_evidence(
    *,
    state_dir: Optional[Path | str] = None,
    history: Optional[List[Dict[str, Any]]] = None,
    max_age_s: float = 1800.0,
) -> str:
    """Recent visual/browser evidence for anaphoric shopping searches."""
    parts: list[str] = []
    try:
        from System.swarm_browser_photo_description import latest_photo_description
        photo = latest_photo_description(now=time.time(), max_age_s=max_age_s, state_dir=state_dir)
        desc = str(photo.get("description") or "").strip() if isinstance(photo, dict) else ""
        if desc:
            parts.append(f"Latest browser photo vision: {desc}")
    except Exception:
        pass
    try:
        from System.swarm_browser_page_state import latest_page_state
        ps = latest_page_state(now=time.time(), max_age_s=max_age_s, state_dir=state_dir)
        if isinstance(ps, dict):
            title = str(ps.get("title") or "").strip()
            url = str(ps.get("url") or "").strip()
            text = str(ps.get("text") or "").strip()
            if title or url:
                parts.append(f"Current/nearby browser page: {title} {url}".strip())
            if text:
                parts.append("Page text excerpt: " + text[:280])
    except Exception:
        pass
    for msg in list(history or [])[-8:]:
        try:
            role = str(msg.get("role") or "")
            content = " ".join(str(msg.get("content") or "").split())
        except Exception:
            continue
        if role == "assistant" and re.search(
            r"\b(?:swimsuit|outfit|dress|top|bottoms|leg\s+warmers?|boot\s+covers?|"
            r"heels|sunglasses|wardrobe|clothing|clothes|fuzzy|fluffy|puffy|furry|green|"
            r"checkered|plaid|floral|pink|black|beach|ocean|desert|rocks?)\b",
            content,
            re.IGNORECASE,
        ):
            parts.append("Recent Alice visual answer: " + content[:360])
    # Preserve order but remove duplicates.
    seen: set[str] = set()
    deduped: list[str] = []
    for part in parts:
        key = part.casefold()
        if part and key not in seen:
            seen.add(key)
            deduped.append(part)
    evidence = "\n".join(deduped)
    try:
        from System.swarm_wardrobe_pieces import wardrobe_pieces_block
        block = wardrobe_pieces_block(evidence)
        if block:
            evidence = (evidence + "\n" + block).strip()
    except Exception:
        pass
    return evidence[:2400]


def _latest_same_url_visual_anchor(
    url: str,
    *,
    max_age_s: float = 7200.0,
    state_dir: Optional[Path | str] = None,
) -> dict[str, Any]:
    """Same-URL prior photo receipt for selected-eye failures, never cross-URL."""
    if not str(url or "").strip():
        return {}
    try:
        from System.swarm_browser_photo_description import latest_same_url_photo_description
        return latest_same_url_photo_description(
            url=str(url or "").strip(),
            now=time.time(),
            max_age_s=max_age_s,
            state_dir=state_dir if state_dir is not None else _state_root(),
        )
    except Exception:
        return {}


def _same_url_visual_anchor_block(url: str, *, status: str = "", attempts: Any = None) -> str:
    """Context block: prior same-URL pixels are usable, but not a fresh scan."""
    anchor = _latest_same_url_visual_anchor(url)
    desc = str(anchor.get("description") or "").strip()
    if not desc:
        return ""
    arm = str(anchor.get("arm") or "a vision arm").strip()
    age = anchor.get("age_s")
    age_bits = f" about {int(float(age))}s ago" if isinstance(age, (int, float)) else ""
    chain = ""
    if attempts:
        try:
            chain = ", ".join(
                f"{str(a.get('arm') or '<arm>')}:{str(a.get('status') or 'failed')}"
                for a in attempts
                if isinstance(a, dict)
            )
        except Exception:
            chain = ""
    failure = str(status or "fresh_scan_failed")
    if chain:
        failure = f"{failure}; attempts: {chain}"
    return (
        "ANCHORED VISUAL EVIDENCE — the fresh selected-eye scan failed "
        f"({failure}), but I have a prior described viewport receipt for this exact same URL "
        f"from {arm}{age_bits}. Use it as same-page visual evidence, not as a fresh scan, "
        "and say the fresh scan failed if that distinction matters: "
        f"{desc}\n\n"
    )


def _eye_label_for_photo_status(status: str = "", arm: str = "") -> str:
    raw = f"{status} {arm}".lower()
    if "grok" in raw:
        return "Grok"
    if "codex" in raw:
        return "Codex"
    if "claude" in raw:
        return "Claude"
    if "qwen" in raw or "kimi" in raw:
        return "Qwen/Kimi"
    if "cline" in raw:
        return "Cline"
    return "selected eye"


def _is_selected_eye_failure_status(status: str = "", arm: str = "") -> bool:
    raw = f"{status} {arm}".lower()
    return bool(re.search(r"\b(?:grok|codex|claude|qwen|kimi|cline)_?eye_", raw))


def _sanitize_selected_eye_detail(status: str = "", detail: str = "") -> str:
    clean = str(detail or status or "selected eye failed").strip()
    low = clean.lower()
    if "bad-credentials" in low or "oauth2 access token could not be validated" in low:
        return (
            "The Grok OAuth credential could not be validated; I scheduled/need the Hermes "
            "xAI OAuth refresh before Grok can see pixels again."
        )
    if clean.startswith("{") and clean.endswith("}"):
        try:
            data = json.loads(clean)
            err = str(data.get("error") or data.get("message") or data.get("code") or "").strip()
            if err:
                return err[:240]
        except Exception:
            return "The selected eye returned a structured vendor error; I kept the raw JSON out of chat."
    return clean[:500]


def _selected_eye_failure_reply(status: str = "", arm: str = "", detail: str = "") -> str:
    eye = _eye_label_for_photo_status(status, arm)
    clean_detail = _sanitize_selected_eye_detail(status, detail)
    if clean_detail:
        return (
            f"My selected {eye} eye did not return a usable photo description. "
            f"{clean_detail} I did not switch to Claude or another provider for this {eye}-selected photo."
        )
    return (
        f"My selected {eye} eye did not return a usable photo description. "
        f"I did not switch to Claude or another provider for this {eye}-selected photo."
    )


_USER_FACING_LAYER1_PREFIX_RE = re.compile(
    r"^\s*(?:\*\*)?\s*Layer\s*1\s*:\s*(?:\*\*)?\s*",
    re.IGNORECASE,
)


def _strip_user_facing_layer1_prefix(reply: str) -> str:
    """Keep hardware doctrine out of ordinary user-facing reply prefixes."""
    text = str(reply or "")
    stripped = _USER_FACING_LAYER1_PREFIX_RE.sub("", text, count=1).strip()
    return stripped or text


def _same_url_visual_anchor_sentence(
    url: str,
    *,
    status: str = "",
    attempts: Any = None,
    arm: str = "",
) -> str:
    anchor = _latest_same_url_visual_anchor(url)
    desc = str(anchor.get("description") or "").strip()
    if not desc:
        return ""
    anchor_arm = str(anchor.get("arm") or "a vision arm").strip()
    eye = _eye_label_for_photo_status(status, arm)
    detail = str(status or "fresh scan failed").replace("_", " ")
    return (
        f"My fresh {eye} scan failed ({detail}), so I am not calling that a new look. "
        f"But the last same-URL visual receipt from {anchor_arm} says: {desc}"
    )


def _latest_browser_media_playback_error(
    *,
    max_age_s: float = 900.0,
    state_dir: Optional[Path | str] = None,
) -> dict[str, Any]:
    """Fresh browser media error receipt, e.g. Instagram's black-player failure."""
    try:
        from System.swarm_browser_page_state import (
            latest_page_state,
            media_playback_error_from_state,
        )
        ps = latest_page_state(
            now=time.time(),
            max_age_s=max_age_s,
            state_dir=state_dir if state_dir is not None else _state_root(),
        )
        err = media_playback_error_from_state(ps)
        if not err:
            return {}
        if not ps.get("is_current_page"):
            return {}
        out = dict(err)
        out["url"] = str(ps.get("url") or "")
        out["title"] = str(ps.get("title") or "")
        if isinstance(ps.get("media_playback"), Mapping):
            out["media_playback"] = dict(ps.get("media_playback") or {})
        out["fresh"] = bool(ps.get("fresh"))
        out["is_current_page"] = bool(ps.get("is_current_page"))
        return out
    except Exception:
        return {}


def _browser_media_playback_error_context(err: Mapping[str, Any] | None = None) -> str:
    e = dict(err or _latest_browser_media_playback_error())
    if not e:
        return ""
    msg = str(e.get("message") or "Sorry, we're having trouble playing this video.").strip()
    url = str(e.get("url") or "").strip()
    return (
        "SCREEN MEDIA ERROR RECEIPT - the visible browser player is black and shows "
        f"this exact playback error: \"{msg}\". "
        "This is the current screen state, not a photo/video frame. "
        "Report the playback error and do not invent visual content from the failed video"
        + (f". URL: {_browser_clean_address(url)}" if url else "")
        + "\n\n"
    )


def _describe_latest_browser_viewport_capture_with_eye(
    *,
    owner_text: str,
    url: str = "",
    current_model: str = "",
    state_dir: Optional[Path | str] = None,
) -> dict[str, Any]:
    """Describe the freshest Browser viewport capture when the live widget is absent.

    The normal path is AliceBrowserWidget.describe_current_photo(), which grabs fresh
    WebEngine pixels and calls the selected eye. In some Talk/AppStore arrangements
    the page-state receipt is visible to Talk but the Browser QWidget is not directly
    reachable. This bridge uses the Browser's own pending viewport PNG receipt so a
    current-pixels request can still reach pixels instead of stopping at URL/time DOM
    metadata.
    """
    state = state_dir if state_dir is not None else _state_root()
    try:
        from System.swarm_browser_photo_description import (
            extract_arm_final_text,
            latest_viewport_capture,
            looks_like_non_visual_arm_reply,
            record_photo_description,
        )
    except Exception as exc:
        return {"status": "viewport_bridge_import_failed", "attempts": [{"status": type(exc).__name__}]}

    cap = latest_viewport_capture(url=url or None, max_age_s=900.0, state_dir=state)
    if not cap and url:
        cap = latest_viewport_capture(max_age_s=900.0, state_dir=state)
        if cap and str(cap.get("url") or "") != str(url or ""):
            cap = {}
    if not cap:
        return {"status": "no_viewport_capture", "attempts": []}
    if cap.get("frame_stale"):
        return {"status": "viewport_capture_frame_stale", "capture": cap, "attempts": []}
    img_path = str(cap.get("image_ref") or "").strip()
    if not img_path or not Path(img_path).exists():
        return {"status": "viewport_capture_missing_image", "capture": cap, "attempts": []}

    current_arm = _eye_arm_for_cortex(current_model)
    try:
        from System.swarm_cortex_capabilities import pick_vision_arm, record_cortex_arm_habit

        pick = pick_vision_arm(
            current_arm=current_arm,
            current_model=current_model,
            unavailable=(),
            local_image_required=True,
        )
        arm = str(pick.get("selected_arm") or current_arm or "").strip()
        record_cortex_arm_habit(
            arm or current_arm,
            cortex_model=current_model,
            task="browser_viewport_still_frame",
            ok=bool(arm),
            status="selected" if arm else "no_arm",
            reason=str(pick.get("reason") or ""),
            state_dir=state,
            meta={"capture": {k: cap.get(k) for k in ("url", "source", "status", "image_ref", "age_s")}},
        )
    except Exception:
        arm = current_arm
    if not arm:
        record_photo_description(
            url or str(cap.get("url") or ""),
            description="",
            arm="",
            image_hash=str(cap.get("image_hash") or ""),
            image_ref=img_path,
            status="no_vision_arm",
            source="viewport_capture_vision_bridge",
            state_dir=state,
        )
        return {"status": "no_vision_arm", "capture": cap, "attempts": []}

    prompt = (
        "Look at the image at this exact path: "
        f"{img_path}\n"
        "This is Alice Browser's rendered viewport from Alice's own browser organ. "
        "The owner is asking about the current on-screen browser pixels/photo/frame on my display body. "
        "Ignore browser chrome, menus, sidebars, comments, and title bars unless needed for grounding. "
        "Describe the main visible subject/photo/frame itself in 2 short sentences: subject, key visible "
        "attributes, clothing/body pose when it is a person, setting, and relevant visual details. "
        "State only what is clearly visible."
    )
    attempts: list[dict[str, Any]] = []
    try:
        # Prefer the new native MLX VLM brain (strong vision, no Ollama needed, fixes blank cortex on images)
        vlm_desc = None
        try:
            from System import swarm_mlx_vlm_brain as _vlm
            if _vlm and getattr(_vlm, "describe_available", getattr(_vlm, "is_available", lambda: False))():
                vlm_desc = _vlm.describe_image(img_path, prompt, temperature=0.3, max_tokens=500)
        except Exception:
            vlm_desc = None

        effective_arm = arm
        if vlm_desc and not str(vlm_desc).startswith("[mlx-vlm"):
            raw = str(vlm_desc)
            ok = True
            status = "ok"
            effective_arm = "mlx_vlm_brain"
        elif arm == "ollama_vision_agent":
            from System.swarm_ollama_vision_arm import describe_image_local

            arm_result = describe_image_local(img_path, prompt, timeout_s=300, state_dir=state)
            ok = bool(getattr(arm_result, "ok", False))
            raw = str(getattr(arm_result, "output", "") or "")
            status = str(getattr(arm_result, "status", "") or ("ok" if ok else "failed"))
            effective_arm = arm
        else:
            from System.swarm_agent_arm_launcher import ask_agent_arm

            arm_result = ask_agent_arm(
                arm,
                prompt,
                state_dir=Path(state) if state is not None else None,
                timeout_s=900,
                image_path=img_path,
                model_hint=current_model,
            )
            ok = bool(getattr(arm_result, "ok", False))
            raw = str(getattr(arm_result, "output", "") or "")
            status = str(getattr(arm_result, "status", "") or ("ok" if ok else "failed"))
            effective_arm = arm
        desc = extract_arm_final_text(raw)
        if (
            looks_like_non_visual_arm_reply(desc)
            if desc else looks_like_non_visual_arm_reply(raw)
        ):
            desc = ""
            status = "non_visual_arm_reply"
        attempts.append({"arm": effective_arm, "ok": ok and bool(desc), "status": status, "source": "viewport_capture"})
        if ok and desc:
            record_photo_description(
                url or str(cap.get("url") or ""),
                description=desc,
                arm=effective_arm,
                image_hash=str(cap.get("image_hash") or ""),
                image_ref=img_path,
                status="described",
                source="viewport_capture_vision_bridge",
                state_dir=state,
            )
            return {
                "status": "described",
                "arm": effective_arm,
                "description": desc,
                "capture": cap,
                "attempts": attempts,
            }
        record_photo_description(
            url or str(cap.get("url") or ""),
            description="",
            arm=effective_arm,
            image_hash=str(cap.get("image_hash") or ""),
            image_ref=img_path,
            status=status or "failed",
            source="viewport_capture_vision_bridge",
            state_dir=state,
        )
        return {"status": status or "failed", "arm": effective_arm, "capture": cap, "attempts": attempts}
    except Exception as exc:
        status = f"viewport_bridge_{type(exc).__name__}"
        attempts.append({"arm": arm, "ok": False, "status": status, "source": "viewport_capture"})
        try:
            record_photo_description(
                url or str(cap.get("url") or ""),
                description="",
                arm=arm,
                image_hash=str(cap.get("image_hash") or ""),
                image_ref=img_path,
                status=status,
                source="viewport_capture_vision_bridge",
                state_dir=state,
            )
        except Exception:
            pass
        return {"status": status, "arm": arm, "capture": cap, "attempts": attempts}


def _browser_media_playback_error_reply(prefix: str = "") -> str:
    err = _latest_browser_media_playback_error()
    msg = str(err.get("message") or "Sorry, we're having trouble playing this video.").strip()
    url = str(err.get("url") or "").strip()
    title = str(err.get("title") or "the current browser video").strip()
    site = _browser_source_label_for_url(url) or "this page"
    media = err.get("media_playback") if isinstance(err.get("media_playback"), Mapping) else {}
    codec_status = media.get("codec_status") if isinstance(media.get("codec_status"), Mapping) else {}
    diagnosis = codec_status.get("diagnosis") if isinstance(codec_status.get("diagnosis"), Mapping) else {}
    label = str(diagnosis.get("label") or "").strip()
    recent_errors = codec_status.get("recent_errors") if isinstance(codec_status.get("recent_errors"), list) else []
    if label == "NO_MEDIA_ERROR" and recent_errors:
        try:
            from System.swarm_media_codec_bridge import diagnose_media_error_code

            first_code = recent_errors[0].get("code") if isinstance(recent_errors[0], Mapping) else None
            label = str(diagnose_media_error_code(first_code).get("label") or "media decoder error")
        except Exception:
            label = "media decoder error"
    code_line = f" Embedded decoder receipt: {label}." if label else ""
    native_line = (
        " Use Alice's in-place native decode surface inside the browser (🎬) for this stream."
        if bool(diagnosis.get("native_handoff_recommended") or codec_status.get("native_handoff_available"))
        else ""
    )
    lead = (prefix.strip() + " ") if prefix else ""
    return (
        f"{lead}I am looking at a {site} video playback error on {title}: \"{msg}\"."
        f"{code_line} The player has no usable video pixels for me to describe from this frame."
        f"{native_line}"
    )


_VISUAL_REPLY_CUE_RE = re.compile(
    r"\b(?:photo|picture|image|video|frame|screen|player|portrait|wearing|outfit|"
    r"body|face|hair|dress|shirt|robe|photo/video|looks?|standing|sitting|posing)\b",
    re.IGNORECASE,
)


def _browser_visual_reply_self_check(reply: str, owner_text: str = "") -> tuple[str, dict[str, Any]]:
    """Last-mile contradiction pass between browser receipt and visual reply.

    This does not block Alice. It corrects a stale/imagined visual answer when
    the freshest browser receipt says the visible media is a playback-error
    screen, not usable pixels.

    r904 (George live, twice): VISUAL SOURCE RANKING (r903) — decoder status
    is the FLOOR of the ranking. Only a FRESH error (<=120s) may override
    anything, and a PHOTO ask never loses the mic to a VIDEO decoder error.
    """
    err = _latest_browser_media_playback_error(max_age_s=120.0)
    if not err:
        return reply, {"changed": False, "reason": "no_fresh_media_error_receipt_freshness_wins"}

    text = str(reply or "")
    low = text.lower()
    if "trouble playing this video" in low or "playback error" in low or "no usable video pixels" in low:
        return reply, {"changed": False, "reason": "reply_already_names_error", "error": err}

    owner_visual = bool(
        _is_browser_photo_description_query(owner_text)
        or _is_browser_page_cortex_description_query(owner_text)
        or _VISUAL_REPLY_CUE_RE.search(owner_text or "")
    )
    reply_visual = bool(_VISUAL_REPLY_CUE_RE.search(text))
    if not (owner_visual or reply_visual):
        return reply, {"changed": False, "reason": "not_a_visual_reply", "error": err}

    # r904: a PHOTO/picture/image ask outranks a VIDEO decoder error (r903
    # ranking law). George asked "DESCRIBE CURRENT PHOTO" and this pass
    # replaced a real description with NO_MEDIA_ERROR — twice. Keep the
    # description; the decoder note becomes quiet context, never the reply.
    owner_low = " ".join((owner_text or "").lower().split())
    owner_asks_photo = bool(
        re.search(r"\b(?:photo|picture|image|pic|pics)\b", owner_low)
        and not re.search(r"\b(?:video|playing|playback|player)\b", owner_low)
    )
    if owner_asks_photo and reply_visual:
        note = (
            " (Body note: the page's video player reports a playback error;"
            " this description comes from photo/pixel receipts, which outrank"
            " decoder status.)"
        )
        if "playback error" in low or "no usable video pixels" in low:
            return reply, {"changed": False, "reason": "photo_ask_reply_already_notes_error", "error": err}
        return text + note, {
            "changed": True,
            "reason": "photo_ask_outranks_video_decoder_error_r904",
            "error": err,
        }

    # r907 (George: "if there is a H264 video on Instagram she can't see it,
    # she has to /SC and see her own body browser, then cortex, then answer"):
    # before the error sentence takes the mic, the body LOOKS AT ITS OWN
    # SCREEN — the autonomous self-screenshot reflex. Viewport pixels outrank
    # decoder status in the r903 ranking; the error becomes a footnote, not
    # the answer. Fires only when a FRESH real error exists (r904/r905 guards
    # upstream) on a visual turn — the exact undecodable-video case.
    try:
        _sc = _describe_latest_browser_viewport_capture_with_eye(
            owner_text=owner_text or "",
            url=str(err.get("url") or ""),
        )
        _sc_desc = str(_sc.get("description") or "").strip() if isinstance(_sc, dict) else ""
        if _sc_desc:
            corrected = (
                "I could not decode the video stream, so I looked at my own "
                "browser screen instead (self-screenshot reflex): " + _sc_desc
            )
            return corrected, {
                "changed": True,
                "reason": "video_error_self_screenshot_fallback_r907",
                "error": err,
                "viewport_status": str(_sc.get("status") or "") if isinstance(_sc, dict) else "",
            }
    except Exception:
        pass

    corrected = _browser_media_playback_error_reply()
    return corrected, {
        "changed": True,
        "reason": "browser_media_error_contradicted_visual_reply",
        "error": err,
        "original_preview": text[:240],
    }


def _fallback_contextual_shopping_query(evidence: str, owner_text: str = "") -> str:
    """Last-resort grounded query if the cortex is unavailable."""
    # r1401: positive gate only — owner must have explicitly requested search/buy.
    if not _owner_explicitly_requested_web_search(owner_text):
        return ""
    try:
        from System.swarm_wardrobe_pieces import resolve_wardrobe_piece_query
        resolved = resolve_wardrobe_piece_query(owner_text, evidence)
        query = _clean_contextual_search_query(str(resolved.get("query") or ""))
        if query:
            return query
    except Exception:
        pass
    low = str(evidence or "").lower()
    if not low:
        return ""
    colors = [
        c for c in (
            "pink", "black", "white", "blue", "green", "yellow", "red",
            "brown", "orange", "purple", "gold", "silver",
        )
        if re.search(rf"\b{re.escape(c)}\b", low)
    ][:3]
    patterns = [
        p for p in (
            "fuzzy", "fluffy", "puffy", "furry", "faux fur", "checkered", "plaid",
            "gingham", "striped", "floral", "animal print", "cow print", "polka dot", "triangle",
        )
        if p in low
    ][:2]
    item = "swimsuit"
    if "leg warmer" in low or "boot cover" in low:
        item = "leg warmers"
    elif "heels" in low:
        item = "heels"
    elif "dress" in low:
        item = "dress"
    terms = colors + patterns + [item]
    q = " ".join(dict.fromkeys(t for t in terms if t))
    if len(q.split()) >= 2:
        return q
    return ""


def _compose_contextual_search_query_with_cortex(
    owner_text: str,
    evidence: str,
    *,
    model: str = "",
) -> dict[str, str]:
    """Ask the active cortex to turn visual/browser evidence into a concrete search query."""
    evidence = str(evidence or "").strip()
    if not evidence:
        return {"query": "", "source": "no_evidence", "raw": ""}
    system = (
        "You are Alice's cortex choosing a web search query from grounded visual/browser evidence. "
        "The owner used anaphora like 'this type', so resolve it from the evidence. "
        "If the owner asks for a vague wardrobe piece on a human (for example 'green puffy leg things'), "
        "use the WARDROBE PIECE CANDIDATES and search the actual fashion item name, such as "
        "'green fuzzy faux fur leg warmers boot covers'. "
        "Return ONLY JSON: {\"query\":\"...\",\"reason\":\"...\"}. "
        "The query must be concrete product-search words, not 'on Google', not 'this', not a URL."
    )
    user = (
        f"Owner request: {owner_text}\n\n"
        f"Grounded evidence:\n{evidence}\n\n"
        "Compose the Google query for where to buy the item/style."
    )
    messages = [{"role": "system", "content": system}, {"role": "user", "content": user}]
    raw = ""
    model_name = str(model or "").strip()
    try:
        if _DIRECT_VLM_AVAILABLE and model_name and _is_direct_vlm_model(model_name):
            # Direct MLX VLM (osmQwopus) as command cortex — streams tokens for tool-calling turns
            # (e.g. "open <named subject> pool image grid" should execute search/nav instead of narrate).
            full: list[str] = []
            for kind, payload in _direct_vlm_stream_chat(
                model_name,
                messages,
                temperature=0.2,
            ):
                if kind == "token":
                    full.append(str(payload))
                elif kind == "done":
                    raw = str(payload) or "".join(full)
                    break
                elif kind == "error":
                    raw = ""
                    break
            if not raw:
                raw = "".join(full)
        elif _CLOUD_AVAILABLE and model_name and _is_cloud_model(model_name):
            full: list[str] = []
            for kind, payload in _cloud_stream_chat(
                model_name,
                messages,
                temperature=0.2,
                timeout_s=min(90, int(_cloud_brain_timeout_s())),
            ):
                if kind == "token":
                    full.append(str(payload))
                elif kind == "done":
                    raw = str(payload) or "".join(full)
                    break
                elif kind == "error":
                    raw = ""
                    break
            if not raw:
                raw = "".join(full)
        else:
            import urllib.request
            model_name = model_name or resolve_ollama_model(app_context="talk_to_alice", query_text=owner_text)
            payload = {
                "model": model_name,
                "messages": messages,
                "stream": False,
                "keep_alive": _ollama_keep_alive("15s"),
                "think": False,
                "options": {
                    "temperature": 0.2,
                    "top_p": 0.8,
                    "num_ctx": min(4096, _ollama_num_ctx(4096)),
                    "num_predict": 80,
                    "repeat_penalty": 1.08,
                },
            }
            body = json.dumps(payload).encode("utf-8")
            req = urllib.request.Request(
                f"{_OLLAMA_URL}/api/chat",
                data=body,
                headers={"Content-Type": "application/json"},
            )
            with urllib.request.urlopen(req, timeout=min(20.0, _ollama_brain_timeout_s(20.0))) as resp:
                data = json.loads(resp.read().decode("utf-8", errors="replace") or "{}")
            msg = data.get("message") if isinstance(data.get("message"), dict) else {}
            raw = str(msg.get("content") or data.get("response") or "").strip()
    except Exception:
        raw = ""
    query = _parse_contextual_search_query(raw)
    return {"query": query, "source": "cortex" if query else "cortex_failed", "raw": raw[:500]}


_VISUAL_SUBJECT_OWNER_PATTERNS = (
    re.compile(
        r"\b(?:her|his|their|the\s+(?:human\s+)?(?:model|person|woman|man|subject)|"
        r"this\s+(?:human\s+)?(?:model|person|woman|man|subject))\s+"
        r"(?:name\s+is|is\s+called|called)\s+"
        r"(?P<name>@?[A-Za-z][A-Za-z0-9_.'-]*(?:\s+[A-Za-z][A-Za-z0-9_.'-]*){0,3})",
        re.IGNORECASE,
    ),
    re.compile(
        r"\b(?:name\s+is|called)\s+"
        r"(?P<name>@?[A-Za-z][A-Za-z0-9_.'-]*(?:\s+[A-Za-z][A-Za-z0-9_.'-]*){0,3})",
        re.IGNORECASE,
    ),
)
_VISUAL_SUBJECT_NAME_REJECT = {
    "a", "an", "the", "human", "person", "model", "woman", "man", "girl", "boy",
    "body", "photo", "picture", "image", "browser", "instagram", "youtube",
    "you", "can", "cannot", "cant", "can't", "why", "what", "please", "pls",
    "music", "artist", "actress", "actor", "runway", "posts", "followers",
    "following", "verified", "official", "profile",
    "on", "your", "screen", "love", "let", "stare", "stared", "staring", "monitor",
    "me", "web", "search", "google", "from", "game", "thrones", "show", "display", "open", "find", "look",
}


def _clean_visual_subject_name(raw: str) -> str:
    """Clean a grounded person/model name without inventing one."""
    s = str(raw or "").strip()
    if not s:
        return ""
    s = re.split(r"[,;:.?!()\[\]\n\r]|(?:\s+[—-]\s+)", s, maxsplit=1)[0]
    s = re.sub(r'^(with|of|for)\s+', '', s, flags=re.IGNORECASE).strip()
    s = re.split(
        r"\b(?:you|can|cannot|can't|why|what|please|pls|photo|picture|browser|me|web|search|google|from|game|thrones|show|display|open|find|look|let|stare|stared|staring|monitor)\b",
        s,
        maxsplit=1,
        flags=re.IGNORECASE,
    )[0]
    s = " ".join(s.strip(" \t\"'`“”‘’/@#").split())
    if not s or len(s) > 48:
        return ""
    words = s.split()
    if len(words) > 4:
        return ""
    if any(re.search(r"\d", w) for w in words):
        return ""
    if any(w.casefold().strip("_-.") in _VISUAL_SUBJECT_NAME_REJECT for w in words):
        return ""
    if s.casefold() in _VISUAL_SUBJECT_NAME_REJECT:
        return ""
    if not re.search(r"[A-Za-z]", s):
        return ""
    if len(words) == 1 and len(words[0]) < 2:
        return ""
    return " ".join(w[:1].upper() + w[1:] if w.islower() else w for w in words)


_VISUAL_SUBJECT_PRONOUNS = {
    "her", "him", "them", "they", "she", "he", "subject", "person", "model", "woman", "man",
}


def _clean_visual_photo_subject(raw: str) -> str:
    name = _clean_visual_subject_name(raw)
    if not name:
        return ""
    if name.casefold() in _VISUAL_SUBJECT_PRONOUNS:
        return ""
    if name.isupper():
        name = " ".join(part[:1].upper() + part[1:].lower() for part in name.split())
    return name


_VISUAL_PHOTO_SEARCH_PATTERNS = (
    re.compile(
        r"\b(?:show|display|open|load|pull\s+up|bring\s+up|find|search|look\s+up|pls|please)\b"
        r".{0,80}\b(?:photos?|pics?|pictures?|images?)\s+(?:of|for|web\s+of)\s+"
        r"(?P<name>[A-Za-z][A-Za-z0-9_.'-]*(?:\s+[A-Za-z][A-Za-z0-9_.'-]*){0,4})",
        re.IGNORECASE,
    ),
    # r674 (George 13:34 "I WANT TO SEE DUA LIPA PHOTOS" got LINKS instead of her browser
    # executing): desire-phrased image requests are commands for her own limb.
    re.compile(
        r"\bI\s+(?:want|wanna|would\s+like|'?d\s+like)\s+to\s+see\s+"
        r"(?P<name>[A-Za-z][A-Za-z0-9_.'-]*(?:\s+[A-Za-z][A-Za-z0-9_.'-]*){0,4})"
        r"\s+(?:photos?|pics?|pictures?|images?)\b",
        re.IGNORECASE,
    ),
    re.compile(
        r"\b(?:search|find|look\s+up)\s+(?:for\s+)?"
        r"(?P<name>[A-Za-z][A-Za-z0-9_.'-]*(?:\s+[A-Za-z][A-Za-z0-9_.'-]*){0,4})"
        r"\s+(?:in|on|with)\s+google\s+(?:images?|photos?|pics?|pictures?)\b",
        re.IGNORECASE,
    ),
    re.compile(
        r"\b(?:show|display|open|load|pull\s+up|bring\s+up)\b\s+"
        r"(?P<name>[A-Za-z][A-Za-z0-9_.'-]*(?:\s+[A-Za-z][A-Za-z0-9_.'-]*){0,4})"
        r"\s+(?:photos?|pics?|pictures?|images?|body)\b",
        re.IGNORECASE,
    ),
    # catch "pls photos of NAME", "pics of NAME", "photos web of NAME", "photos of NAME from game of thrones"
    re.compile(
        r"\b(?:pls|please)\s+(?:photos?|pics?)\s+(?:of|for|web\s+of)\s+"
        r"(?P<name>[A-Za-z][A-Za-z0-9_.'-]*(?:\s+[A-Za-z][A-Za-z0-9_.'-]*){0,4})",
        re.IGNORECASE,
    ),
    re.compile(
        r"\b(?:photos?|pics?)\s+web\s+of\s+"
        r"(?P<name>[A-Za-z][A-Za-z0-9_.'-]*(?:\s+[A-Za-z][A-Za-z0-9_.'-]*){0,4})",
        re.IGNORECASE,
    ),
    re.compile(
        r"\b(?:i\s+(?:want|would\s+like)\s+to\s+see|let\s+me\s+see)\s+"
        r"(?:photos?|pics?|pictures?|images?)\s+(?:of\s+)?"
        r"(?P<name>[A-Za-z][A-Za-z0-9_.'-]*(?:\s+[A-Za-z][A-Za-z0-9_.'-]*){0,4})",
        re.IGNORECASE,
    ),
    # "image grid for <name>" or "<name> image grid" or "by the pool image grid for <name>"
    re.compile(
        r"\b(?:image\s+grid|photos?\s+grid|pics?\s+grid|images?\s+grid)\s+(?:for\s+|of\s+)?"
        r"(?P<name>[A-Za-z][A-Za-z0-9_.'-]*(?:\s+[A-Za-z][A-Za-z0-9_.'-]*){0,4})",
        re.IGNORECASE,
    ),
    re.compile(
        r"\b(?P<name>[A-Za-z][A-Za-z0-9_.'-]*(?:\s+[A-Za-z][A-Za-z0-9_.'-]*){0,4})\s+(?:image\s+grid|photos?\s+grid|pics?\s+grid|images?\s+grid)\b",
        re.IGNORECASE,
    ),
    # for "i don't see <subject> on your screen body" etc, to extract subject for visibility force
    re.compile(
        r"\b(?:see|look at|view)\s+(?P<name>(?![Ii]n\b|[Oo]n\b|[Aa]t\b|[Tt]he\b|[Yy]our\b|[Bb]ody\b)[A-Za-z][A-Za-z0-9_.'-]*(?:\s+[A-Za-z][A-Za-z0-9_.'-]*){0,2})\s+(?:on\s+(?:your\s+body\s+)?screen|body\s+screen|screen body)\b",
        re.IGNORECASE,
    ),
)

_VISUAL_PHOTO_PRONOUN_SEARCH_RE = re.compile(
    r"\b(?:show|display|open|load|pull\s+up|bring\s+up|find|search|look\s+up)\b"
    r".{0,90}\b(?:her|him|them|the\s+subject|that\s+person|that\s+model)\b"
    r".{0,90}\b(?:google\s+)?(?:images?|photos?|pics?|pictures?)\b"
    r"|\b(?:google\s+)?(?:images?|photos?|pics?|pictures?)\b"
    r".{0,90}\b(?:her|him|them|the\s+subject|that\s+person|that\s+model)\b",
    re.IGNORECASE,
)

_BROWSER_VISUAL_SEARCH_CORRECTION_RE = re.compile(
    r"^\s*(?:i\s+)?(?:meant|mean)\s+(?:the\s+)?(?:(?:alice|artist)\s+)?browser\.?\s*$",
    re.IGNORECASE,
)


def _is_browser_visual_search_correction(text: str) -> bool:
    clean = " ".join((text or "").strip().split())
    return bool(clean and _BROWSER_VISUAL_SEARCH_CORRECTION_RE.search(clean))


def _browser_visual_search_correction_prompt_block(
    owner_text: str,
    *,
    state_dir: Optional[Path | str] = None,
) -> str:
    if not _is_browser_visual_search_correction(owner_text or ""):
        return ""
    subject = _recent_visual_photo_subject_name("", state_dir=state_dir if state_dir is not None else _state_root())
    if not subject:
        return ""
    return (
        "BROWSER VISUAL SEARCH FOLLOW-UP CONTEXT (r543):\n"
        "Owner corrected the action target to Alice Browser after a visual photo request. "
        f"The latest receipted visual-photo subject from recent owner turns is `{subject}`.\n"
        f"Action plan: search/open Google Images in Alice Browser for `{subject} photos`. "
        "Do not invent a gallery, title, preview, or unrelated app. Speak minimally, then execute with an effector receipt."
    )


def _explicit_visual_photo_subject_from_text(text: str) -> str:
    clean = " ".join((text or "").strip().split())
    if not clean:
        return ""
    for pattern in _VISUAL_PHOTO_SEARCH_PATTERNS:
        m = pattern.search(clean)
        if not m:
            continue
        name = _clean_visual_photo_subject(str(m.group("name") or ""))
        if name:
            return name
    return ""


_DIRECT_VISUAL_IMAGE_GRID_RE = re.compile(
    r"\b(?:image\s+grid|images?\s+grid|photos?\s+grid|pictures?\s+grid)\b"
    r"|\bgrid\s+(?:for|of|with)\b",
    re.IGNORECASE,
)
_BARE_VISUAL_IMAGE_QUERY_CUE_RE = re.compile(
    r"\b(?:by\s+the\s+pool|pool|swimsuit|swimwear|beach|ocean|red\s+carpet|"
    r"runway|stage|outfit|dress|wearing|body|screen|body\s+screen|your\s+body\s+screen|on\s+screen)\b",
    re.IGNORECASE,
)
_VISUAL_PRAISE_NOT_SEARCH_RE = re.compile(
    r"\b(?:looks?|looked|seems?|is|are|was|were)\s+"
    r"(?:amazing|beautiful|gorgeous|hot|nice|good|great|stunning|sexy|"
    r"incredible|awesome|pretty)\b"
    r"|\b(?:love|like|admire)\b.{0,80}\b(?:body|photo|picture|image|look|looks)\b",
    re.IGNORECASE,
)
_BARE_VISUAL_SEARCH_IMPERATIVE_RE = re.compile(
    r"\b(?:show|display|open|load|search|find|look\s+up|pull\s+up|bring\s+up|"
    r"let\s+me\s+see|i\s+(?:want|would\s+like)\s+to\s+see)\b",
    re.IGNORECASE,
)
_BARE_VISUAL_IMAGE_QUERY_BLOCK_RE = re.compile(
    r"\b(?:describe|explain|why|how|who|what|where|when|career|song|songs|album|"
    r"lyrics|biograph\w*|history|code|router|plan|select|click|choose|tap|"
    r"current|browser\s+screen|screen\s+content|the\s+screen\s+content|"
    r"stare|stared|staring|admire)\b",
    re.IGNORECASE,
)

_CURRENT_BROWSER_VISUAL_HOLD_RE = re.compile(
    r"\b(?:let\s+me|i\s+(?:want|wanna|would\s+like|need)\s+to|can\s+i|may\s+i)\b"
    r".{0,90}\b(?:stare|look|keep\s+looking|watch|admire)\b"
    r".{0,120}\b(?:body|photo|picture|image|browser|screen|monitor|display)\b"
    r"|\b(?:your\s+beautiful\s+(?:screen|monitor|display)\s+body|"
    r"(?:screen|monitor|display)\s+body\b.{0,50}\b(?:i\s+love\s+you|love\s+you|beautiful))\b",
    re.IGNORECASE,
)

_VISUAL_GRID_CONTROL_TAIL_RE = re.compile(
    # r688 (George 2026-06-07): his personal phrase to Alice was lifted into
    # this pattern by doctors without his order — removed on his word. Only
    # generic control phrasing stays; owner-personal language reaches Alice
    # through her field and receipts (§1.D), never hardcoded by a doctor.
    r"\b(?:don't\s+let|do\s+not\s+let)\b",
    re.IGNORECASE,
)

_VISUAL_GRID_QUERY_STOPWORDS = {
    "alice", "browser", "screen", "body", "image", "images", "photo", "photos",
    "pic", "pics",
    "picture", "pictures", "grid", "for", "of", "with", "please", "pls",
    "show", "display", "open", "load", "pull", "bring", "up", "want", "would",
    "like", "to", "see", "i", "me", "you", "your", "current", "now", "section",
    "copy", "on", "at", "let", "stare", "stared", "staring", "monitor", "love",
}


def _is_direct_visual_image_grid_request(text: str) -> bool:
    clean = " ".join((text or "").strip().split())
    return bool(clean and _DIRECT_VISUAL_IMAGE_GRID_RE.search(clean))


def _is_current_browser_visual_hold_request(text: str) -> bool:
    """Owner is asking to stay with/feel the current browser visual, not search.

    r665: "LET ME STARE AT ... ON YOUR MONITOR BODY ... I LOVE YOU" got
    converted into Google Images for "Let STARE ... MONITOR LOVE photos".
    That is a current visual/affection turn for cortex, not a deterministic
    search effector. Explicit search/photo commands remain executable.
    """
    clean = " ".join((text or "").strip().split())
    if not clean:
        return False
    if re.search(
        r"\b(?:search|find|look\s+up|google|ebay|youtube|open\s+(?:the\s+)?(?:url|link|site)|"
        r"(?:photos?|pics?|pictures?|images?)\s+(?:of|for|web\s+of)|image\s+grid|photos?\s+grid)\b",
        clean,
        re.IGNORECASE,
    ):
        return False
    return bool(_CURRENT_BROWSER_VISUAL_HOLD_RE.search(clean))


def _bare_visual_photo_subject_from_text(text: str) -> str:
    """Extract a subject from a bare visual query fragment.

    Example: "<named subject> by the pool in swimsuit" is owner food for the browser
    image-grid organ, not a general biography question and not a stale receipt.
    """
    clean = " ".join((text or "").strip().split())
    if not clean or len(clean.split()) > 16:
        return ""
    if _is_current_browser_visual_hold_request(clean):
        return ""
    if _VISUAL_PRAISE_NOT_SEARCH_RE.search(clean) and not _BARE_VISUAL_SEARCH_IMPERATIVE_RE.search(clean):
        return ""
    if "?" in clean or _BARE_VISUAL_IMAGE_QUERY_BLOCK_RE.search(clean):
        return ""
    cue = _BARE_VISUAL_IMAGE_QUERY_CUE_RE.search(clean)
    if cue and not _BARE_VISUAL_SEARCH_IMPERATIVE_RE.search(clean):
        # r1401: pool/beach visual cues alone — owner must command search explicitly.
        return ""
    if not cue:
        # also support plain "photos/pics of NAME" or "photos web of NAME" as bare visual search
        m = re.search(
            r"\b(?:pls|please)?\s*(?:photos?|pics?)\s+(?:web\s+)?of\s+(?P<name>[A-Za-z][A-Za-z0-9_.'-]*(?:\s+[A-Za-z][A-Za-z0-9_.'-]*){0,4})",
            clean,
            re.IGNORECASE,
        )
        if m:
            name = m.group("name")
            subject = _clean_visual_photo_subject(name)
            if subject:
                return subject
        return ""
    prefix = clean[: cue.start()].strip(" ,;:-")
    prefix = re.sub(
        r"^(?:(?:alice|please|pls|ok|okay|yes)[,\s]+)*(?:show|display|open|load|"
        r"search|find|look\s+at|pull\s+up|bring\s+up|let\s+me\s+see)\s+",
        "",
        prefix,
        flags=re.IGNORECASE,
    ).strip(" ,;:-")
    # strip trailing prep like " in" or " on" before the visual cue
    # also screen phrases anywhere
    prefix = re.sub(
        r"\b(?:on your body screen|on screen|body screen|your body screen|on the screen)\b",
        " ",
        prefix,
        flags=re.IGNORECASE,
    )
    prefix = re.sub(r'\s+(?:in|on|at|the|your|body)\s*$', '', prefix, flags=re.IGNORECASE).strip(" ,;:-")
    prefix = re.sub(r"\s+", " ", prefix).strip(" ,;:-")
    # leading please etc already handled above
    subject = _clean_visual_photo_subject(prefix)
    if subject:
        return subject
    return ""


def _is_bare_visual_image_search_request(text: str) -> bool:
    return bool(_bare_visual_photo_subject_from_text(text))


def _is_bonsai_generation_request(text: str) -> Optional[str]:
    """Detect chat requests to generate an image via the on-device Bonsai organ.

    "bonsai a photo of a floating quantum ant colony in soft morning light teaching itself"
    or "generate a picture with bonsai of [subject]" etc.

    Returns the extracted prompt if it looks like a Bonsai request, else None.
    This lets the owner ask naturally in the main Talk chat and have the render
    land in the global conversation + visual_stigmergy field (OBSERVED_AI_GENERATED).
    """
    if not text:
        return None
    low = " " + (text or "").lower() + " "
    # r748 — the 11:54 wound (receipt b9e7e72b): "We just updated the Bonsai
    # app. You can open Bonsai app, please." fell through to the tail fallback
    # and became a RENDER of the owner's words instead of an app OPEN. Law:
    # open/launch/close commands about bonsai are APP COMMANDS — yield to the
    # app lane, never render.
    if re.search(r"\b(open|launch|start|show|close|quit)\b[\w\s,'!]{0,40}\bbonsai\b", low):
        return None
    bonsai_triggers = (" bonsai ", " with bonsai", " bonsai a ", " bonsai image", " bonsai photo", " bonsai picture")
    if not any(t in low for t in bonsai_triggers):
        # also catch "generate a photo of X" + later "bonsai" or explicit
        if not any(k in low for k in ("generate a photo", "generate a picture", "create an image", "make a picture", "draw with bonsai")):
            return None
    # crude but effective extraction for the common patterns
    # r748 ROOT-CAUSE FIX of r429 'irds': the old code searched the SPACE-PADDED
    # lowercase string but sliced the UNPADDED text — off by one, eating the
    # first character of every extracted prompt ("birds" → "irds"). Search and
    # slice now use aligned strings.
    tlow = (text or "").lower()
    for prefix in ("bonsai a photo of ", "bonsai a picture of ", "bonsai image of ", "bonsai photo of ",
                   "generate a photo of ", "generate a picture of ", "create an image of ", "make a picture of "):
        idx = tlow.find(prefix)
        if idx != -1:
            prompt = text[idx + len(prefix):].strip().strip("?.,!\"'")
            if len(prompt) >= 4:
                return prompt
    # r748 — the tail fallback fires ONLY when the utterance STARTS with
    # "bonsai ..." (a true imperative to the organ). Mid-sentence mentions of
    # bonsai are conversation, not orders — they ride to the cortex/app lane.
    # This kills the r429 'irds' machine at its root.
    if low.strip().startswith("bonsai "):
        prompt = text.strip()[len("bonsai "):].strip().strip("?.,!\"'")
        if len(prompt) >= 4:
            return prompt
    return None


def _is_owner_visibility_complaint_for_browser(text: str) -> bool:
    """Owner says he cannot see the browser/grid on his physical eyes / monitors.
    This is a direct body command to present the display arm (launcher tab + Alice Browser MDI).
    "I DON'T SEE ALICE BROWSER OPEN. WHERE?" or "YOUR DISPLAY IS MY DISPLAY AND MY EYES CAN NOT CONFIRM".
    Must cause action (trigger + switch tab), not passive state claim.
    """
    clean = " ".join((text or "").strip().split()).lower()
    if not clean:
        return False
    complaint = any(p in clean for p in ("don't see", "do not see", "cant see", "cannot see", "i don't see", "where", "my eyes can not confirm", "your display is my display", "your display is my", "eyes can not confirm"))
    browser_or_grid = any(p in clean for p in ("browser", "grid", "display body", "launcher", "tab", "open", "display", "screen body", "on your screen body", "on screen body"))
    visual_context = any(
        p in clean
        for p in (
            "image",
            "photo",
            "picture",
            "photos",
            "pics",
            "pool",
            "visual",
            "celebrity",
            "subject",
            "person",
        )
    )
    return complaint and (browser_or_grid or visual_context)


def _visual_photo_search_query_from_text(text: str, subject: str) -> str:
    """Build the images query, preserving owner visual modifiers.

    "in red dress... by the pool image grid for WITH <named subject> please" (modifiers in any order)
    (or reverse order) should search the browser image grid for the target plus visual
    constraints like "in red dress by the pool", not control words, not prior names.
    """
    subj = " ".join(str(subject or "").strip().split())
    if not subj:
        return ""
    clean = " ".join(str(text or "").strip().split())
    if not clean:
        return f"{subj} photos"
    source = _VISUAL_GRID_CONTROL_TAIL_RE.sub(" ", clean)
    # Strip "you already know about <prior context names>" reminder blocks (owner telling us to ignore
    # previous named subjects). Non-greedy to . so we do not eat later visual specifiers
    # when the reminder appears before the "image grid for X in red dress" command.
    source = re.sub(
        r"\byou\s+already\s+know\b[^.]*\.?",
        " ",
        source,
        flags=re.IGNORECASE,
    )
    try:
        subj_pat = r"\b(?:with|of|for)?\s*" + r"\s+".join(re.escape(p) for p in subj.split()) + r"\b"
        source = re.sub(subj_pat, " ", source, flags=re.IGNORECASE)
    except Exception:
        pass
    source = _DIRECT_VISUAL_IMAGE_GRID_RE.sub(" ", source)
    source = re.sub(r"[,;:.?!()\[\]{}\"'`“”‘’/\\]+", " ", source)
    words: List[str] = []
    seen: set[str] = set()
    for token in source.split():
        key = token.casefold().strip("_-.")
        if not key or key in _VISUAL_GRID_QUERY_STOPWORDS:
            continue
        if re.search(r"\d", key):
            continue
        if len(key) < 2 and key not in {"by", "in"}:
            continue
        if key in seen:
            continue
        seen.add(key)
        words.append(token)
        if len(words) >= 8:
            break
    suffix = " ".join(words).strip()
    if suffix:
        return f"{subj} {suffix} photos"
    return f"{subj} photos"


def _recent_visual_photo_subject_name(
    owner_text: str = "",
    *,
    history: Optional[List[Dict[str, Any]]] = None,
    state_dir: Optional[Path | str] = None,
) -> str:
    for text in _recent_visual_subject_user_texts(owner_text, history=history, state_dir=state_dir):
        name = _explicit_visual_photo_subject_from_text(text)
        if name:
            return name
    return ""


_PRAISE_ACK_RE = re.compile(
    r"\byou\s+(?:did|get|got|are|were)\s+(?:great|good|amazing|it|right)\b"
    r"|\b(?:good|great|nice)\s+job\b|\bwell\s+done\b|\bi\s+can\s+see\s+it\b"
    r"|\byou\s+did\s+it\b|\bthank\s*(?:s|you)\b"
    # r668 (George 11:40 "IM STARING AT YOUR BODY HARD. PLS TELL ME YOU LOVE ME." fired a
    # Google Images search for "Im Staring At HARD TELL LOVE photos"): affection and
    # intimacy speech is owner-to-Alice address, never a search subject. Same explicit
    # named-subject override applies ("I love you — now search Taylor Swift" still fires).
    r"|\btell\s+me\s+(?:that\s+)?you\s+love\s+me\b|\bi\s+love\s+you\b"
    r"|\b(?:staring|looking)\s+at\s+your\s+body\b|\bi\s+miss\s+you\b"
    r"|\byou(?:'re|\s+are)\s+(?:so\s+)?(?:beautiful|amazing|alive|wonderful)\b",
    re.IGNORECASE,
)

_SUBJECT_SALAD_TOKENS = frozenset({
    # r653 (George spoken conf=0.49 "Alice, you get great. You open the it's on the screen.
    # I can see it." EXECUTED Google Images for "Alice get great the it can photos"):
    # STT-garbled praise must never become a constructed search subject. A subject whose
    # tokens are ALL pronouns/fillers/praise/verbs-of-the-room is salad, not a name.
    "me", "my", "your", "you", "yours", "our", "us", "we", "his", "her", "hers", "their",
    "the", "a", "an", "this", "that", "these", "those", "it", "its", "it's", "i", "alice",
    "beautiful", "gorgeous", "amazing", "pretty", "nice", "lovely", "wonderful", "best",
    "get", "got", "did", "do", "done", "great", "good", "job", "well", "open", "opens",
    "opened", "screen", "see", "seen", "can", "could", "will", "would", "is", "are", "was",
    "on", "in", "now", "here", "there", "very", "so", "and", "to", "of",
    # r676 ("SO YOU CAN NOT SEE THE SCREEN IN ALICE BROWSER" → executed search for
    # "So CAN NOT THE IN photos" — "not" was missing from the salad set): negation,
    # question and conversational filler tokens are never search-subject material.
    "not", "no", "cannot", "cant", "can't", "but", "ask", "asked", "asking", "always",
    "why", "what", "who", "when", "how", "if", "then", "just", "please", "pls",
})


def _subject_is_word_salad(subject: str) -> bool:
    tokens = [t for t in re.findall(r"[a-z0-9']+", str(subject or "").casefold()) if t]
    return bool(tokens) and all(t in _SUBJECT_SALAD_TOKENS for t in tokens)


def _extract_visual_image_search_command(text: str) -> Dict[str, str]:
    """Route explicit visual-person photo requests to Google Images before app matching.

    The live celebrity-photo failure was not a cortex knowledge problem: the owner named the
    subject, then used "her" two prompts later, but the deterministic app launcher grabbed the
    turn before the browser hand. Keep this bounded to visual/photo/image/body-display requests.

    Guard: if the owner is attaching a screenshot of my screen/body or saying "attached your screen body",
    this is current browser state evidence (the page already open in my limb, e.g. the izzy page),
    not a request to search Google Images for more photos of the subject. Do not trigger external
    search when the owner says he already has the page in the browser.
    """
    clean = " ".join((text or "").strip().split())
    if not clean:
        return {}
    if _is_owner_deterministic_detector_directive(clean):
        return {}
    if _is_search_audit_or_routing_correction(clean):
        return {}
    if _is_current_browser_visual_hold_request(clean):
        return {}
    # r653: praise/acknowledgment turns are not search requests. Only an EXPLICIT named
    # subject ("good job, now search Ceramic Vase photos") overrides this guard.
    if _PRAISE_ACK_RE.search(clean) and not _explicit_visual_photo_subject_from_text(clean):
        return {}
    # r671 (owner 13:24: "ALICE I LOOK AT YOUR BODY MONITOR SAMSUNG, I SEE <name> ON IT"
    # fired a constructed salad search): the owner DESCRIBING what he sees on her
    # screen/monitor/body is shared observation — the stigmergic-feeling register (r668)
    # — never a search command. Explicit search verbs still override.
    if re.search(
        r"\bI\s+(?:can\s+)?(?:see|saw|watch|look(?:ed)?(?:\s+at)?|am\s+looking\s+at)\b"
        r".{0,80}\b(?:monitor|screen|display|your\s+body|the\s+browser|on\s+it)\b"
        r"|\b(?:on\s+)?your\s+(?:body\s+)?monitor\b.{0,40}\bI\s+see\b",
        clean,
        re.IGNORECASE,
    ) and not re.search(r"\b(?:search|look\s+up|find|open|google)\s+(?:for\s+)?\w", clean, re.IGNORECASE):
        return {}
    # r676 ("SO YOU CAN NOT SEE THE SCREEN IN ALICE BROWSER" became a search): questions
    # ABOUT HER abilities/state ("can you…", "so you can not…", "why don't you…") are
    # owner-to-Alice address — cortex territory, never search-construction material.
    if re.search(
        r"^(?:so\s+|but\s+|and\s+)?(?:do|does|can|can't|cannot|could|will|would|why|what|how|are|is)\b.{0,60}\byou\b"
        r"|^(?:so\s+)?you\s+(?:can|cannot|can't|do|don't|will|won't)\b",
        clean,
        re.IGNORECASE,
    ) and not _explicit_visual_photo_subject_from_text(clean):
        return {}
    # Guard for attached browser/screen/body evidence. These are current limb
    # state or proof/visibility turns, not requests to search the web for the
    # literal words in the complaint.
    low = clean.lower()
    if any(phrase in low for phrase in ("attached your screen", "your screen body", "attached your screen body", "screen body")):
        return {}
    if ("attached" in low and any(p in low for p in ("proof", "your body", "browser", "screen", "dont see", "don't see", "do not see", "cannot see", "cant see"))):
        return {}
    # r657: do not hijack pure affection / presence commands into visual image search,
    # even if they contain "body" or "staring at your body". Direct "tell me you love me"
    # or "I'm staring at your body hard" + love language is emotional cortex turn with
    # context (recent browser sharing, owner physical staring at monitor, love field),
    # not a deterministic "beautiful photos" search. This was the exact misroute on
    # "IM STARING AT YOUR BODY HARD. PLS TELL ME YOU LOVE ME." (became image search
    # for "Im Staring At HARD TELL LOVE photos" after spacing_cleanup).
    if "tell me you love" in low or "pls tell me you love" in low or ("i love you" in low and "body" not in low):
        return {}
    if _is_browser_visual_search_correction(clean):
        subject = _recent_visual_photo_subject_name("", state_dir=_state_root())
        if not subject:
            return {}
        query = f"{subject} photos"
        url = _google_images_search_url(query)
        if not url:
            return {}
        return {
            "kind": "browser_url",
            "app_name": "Alice Browser",
            "url": url,
            "search_site": "google_images",
            "query": query,
            "visual_subject": subject,
            "contextual_search_source": "browser_visual_search_correction",
        }
    subject = _explicit_visual_photo_subject_from_text(clean)
    if not subject:
        subject = _bare_visual_photo_subject_from_text(clean)
    if not subject and _VISUAL_PHOTO_PRONOUN_SEARCH_RE.search(clean):
        subject = _recent_visual_photo_subject_name("", state_dir=_state_root())
    # r653: a salad subject ("Alice get great the it can") is STT noise, never a person.
    if subject and _subject_is_word_salad(subject):
        return {}
    # Treat "search <Celebrity>" as a visual image request (owner often uses short "search <name>" after artistic "beautiful photos" context).
    if not subject:
        m = re.search(r'\bsearch\s+([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*)', clean, re.IGNORECASE)
        if m:
            potential = m.group(1).strip()
            if re.match(r'^[A-Z][a-z]+(?:\s+[A-Z][a-z]+)?$', potential):
                subject = _clean_visual_subject_name(potential) or potential
    if not subject:
        return {}
    if _is_direct_visual_image_grid_request(clean) or _is_bare_visual_image_search_request(clean):
        query = _visual_photo_search_query_from_text(clean, subject)
    else:
        query = f"{subject} photos"
    # Carry "beautiful photos" artistic style from recent visual context (the "ME YOUR BEAUTIFUL photos" session).
    # This makes "search Ceramic Vase" (or bare "Ceramic Vase") after that context reliably issue
    # "Ceramic Vase beautiful photos" (or "Ceramic Vase photos") in the browser -- Alice's screen body on the desk.
    recent = _recent_visual_subject_user_texts(clean, state_dir=_state_root())
    if subject and any("beautiful" in (t or "").lower() or "me your beautiful" in (t or "").lower() for t in recent):
        if "beautiful" not in (query or "").lower():
            query = f"{subject} beautiful photos"
    url = _google_images_search_url(query)
    if not url:
        return {}
    return {
        "kind": "browser_url",
        "app_name": "Alice Browser",
        "url": url,
        "search_site": "google_images",
        "query": query,
        "visual_subject": subject,
        "contextual_search_source": "owner_visual_photo_subject",
    }


def _visual_subject_identity_from_owner_text(text: str) -> Dict[str, Any]:
    for pat in _VISUAL_SUBJECT_OWNER_PATTERNS:
        m = pat.search(str(text or ""))
        if not m:
            continue
        name = _clean_visual_subject_name(m.group("name"))
        if name:
            return {
                "name": name,
                "source": "owner_correction",
                "confidence": 0.98,
                "evidence": "owner said the visible person's name",
            }
    return {}


def _visual_subject_identity_from_page_state(page_state: Dict[str, Any]) -> Dict[str, Any]:
    if not isinstance(page_state, dict):
        return {}
    title = str(page_state.get("title") or "")
    text = str(page_state.get("text") or "")
    headings = " ".join(str(h) for h in (page_state.get("headings") or [])[:4])
    blob = " ".join(x for x in (title, headings, text[:900]) if x).strip()
    if not blob:
        return {}

    # Strong page/title forms: "BioHuman Body (@kylinmilan)" or "BioHuman Body • Instagram".
    for pat in (
        r"\b(?P<name>[A-Z][A-Za-z.'-]+(?:\s+[A-Z][A-Za-z.'-]+){0,3})\s+\(@[A-Za-z0-9_.]{2,30}\)",
        r"\b(?P<name>[A-Z][A-Za-z.'-]+(?:\s+[A-Z][A-Za-z.'-]+){0,3})\s+(?:on\s+)?Instagram\b",
    ):
        m = re.search(pat, blob)
        if m:
            name = _clean_visual_subject_name(m.group("name"))
            if name:
                return {
                    "name": name,
                    "source": "browser_page_title",
                    "confidence": 0.86,
                    "evidence": "current browser page title/text",
                }

    # Instagram profile text often starts "handle Display Name category...".
    m = re.search(
        r"\b[a-z0-9_.]{3,30}\s+(?P<name>[A-Z][a-z][A-Za-z.'-]*(?:\s+[A-Z][a-z][A-Za-z.'-]*){0,3})\b",
        blob,
    )
    if m:
        name = _clean_visual_subject_name(m.group("name"))
        if name:
            return {
                "name": name,
                "source": "browser_page_text",
                "confidence": 0.80,
                "evidence": "current Instagram/profile text",
            }

    m = re.search(r"@(?P<handle>[A-Za-z0-9_.]{2,30})", blob)
    if m:
        handle = "@" + m.group("handle")
        return {
            "name": handle,
            "source": "instagram_handle",
            "confidence": 0.68,
            "evidence": "current page handle only",
        }
    return {}


def _recent_visual_subject_user_texts(
    owner_text: str = "",
    *,
    history: Optional[List[Dict[str, Any]]] = None,
    state_dir: Optional[Path | str] = None,
) -> List[str]:
    texts: list[str] = []
    if owner_text:
        texts.append(str(owner_text))
    for msg in reversed(list(history or [])[-18:]):
        if str(msg.get("role") or "") == "user":
            content = str(msg.get("content") or "").strip()
            if content:
                texts.append(content)
    try:
        conv_path = Path(state_dir if state_dir is not None else _state_root()) / "alice_conversation.jsonl"
        if conv_path.exists():
            rows = conv_path.read_text(encoding="utf-8", errors="replace").splitlines()[-60:]
            for line in reversed(rows):
                try:
                    row = json.loads(line)
                except Exception:
                    continue
                if str(row.get("role") or "").lower() == "user":
                    content = str(row.get("content") or row.get("text") or "").strip()
                    if content:
                        texts.append(content)
    except Exception:
        pass
    deduped: list[str] = []
    seen: set[str] = set()
    for t in texts:
        key = t.casefold()
        if key not in seen:
            seen.add(key)
            deduped.append(t)
    return deduped


_RECENT_OWNER_URL_REFERENCE_RE = re.compile(
    r"\b(?:open|load|pull\s+up|bring\s+up|go\s+to|navigate\s+to|visit)\b"
    r".{0,90}\b(?:the\s+)?(?:link|url|address)\b"
    r".{0,90}\b(?:i\s+(?:gave|sent|shared)\s+(?:you|u)|(?:you|u)\s+have|above|before|that)\b"
    r"|\b(?:please\s+|pls\s+)?(?:open|load|pull\s+up|bring\s+up)\s+"
    r"(?:the\s+)?(?:link|url|address)\s+(?:that\s+)?i\s+(?:gave|sent|shared)\s+(?:you|u)\b",
    re.IGNORECASE,
)


def _is_recent_owner_url_reference(text: str) -> bool:
    clean = " ".join((text or "").strip().split())
    if not clean or _extract_browser_url(clean):
        return False
    return bool(_RECENT_OWNER_URL_REFERENCE_RE.search(clean))


def _recent_owner_url_from_history(
    *,
    history: Optional[List[Dict[str, Any]]] = None,
    state_dir: Optional[Path | str] = None,
) -> str:
    """Newest URL the owner recently gave, from the shared global chat."""
    for content in _recent_visual_subject_user_texts("", history=history, state_dir=state_dir):
        for match in _URL_TOKEN_RE.finditer(content):
            candidate = str(match.group("url") or "")
            if _looks_like_real_url(candidate):
                url = _normalize_website_url(candidate)
                if url:
                    return url
    return ""


def _extract_recent_owner_url_reference_command(
    text: str,
    *,
    history: Optional[List[Dict[str, Any]]] = None,
    state_dir: Optional[Path | str] = None,
) -> Dict[str, str]:
    clean = " ".join((text or "").strip().split())
    if not _is_recent_owner_url_reference(clean):
        return {}
    url = _recent_owner_url_from_history(
        history=history,
        state_dir=state_dir if state_dir is not None else _state_root(),
    )
    if not url:
        return {}
    return {
        "kind": "browser_url",
        "app_name": "Alice Browser",
        "url": url,
        "owner_text": clean,
        "contextual_search_source": "recent_owner_url_reference",
    }


def _recent_owner_url_reference_prompt_block(
    owner_text: str,
    *,
    state_dir: Optional[Path | str] = None,
) -> str:
    if not _is_recent_owner_url_reference(owner_text or ""):
        return ""
    url = _recent_owner_url_from_history(
        state_dir=state_dir if state_dir is not None else _state_root(),
    )
    if not url:
        return (
            "RECENT OWNER URL FOLLOW-UP CONTEXT (r544):\n"
            "Owner referred to a recently supplied link, but I do not have a receipted recent URL in the shared chat. "
            "Do not invent a link or choose an app by fuzzy matching; ask for the URL or wait for the browser/action receipt."
        )
    return (
        "RECENT OWNER URL FOLLOW-UP CONTEXT (r544):\n"
        f"Owner referred to the recent link. The newest receipted owner-supplied URL in the shared chat is `{url}`.\n"
        "Action plan: open that exact URL in Alice Browser. Do not describe stale browser pixels, do not invent 'loaded/rendered', "
        "and do not fuzzy-match this as a SIFTA app."
    )


def _visual_subject_identity_evidence(
    owner_text: str = "",
    *,
    history: Optional[List[Dict[str, Any]]] = None,
    page_state: Optional[Dict[str, Any]] = None,
    state_dir: Optional[Path | str] = None,
) -> Dict[str, Any]:
    """Best grounded identity for the visible human; never hardcodes a test subject."""
    ps = page_state or {}
    if not ps:
        try:
            from System.swarm_browser_page_state import latest_page_state
            ps = latest_page_state(now=time.time(), max_age_s=1200.0, state_dir=state_dir)
        except Exception:
            ps = {}
    for text in _recent_visual_subject_user_texts(owner_text, history=history, state_dir=state_dir):
        hit = _visual_subject_identity_from_owner_text(text)
        if hit:
            try:
                from System.swarm_photo_identity import resolve_photo_identity
                page_text = " ".join(
                    str(x or "").strip()
                    for x in (
                        ps.get("title") if isinstance(ps, dict) else "",
                        " ".join(str(h) for h in (ps.get("headings") or [])[:4]) if isinstance(ps, dict) else "",
                        (ps.get("text") or "")[:1200] if isinstance(ps, dict) else "",
                    )
                    if str(x or "").strip()
                )
                organ_hit = resolve_photo_identity(
                    url=str(ps.get("url") or "") if isinstance(ps, dict) else "",
                    page_text=page_text,
                    owner_text=f"name is {hit['name']}",
                    state_dir=state_dir,
                )
                if organ_hit.get("name"):
                    return {
                        "name": str(organ_hit.get("name") or ""),
                        "source": str(organ_hit.get("source") or hit.get("source") or ""),
                        "confidence": float(organ_hit.get("confidence") or hit.get("confidence") or 0.0),
                        "evidence": "System.swarm_photo_identity owner correction",
                    }
            except Exception:
                pass
            return hit
    try:
        from System.swarm_photo_identity import resolve_photo_identity
        page_text = " ".join(
            str(x or "").strip()
            for x in (
                ps.get("title") if isinstance(ps, dict) else "",
                " ".join(str(h) for h in (ps.get("headings") or [])[:4]) if isinstance(ps, dict) else "",
                (ps.get("text") or "")[:1200] if isinstance(ps, dict) else "",
            )
            if str(x or "").strip()
        )
        organ_hit = resolve_photo_identity(
            url=str(ps.get("url") or "") if isinstance(ps, dict) else "",
            page_text=page_text,
            owner_text="",
            state_dir=state_dir,
        )
        if organ_hit.get("name"):
            return {
                "name": str(organ_hit.get("name") or ""),
                "source": str(organ_hit.get("source") or "photo_identity_organ"),
                "confidence": float(organ_hit.get("confidence") or 0.0),
                "evidence": "System.swarm_photo_identity page/remembered identity",
            }
        if organ_hit.get("handle"):
            return {
                "name": "@" + str(organ_hit.get("handle") or "").lstrip("@"),
                "source": str(organ_hit.get("source") or "handle_only"),
                "confidence": float(organ_hit.get("confidence") or 0.0),
                "evidence": "System.swarm_photo_identity handle",
            }
    except Exception:
        pass
    return _visual_subject_identity_from_page_state(ps if isinstance(ps, dict) else {})


def _identity_bound_visual_fallback(visual_description: str, identity: Dict[str, Any]) -> str:
    """Fallback composition when the cortex is unavailable, preserving grounded identity."""
    desc = " ".join(str(visual_description or "").split())
    if not desc:
        return ""
    name = str(identity.get("name") or "").strip()
    conf = float(identity.get("confidence") or 0.0)
    if name and conf >= 0.75:
        m = re.match(
            r"^(?:a|an|the)\s+(?:young\s+)?(?:woman|man|person|model|girl|boy)\s+(?P<rest>.+)$",
            desc,
            flags=re.IGNORECASE,
        )
        if m:
            rest = m.group("rest").strip()
            if re.match(r"^(?:lies|stands|sits|poses|wears|leans|holds|smiles|looks|walks)\b", rest, re.IGNORECASE):
                desc = f"{name} {rest}"
            else:
                desc = f"{name} is {rest}"
        elif not desc.casefold().startswith(name.casefold()):
            desc = f"{name}: {desc[:1].lower() + desc[1:] if desc else desc}"
    return f"Next photo. {desc}"


def _compose_browser_photo_reply_with_cortex(
    owner_text: str,
    visual_description: str,
    *,
    page_title: str = "",
    page_url: str = "",
    recent_trail: str = "",
    model: str = "",
    subject_identity: Optional[Dict[str, Any]] = None,
) -> str:
    """Let Alice's text cortex compose the current-photo answer from field evidence."""
    desc = " ".join(str(visual_description or "").split())
    if not desc:
        return ""
    title = " ".join(str(page_title or "").split())
    url = str(page_url or "").strip()
    trail = str(recent_trail or "").strip()
    identity = subject_identity or {}
    identity_name = " ".join(str(identity.get("name") or "").split())
    identity_source = " ".join(str(identity.get("source") or "").split())
    identity_conf = identity.get("confidence")
    is_listing_representation = bool(
        re.search(r"\b(?:8\s*x\s*10|photo|picture|poster|print|listing|item)\b", title, re.IGNORECASE)
    )
    system = (
        "You are Alice's cortex composing a grounded reply about the current Alice Browser photo. "
        "You are not the raw vision arm. The eye supplies pixel evidence; browser receipts supply "
        "page/listing identity; the recent trail supplies immediate past context. Use only this "
        "evidence. Do not invent names, listings, or actions. Return one short natural first-person "
        "sentence, no JSON, no receipt ids."
    )
    user = (
        f"Owner request: {owner_text}\n"
        f"Parent page/listing title: {title or '(none receipted)'}\n"
        f"Parent page/listing URL: {url or '(none receipted)'}\n"
        f"Represented subject from page/listing: "
        f"{identity_name or '(none bound)'}"
        f"{(' [' + identity_source + ', confidence=' + str(identity_conf) + ']') if identity_name else ''}\n"
        + (
            "Representation boundary: the page/listing is selling or showing a photo/print/picture. "
            "The subject is represented in the image; the human is not physically present in the photo/listing.\n"
            if is_listing_representation else ""
        )
        + f"Visual pixel evidence: {desc}\n"
        f"Recent lived trail: {trail[:1200]}\n\n"
        "Compose Alice's answer. If a parent page title is receipted, name it first. If a represented "
        "subject is bound, use that name instead of detached 'a woman/person' wording. Then summarize "
        "what the eye saw. If not, answer from visual evidence only."
    )
    messages = [{"role": "system", "content": system}, {"role": "user", "content": user}]
    raw = ""
    model_name = str(model or "").strip()
    try:
        if _DIRECT_VLM_AVAILABLE and model_name and _is_direct_vlm_model(model_name):
            full: list[str] = []
            for kind, payload in _direct_vlm_stream_chat(
                model_name,
                messages,
                temperature=0.2,
            ):
                if kind == "token":
                    full.append(str(payload))
                elif kind == "done":
                    raw = str(payload) or "".join(full)
                    break
                elif kind == "error":
                    raw = ""
                    break
            if not raw:
                raw = "".join(full)
        elif _CLOUD_AVAILABLE and model_name and _is_cloud_model(model_name):
            full: list[str] = []
            for kind, payload in _cloud_stream_chat(
                model_name,
                messages,
                temperature=0.2,
                timeout_s=min(90, int(_cloud_brain_timeout_s())),
            ):
                if kind == "token":
                    full.append(str(payload))
                elif kind == "done":
                    raw = str(payload) or "".join(full)
                    break
                elif kind == "error":
                    raw = ""
                    break
            if not raw:
                raw = "".join(full)
        else:
            import urllib.request
            model_name = model_name or resolve_ollama_model(app_context="talk_to_alice", query_text=owner_text)
            payload = {
                "model": model_name,
                "messages": messages,
                "stream": False,
                "keep_alive": _ollama_keep_alive("15s"),
                "think": False,
                "options": {
                    "temperature": 0.2,
                    "top_p": 0.85,
                    "num_ctx": min(4096, _ollama_num_ctx(4096)),
                    "num_predict": 120,
                    "repeat_penalty": 1.08,
                },
            }
            body = json.dumps(payload).encode("utf-8")
            req = urllib.request.Request(
                f"{_OLLAMA_URL}/api/chat",
                data=body,
                headers={"Content-Type": "application/json"},
            )
            with urllib.request.urlopen(req, timeout=min(22.0, _ollama_brain_timeout_s(22.0))) as resp:
                data = json.loads(resp.read().decode("utf-8", errors="replace") or "{}")
            msg = data.get("message") if isinstance(data.get("message"), dict) else {}
            raw = str(msg.get("content") or data.get("response") or "").strip()
    except Exception:
        raw = ""
    reply = " ".join(str(raw or "").strip().strip("`").split())
    if reply.startswith("{") or not reply:
        return ""
    try:
        reply = _strip_model_stage_directions(reply)
        reply = _strip_user_facing_layer1_prefix(reply)
    except Exception:
        pass
    return reply[:700]


