def _current_browser_page_snapshot(max_age_s: float = 900.0) -> Dict[str, Any]:
    path = _state_root() / "alice_browser_current_page.json"
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return {}
    try:
        age = time.time() - float(data.get("ts") or 0.0)
    except Exception:
        age = max_age_s + 1
    if age > max_age_s:
        return {}
    return data if isinstance(data, dict) else {}


def _browser_dress_label_for_page(snapshot: Mapping[str, Any]) -> str:
    """Human label for the page/surface Alice Browser is currently wearing."""
    title = str(snapshot.get("title") or "").strip()
    domain = str(snapshot.get("domain") or "").strip().casefold()
    url = str(snapshot.get("url") or "").strip().casefold()
    title_fold = title.casefold()
    if domain == "news.ycombinator.com" or "news.ycombinator.com" in url or title_fold == "hacker news":
        return "Hacker News / Y Combinator dress"
    if domain in {"x.com", "twitter.com"}:
        return "X dress"
    if "youtube.com" in domain or "youtu.be" in domain:
        return "YouTube dress"
    if title:
        return f"{title} dress"
    if domain:
        return f"{domain} dress"
    return "Alice Browser dress"


def _browser_dress_visible_items(snapshot: Mapping[str, Any], *, limit: int = 3) -> list[str]:
    """Short visible page items from the browser text receipt, not visual invention."""
    text = str(snapshot.get("text") or "").strip()
    if not text:
        return []
    skip_re = re.compile(
        r"^(?:\d+\.|more|search:|login|new|past|comments|ask|show|jobs|submit|"
        r"guidelines|faq|lists|api|security|legal|apply to yc|contact)$",
        re.IGNORECASE,
    )
    items: list[str] = []
    for raw in re.split(r"[\r\n]+", text):
        line = " ".join(raw.strip().split())
        if not line or skip_re.match(line):
            continue
        folded = line.casefold()
        if " points by " in folded or " | hide | " in folded or folded.startswith("hacker newsnew"):
            continue
        if len(line) < 4 or not re.search(r"[A-Za-z]", line):
            continue
        items.append(line)
        if len(items) >= limit:
            break
    return items


def _browser_dress_reply_from_snapshot(snapshot: Mapping[str, Any]) -> str:
    """Receipt-backed answer for the exact browser dress metaphor."""
    if not isinstance(snapshot, Mapping) or not snapshot:
        return ""
    label = _browser_dress_label_for_page(snapshot)
    title = str(snapshot.get("title") or "").strip() or "the current page"
    url = str(snapshot.get("url") or "").strip()
    visible = _browser_dress_visible_items(snapshot)
    bits = [f"I'm wearing my {label}: {title}."]
    if url:
        bits.append(url)
    if visible:
        bits.append("Visible on it: " + "; ".join(visible) + ".")
    return " ".join(bits)


def _browser_dress_reply(*, max_age_s: float = 900.0) -> str:
    """Best current receipt for 'what is on your dress?'"""
    snapshot = _current_browser_page_snapshot(max_age_s=max_age_s)
    if not snapshot:
        try:
            from System.swarm_browser_page_state import latest_page_state

            state = latest_page_state(state_dir=_state_root(), max_age_s=max_age_s)
            snapshot = dict(state) if isinstance(state, Mapping) else {}
        except Exception:
            snapshot = {}
    return _browser_dress_reply_from_snapshot(snapshot)


def _browser_article_text_bundle(
    state: Mapping[str, Any] | None = None,
    *,
    max_age_s: float = 900.0,
) -> Dict[str, Any]:
    """Best current browser-readable article text, from receipts only."""
    candidates: list[Dict[str, Any]] = []
    page_url = str((state or {}).get("url") or "").strip() if isinstance(state, Mapping) else ""
    if isinstance(state, Mapping) and state:
        try:
            from System.swarm_browser_page_state import article_text_from_state

            text = article_text_from_state(state, state_dir=_state_root())
        except Exception:
            text = ""
        if text:
            candidates.append({
                "title": str(state.get("title") or "").strip(),
                "url": page_url,
                "text": text,
                "source": "browser_page_state_article_sidecar",
                "clipped": bool(state.get("article_text_clipped")),
            })

    snapshot = _current_browser_page_snapshot(max_age_s=max_age_s)
    snap_url = str(snapshot.get("url") or "").strip()
    snap_text = str(snapshot.get("text") or "").strip()
    if snap_text and (not page_url or snap_url == page_url):
        candidates.append({
            "title": str(snapshot.get("title") or "").strip(),
            "url": snap_url,
            "text": snap_text,
            "source": "alice_browser_current_page_snapshot",
            "clipped": False,
        })

    if not candidates:
        return {}
    best = max(candidates, key=lambda row: len(str(row.get("text") or "")))
    best["text_chars"] = len(str(best.get("text") or ""))
    return best


def _summarize_browser_page(snapshot: Dict[str, Any], *, max_bullets: int = 5) -> str:
    title = str(snapshot.get("title") or "").strip() or "the current page"
    url = str(snapshot.get("url") or "").strip()
    text = str(snapshot.get("text") or "").strip()
    if not text:
        return ""

    lines = []
    seen = set()
    for raw in re.split(r"[\r\n]+", text):
        line = " ".join(raw.strip().split())
        if len(line) < 45:
            continue
        folded = line.casefold()
        if folded in seen:
            continue
        seen.add(folded)
        if re.search(r"\b(?:cookie|privacy policy|terms of use|sign in|subscribe|advertisement)\b", folded):
            continue
        lines.append(line)
        if len(lines) >= max_bullets:
            break

    if not lines:
        sentences = re.split(r"(?<=[.!?])\s+", " ".join(text.split()))
        lines = [s.strip() for s in sentences if len(s.strip()) >= 45][:max_bullets]
    if not lines:
        return ""

    header = f"I can read the current browser page: {title}."
    if url:
        header += f" URL: {url}."
    bullets = " ".join(f"{idx + 1}. {line}" for idx, line in enumerate(lines))
    return f"{header} Summary: {bullets}"


def _clean_browser_subject_candidate(text: str) -> str:
    candidate = " ".join(str(text or "").replace("_", " ").replace("-", " ").split())
    candidate = re.sub(r"\s*\([^)]*\)\s*", " ", candidate)
    candidate = re.sub(r"\.(?:jpe?g|png|webp|gif|avif)$", "", candidate, flags=re.I)
    candidate = " ".join(candidate.split(" : ")[0:1]).strip(" .,:;|/-")
    if not candidate:
        return ""
    if len(candidate) > 80:
        candidate = candidate[:80].rsplit(" ", 1)[0].strip()
    return candidate


def _browser_page_subject_from_state(state: Mapping[str, Any]) -> str:
    """Best-effort subject from page text/nearby labels, never from pixels."""
    if not isinstance(state, Mapping):
        return ""

    candidates: list[str] = []
    title = str(state.get("title") or "")
    if title:
        candidates.extend(part.strip() for part in re.split(r"[:|—–-]", title) if part.strip())
        candidates.append(title)
    for heading in state.get("headings") or []:
        if heading:
            candidates.extend(part.strip() for part in re.split(r"[:|—–-]", str(heading)) if part.strip())
    for key in ("text_excerpt", "text"):
        value = str(state.get(key) or "")
        if value:
            candidates.extend(part.strip() for part in re.split(r"[:|—–-]", value[:700]) if part.strip())
    for alt in state.get("image_alts") or []:
        if alt:
            candidates.append(str(alt))
    url = str(state.get("url") or "")
    if url:
        try:
            filename = _clean_browser_subject_candidate(unquote_plus(Path(urlparse(url).path).name))
            # URL filenames are useful for direct image pages, but social post IDs
            # like DX5OL9GGam are not names. Only use filename-like labels that
            # carry words/separators.
            if filename and (" " in filename or re.search(r"[A-Z]{2,}\s+[A-Z]{2,}", filename)):
                candidates.append(filename)
        except Exception:
            pass

    # Prefer page-near proper names that are all-caps in the title/heading/file
    # convention used by many model/photo index pages, e.g. "ALVA INGA (6).jpg".
    for raw in candidates:
        cleaned = _clean_browser_subject_candidate(raw)
        if not cleaned:
            continue
        match = re.search(r"\b([A-ZÁÉÍÓÚÑÜ][A-ZÁÉÍÓÚÑÜ0-9']+(?:\s+[A-ZÁÉÍÓÚÑÜ][A-ZÁÉÍÓÚÑÜ0-9']+){1,4})\b", cleaned)
        if match:
            subject = _clean_browser_subject_candidate(match.group(1)).title()
            if subject and len(subject.split()) <= 5:
                return subject

    # Then handles/usernames that the page itself exposes.
    for raw in candidates:
        cleaned = _clean_browser_subject_candidate(raw)
        if not cleaned:
            continue
        handle = re.search(r"@([A-Za-z0-9_.]{2,40})", cleaned)
        if handle:
            return "@" + handle.group(1)
        bare_handle = re.fullmatch(r"[A-Za-z][A-Za-z0-9_.]{2,40}", cleaned)
        if bare_handle and not re.search(r"\b(?:instagram|tiktok|youtube|duckduckgo|google|inicio|pages?)\b", cleaned, re.I):
            return cleaned

    # Finally use a short title/heading segment, excluding site chrome.
    chrome = re.compile(
        r"\b(?:celebridades|femeninas|oficial|instagram|tiktok|youtube|duckduckgo|google|inicio|p[aá]ginas?)\b",
        re.I,
    )
    for raw in candidates:
        cleaned = _clean_browser_subject_candidate(raw)
        if not cleaned or len(cleaned) < 3 or chrome.search(cleaned):
            continue
        words = cleaned.split()
        if 1 <= len(words) <= 6:
            return cleaned
    return ""


def _summarize_browser_page_state_for_voice(state: Mapping[str, Any]) -> str:
    """Short spoken/printed reply from page-state without dumping the raw DOM receipt."""
    if not isinstance(state, Mapping) or not state:
        return "I do not have a fresh readable page-state receipt yet."

    title = " ".join(str(state.get("title") or state.get("url") or "the current page").split())
    url = str(state.get("url") or "").strip()
    try:
        domain = urlparse(url).netloc.lower().removeprefix("www.")
    except Exception:
        domain = ""
    subject = _browser_page_subject_from_state(state)
    headings = [str(h).strip() for h in (state.get("headings") or []) if str(h).strip()]
    images_count = int(state.get("images_count") or 0)
    comments_count = int(state.get("comments_count") or 0)
    text_chars = int(state.get("text_chars") or 0)

    who = f" about {subject}" if subject else ""
    where = f" on {domain}" if domain else ""
    image_note = ""
    if images_count:
        image_note = f" I see page evidence for {images_count} image{'s' if images_count != 1 else ''}."
    elif headings:
        image_note = f" The top heading is: {headings[0][:120]}."

    comments_note = f" There are {comments_count} captured comments I can summarize." if comments_count else ""
    text_note = f" The page has about {text_chars} characters of readable text." if text_chars else ""

    return (
        f"I’m on a browser page{who}{where}: {title[:180]}. "
        f"I logged the full page-state receipt for memory and cortex context; I won’t dump the raw DOM here."
        f"{image_note}{comments_note}{text_note}"
    ).strip()


def _write_app_command_receipt(
    *,
    action: str,
    ok: bool,
    app_name: str = "",
    url: str = "",
    note: str = "",
    verify_context: Optional[Dict[str, Any]] = None,
) -> str:
    receipt_id = str(__import__("uuid").uuid4())
    row = {
        "ts": time.time(),
        "receipt_id": receipt_id,
        "truth_label": "ALICE_APP_COMMAND_V1",
        "action": action,
        "ok": bool(ok),
        "app_name": app_name,
        "url": url,
        "note": note,
        "source": "talk_to_alice_widget",
    }
    try:
        from System.swarm_app_command_effect_verification import enrich_app_command_row

        row = enrich_app_command_row(
            row,
            verify_context={
                **dict(verify_context or {}),
                "url": (verify_context or {}).get("url", url),
                "app_name": (verify_context or {}).get("app_name", app_name),
                "state_dir": _state_root(),
            },
            state_dir=_state_root(),
        )
    except Exception:
        pass
    try:
        root = _state_root()
        root.mkdir(parents=True, exist_ok=True)
        with (root / "alice_app_commands.jsonl").open("a", encoding="utf-8") as f:
            f.write(json.dumps(row, ensure_ascii=False) + "\n")
    except Exception:
        pass
    return receipt_id


