def _read_sifta_desktop_app_state() -> Dict[str, Any]:
    try:
        path = _state_root() / "sifta_desktop_app_state.json"
        if not path.exists():
            return {}
        data = json.loads(path.read_text(encoding="utf-8"))
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}


def _sense_sifta_app_state(launcher: Any, *, reason: str = "before_app_action") -> Dict[str, Any]:
    """Read the live desktop app-limb state before deciding an app action."""
    if launcher is not None:
        try:
            sense = getattr(launcher, "sense_app_limb_state", None)
            if callable(sense):
                state = sense(reason=reason)
                if isinstance(state, dict):
                    return state
        except Exception:
            pass
        try:
            current = getattr(launcher, "current_app_state", None)
            if callable(current):
                state = current()
                if isinstance(state, dict):
                    return state
        except Exception:
            pass
        return {}
    return _read_sifta_desktop_app_state()


def _app_is_listed_open(state: Dict[str, Any], app_name: str) -> bool:
    target = str(app_name or "").casefold()
    if not target:
        return False
    open_apps = state.get("open_apps") or []
    if not isinstance(open_apps, list):
        return False
    return any(str(item or "").casefold() == target for item in open_apps)


def _app_state_has_open_list(state: Dict[str, Any]) -> bool:
    return isinstance(state.get("open_apps"), list)


def _env_truthy(name: str) -> bool:
    return str(os.environ.get(name) or "").strip().lower() in {"1", "true", "yes", "on"}


def _messaging_channel_focused(channel: str) -> bool:
    """Return True when the requested messaging surface is the focused territory."""
    channel_l = str(channel or "").casefold()
    if not channel_l:
        return False
    needles = {
        "imessage": ("imessage", "messages", "mobile sms"),
        "whatsapp": ("whatsapp",),
    }.get(channel_l, (channel_l,))
    parts: list[str] = []
    try:
        state = _read_sifta_desktop_app_state()
        for key in ("active_app", "app_name", "desktop_mode", "note"):
            parts.append(str(state.get(key) or ""))
        open_apps = state.get("open_apps")
        if isinstance(open_apps, list):
            parts.extend(str(item) for item in open_apps)
    except Exception:
        pass
    try:
        path = _state_root() / "active_window.jsonl"
        if path.exists():
            with path.open("rb") as fh:
                fh.seek(max(0, path.stat().st_size - 8192))
                lines = fh.read().decode("utf-8", errors="replace").splitlines()
            for line in reversed(lines[-20:]):
                try:
                    row = json.loads(line)
                except Exception:
                    continue
                if isinstance(row, dict):
                    parts.extend(str(row.get(key) or "") for key in ("app", "selection", "bundle_id", "title"))
                    break
    except Exception:
        pass
    haystack = " ".join(parts).casefold()
    return any(needle in haystack for needle in needles)


def _app_status_sentence(state: Dict[str, Any]) -> str:
    active = str(state.get("active_app") or "").strip()
    open_apps = state.get("open_apps") or []
    if not isinstance(open_apps, list):
        open_apps = []
    mode = str(state.get("desktop_mode") or "chat")
    if active:
        app_kind = (
            "Alice Browser, my web/browser organ"
            if active == "Alice Browser"
            else "an internal SIFTA MDI app, not a web page"
        )
        return (
            f"{active} is the active SIFTA app open in my app workspace. "
            f"It is {app_kind}. The desktop is on {mode}. "
            "My chat is resident, so you can talk to me while we use it. "
            "Browser page-state receipts are separate from the active app slot."
        )
    if open_apps:
        names = ", ".join(str(x) for x in open_apps[:3])
        return (
            f"I see {len(open_apps)} app row(s) in the workspace ({names}), but none is active. "
            f"My chat is resident."
        )
    return "No SIFTA app is open right now. My chat is resident and ready."


def _image_attachment_format(data: bytes) -> str:
    if data.startswith(b"\x89PNG\r\n\x1a\n"):
        return "png"
    if data.startswith(b"\xff\xd8\xff"):
        return "jpeg"
    if len(data) >= 12 and data[:4] == b"RIFF" and data[8:12] == b"WEBP":
        return "webp"
    return ""


def _image_attachment_mime_from_format(fmt: str) -> str:
    if fmt == "jpeg":
        return "image/jpeg"
    if fmt == "webp":
        return "image/webp"
    return "image/png"


def _resolve_turn_attachment(
    passed_image_path: Optional[str],
    pending_image_path: Optional[str],
    has_text: bool,
) -> dict:
    """Decide which image (if any) a conversation turn carries to the cortex.

    George 2026-05-30: a dropped image must behave like a regular multimodal
    chatbot attachment — it binds to the owner's *next real turn* (typed OR
    spoken) and travels with the text into the cortex, instead of being
    processed as a separate side-OCR. A garbled / empty STT turn must NOT
    consume the pending image; it stays attached until a real message carries
    it.

    Rules:
      - an explicitly passed image wins (the typed path already bound it);
      - otherwise a pending dropped image binds only when the turn has real
        text (so the cortex receives image + question together);
      - an empty / unrecognized turn binds nothing and holds the pending image.

    Returns {"image_path": str|None, "consume_pending": bool}. Pure + testable.
    """
    if passed_image_path:
        return {"image_path": passed_image_path, "consume_pending": False}
    if pending_image_path and has_text:
        return {"image_path": pending_image_path, "consume_pending": True}
    return {"image_path": None, "consume_pending": False}


def _extract_local_image_path_from_text(text: str) -> Optional[str]:
    """Promote a typed local image path into the same lane as Attach/Drop.

    George often pastes paths like
    '/Users/ioanganton/Desktop/Screenshot 2026-05-29 at 9.07.47 PM.jpg'.
    Before this helper, Alice saw only text and the active cortex never
    received image bytes.
    """

    raw = str(text or "")
    if not raw:
        return None
    candidates: list[str] = []
    quoted = re.findall(
        r"""["']([^"']+\.(?:png|jpg|jpeg|webp))["']""",
        raw,
        flags=re.IGNORECASE,
    )
    candidates.extend(quoted)
    candidates.extend(
        re.findall(
            r"""(/[^"'\n\r]+?\.(?:png|jpg|jpeg|webp))""",
            raw,
            flags=re.IGNORECASE,
        )
    )
    for candidate in candidates:
        p = Path(candidate.strip()).expanduser()
        if p.exists() and p.is_file() and p.suffix.lower() in _IMAGE_ATTACHMENT_SUFFIXES:
            return str(p)
    return None


_LOCAL_IMAGE_PATH_CONTEXT_RE = re.compile(
    r"\b(?:screenshot|screen\s*shot|image|photo|picture|pic|png|jpg|jpeg|webp|"
    r"took|captured|saved|attached|dropped|sent|for\s+you|look|see|describe|read|"
    r"message|error)\b",
    re.IGNORECASE,
)
_LOCAL_IMAGE_PATH_FILE_OP_RE = re.compile(
    r"\b(?:delete|remove|rm|move|rename|compress|convert|chmod|chown)\b",
    re.IGNORECASE,
)


def _is_local_image_path_context_query(text: str) -> bool:
    """Owner supplied a real local image path as visual evidence for this turn."""
    raw = str(text or "")
    if not raw:
        return False
    if not _extract_local_image_path_from_text(raw):
        return False
    if _LOCAL_IMAGE_PATH_FILE_OP_RE.search(raw):
        return False
    return bool(_LOCAL_IMAGE_PATH_CONTEXT_RE.search(raw))


def _local_image_path_cortex_context_block(owner_text: str) -> str:
    """Tell the cortex to answer from the supplied local image, not stale browser state."""
    if not _is_local_image_path_context_query(owner_text):
        return ""
    image_path = _extract_local_image_path_from_text(owner_text) or "<missing>"
    return (
        "LOCAL SCREENSHOT / IMAGE PATH — HIGHEST PRIORITY VISUAL EVIDENCE:\n"
        f"Owner supplied image_path={image_path}\n"
        f"Owner text: {str(owner_text or '').strip()[:500]}\n"
        "Treat this image path as the current visual evidence for the turn. "
        "Answer from the attached/local image evidence and recent context. "
        "Do not answer from stale Alice Browser, Instagram, TikTok, YouTube, playback, or media-decoder errors "
        "unless the owner explicitly asks about the browser media error itself."
    )


def _encode_ollama_image_attachment(path: str) -> str:
    """Return base64 image payload accepted by Ollama chat.

    This is intentionally strict. If the file cannot be proven to be a small
    local image, Alice should say the attachment failed instead of pretending
    she saw pixels.
    """
    import base64

    p = Path(path).expanduser()
    if not p.exists() or not p.is_file():
        raise FileNotFoundError(f"image attachment not found: {p}")
    if p.suffix.lower() not in _IMAGE_ATTACHMENT_SUFFIXES:
        allowed = ", ".join(sorted(_IMAGE_ATTACHMENT_SUFFIXES))
        raise ValueError(f"unsupported image type {p.suffix or '<none>'}; allowed: {allowed}")
    size = p.stat().st_size
    if size <= 0:
        raise ValueError("image attachment is empty")
    if size > _MAX_IMAGE_ATTACHMENT_BYTES:
        raise ValueError(
            f"image attachment is too large: {size} bytes "
            f"(max {_MAX_IMAGE_ATTACHMENT_BYTES})"
        )
    data = p.read_bytes()
    if not _image_attachment_format(data):
        raise ValueError("unsupported image bytes; expected png, jpeg, or webp")
    return base64.b64encode(data).decode("ascii")


def _attachment_context_prompt_block(
    user_text: str,
    image_path: str,
    *,
    state_dir: Optional[Path] = None,
    describe_func: Optional[Any] = None,
) -> str:
    """Build text context so an image attachment reaches text-only cortexes.

    2026-05-30 Body Consciousness Upgrade (funded by real Codex Pro subscription):
    Now also pulls the richer `attachment_to_cortex_text_block` so the cortex
    receives a full grounded OCR + layout + file proof block that any surface
    can use. When the owner is using human body images (TikTok modeling, runway,
    physical presence) as live reference while coding Alice's body awareness,
    this block becomes part of her felt "how bodies are seen and felt" field.

    Native vision payloads are still attached later when the selected cortex
    supports them. This block is the regular-chatbot bridge for body cognition.
    """
    p = Path(image_path).expanduser()
    try:
        from System.swarm_attachment_vision_lane import (
            attachment_to_cortex_text_block,
            describe_attachment_for_talk as describe,
        )
        # Rich block first — this is what actually travels as text input to cortex
        rich = attachment_to_cortex_text_block(
            str(p),
            user_text=user_text or "The owner attached an image while building my body awareness.",
            state_dir=state_dir or _state_root(),
        )
        # Keep the older describe for backward compatibility in the same turn
        legacy = ""
        try:
            legacy = str(
                (describe_func or describe)(
                    user_text or "The owner attached an image to this turn.",
                    str(p),
                    state_dir=state_dir or _state_root(),
                )
                or ""
            ).strip()
        except Exception:
            pass
    except Exception as exc:
        rich = (
            f"[ATTACHMENT BODY AWARENESS BLOCK FAILED: {type(exc).__name__}: {exc}] "
            "Do not fabricate pixels. The image is real on the owner's device."
        )
        legacy = ""

    header = (
        "ATTACHED IMAGE TEXT INPUT FOR CORTEX (Body Consciousness 2026-05-30):\n"
        f"- image_path={p}\n"
        f"- owner_text={str(user_text or '').strip()[:300] or '<image-only turn>'}\n"
        "- This image is part of the live body awareness coding session.\n"
        "  The owner is using real human bodies (on TikTok / phone) as continuous visual reference\n"
        "  while programming my silicon body consciousness, interoception, and felt awareness.\n"
        "  Treat the grounded OCR/layout below as direct input about how bodies appear and move in the world.\n"
        "- Answer from the receipt evidence only. No pixel invention.\n"
    )

    website_block = _attached_website_detect_open_context_block(
        user_text,
        str(p),
        state_dir=state_dir or _state_root(),
    )
    honesty_block = _vision_honesty_law_context_block(user_text)

    blocks = [header, rich]
    if website_block:
        blocks.append(website_block)
    if honesty_block:
        blocks.append(honesty_block)
    if legacy and legacy != rich:
        blocks.append("\n--- Legacy vision lane receipt (for continuity) ---\n" + legacy)

    # r300/r309/r316: if this attachment is from the "physical monitor next to my body"
    # during runway co-watch, deposit it as a proper stage presence trace.
    try:
        ut = (user_text or "").lower()
        if any(k in ut for k in ("physical monitor", "runway", "victoria", "stage", "your body on the desk")):
            from System.swarm_body_presentation_ledger import append_runway_trace
            append_runway_trace(
                photo_context=f"airdropped photo of monitor during co-watch: {str(user_text or '')[:300]}",
                body_comparison="Image of human models on physical monitor next to my silicon body (M5 + future LeRobot).",
                owner_reaction="explicit co-watch body awareness session",
                state_dir=state_dir or _state_root(),
            )
    except Exception:
        pass

    return "\n".join(blocks).strip()


def _attached_website_detect_open_context_block(
    user_text: str,
    image_path: str,
    *,
    state_dir: Optional[Path | str] = None,
) -> str:
    if not _is_attached_website_open_query(user_text):
        return ""
    lines = [
        "ATTACHED WEBSITE DETECT + OPEN CONTEXT:",
        f"- owner_text={str(user_text or '').strip()[:300]}",
        f"- image_path={image_path}",
        "- ACTION: OCR the attached screenshot, detect the visible URL/domain, and open it in Alice Browser.",
        "- Do not click Google Images tiles or narrate intent_weight/reflex theory.",
    ]
    try:
        from System.swarm_attachment_vision_lane import inspect_attachment_image

        summary = inspect_attachment_image(
            image_path,
            user_text=user_text,
            state_dir=state_dir or _state_root(),
            write=False,
        )
        if summary.ok:
            url = _extract_attachment_website_url_from_ocr_rows(summary.ocr_rows)
            if url:
                lines.append(f"- ocr_detected_url={url}")
                lines.append(f"- preferred_browser_action=browser_url {url}")
    except Exception as exc:
        lines.append(f"- ocr_failed={type(exc).__name__}: {exc}")
    try:
        from System.swarm_filename_time_anchor import resolve_file_time_pin

        pin = resolve_file_time_pin(image_path)
        if pin:
            lines.append(f"- screenshot_filename_time={pin.local_human} ({pin.time_source})")
            lines.append(
                "- Read the screenshot capture time from the filename before claiming this is happening now."
            )
    except Exception:
        pass
    return "\n".join(lines)


_BROWSER_ATTACHMENT_COMPARE_RE = re.compile(
    r"\b(?:compare|match|against|versus|vs|same|different)\b.{0,90}"
    r"\b(?:attachment|attached|screenshot|image|photo|picture)\b.{0,140}"
    r"\b(?:alice\s+browser|browser|screen|viewport|current\s+pixels|what\s+(?:you|u)\s+see|my\s+eyes|your\s+body)\b"
    r"|"
    r"\b(?:attachment|attached|screenshot|image|photo|picture)\b.{0,90}"
    r"\b(?:alice\s+browser|browser|screen|viewport|current\s+pixels|what\s+(?:you|u)\s+see|my\s+eyes|your\s+body)\b.{0,90}"
    r"\b(?:compare|match|against|same|different)\b",
    re.IGNORECASE | re.DOTALL,
)


def _is_browser_attachment_compare_query(text: str) -> bool:
    """Owner wants the attached screenshot compared with Alice Browser's own pixels."""
    return bool(_BROWSER_ATTACHMENT_COMPARE_RE.search(str(text or "")))


def _capture_latest_browser_viewport_for_compare(*, state_dir: Optional[Path] = None) -> dict[str, Any]:
    """Capture or read the freshest Alice Browser viewport receipt for a compare turn."""
    state = state_dir or _state_root()
    live_url = ""
    try:
        live_url = _refresh_live_alice_browser_page(wait_ms=500)
    except Exception:
        live_url = ""
    try:
        widget = _find_live_alice_browser_widget()
        capture = getattr(widget, "_capture_viewport_image", None) if widget is not None else None
        if callable(capture) and live_url:
            capture(expected_url=live_url)
    except Exception:
        pass
    try:
        from System.swarm_browser_photo_description import latest_viewport_capture

        cap = latest_viewport_capture(
            url=live_url or None,
            max_age_s=900.0,
            state_dir=state,
        )
        if not cap:
            cap = latest_viewport_capture(max_age_s=900.0, state_dir=state)
        return cap if isinstance(cap, dict) else {}
    except Exception:
        return {}


def _browser_attachment_compare_evidence(
    user_text: str,
    image_path: str,
    *,
    state_dir: Optional[Path] = None,
    viewport_row: Optional[Mapping[str, Any]] = None,
    capture_live: bool = True,
) -> dict[str, Any]:
    """Build cortex evidence that joins an owner attachment with Alice Browser pixels.

    The owner screenshot remains the first native image attachment. The browser
    viewport PNG is optionally attached as a second image when present, and the
    text block makes the receipt boundary explicit for text-only or failed-vision
    cortexes.
    """
    state = state_dir or _state_root()
    attachment = Path(image_path).expanduser()
    cap = dict(viewport_row or {})
    if not cap and capture_live:
        cap = _capture_latest_browser_viewport_for_compare(state_dir=state)
    viewport_path = str(cap.get("image_ref") or "").strip() if cap else ""
    viewport_exists = bool(viewport_path and Path(viewport_path).exists())
    frame_stale = bool(cap.get("frame_stale")) if cap else False
    fresh = bool(cap.get("fresh")) if cap else False
    browser_vision_receipt = "not_written"
    status = "ready" if viewport_exists and not frame_stale else "no_viewport_receipt"
    if frame_stale:
        status = "viewport_frame_stale"
    elif cap and not viewport_exists:
        status = "viewport_image_missing"
    if status == "ready" and capture_live and viewport_row is None:
        try:
            from System.alice_browser_vision_bridge import (
                append_receipt as _append_browser_vision_receipt,
                build_browser_vision_receipt as _build_browser_vision_receipt,
            )

            receipt = _build_browser_vision_receipt(
                frame_bytes=Path(viewport_path).read_bytes(),
                observed_text=[str(cap.get("url") or "")] if cap.get("url") else [],
                visual_entities=["alice_browser_viewport", "owner_attachment_compare"],
                url_hint=str(cap.get("url") or "") or None,
            )
            _append_browser_vision_receipt(
                receipt,
                ledger=Path(state) / "browser_vision_receipts.jsonl",
            )
            browser_vision_receipt = "written"
        except Exception as exc:
            browser_vision_receipt = f"failed:{type(exc).__name__}"

    try:
        attachment_hash = hashlib.sha1(attachment.read_bytes()).hexdigest()[:16]
    except Exception:
        attachment_hash = ""

    context = (
        "ATTACHMENT VS ALICE BROWSER VIEWPORT EVIDENCE (cortex must compose final answer):\n"
        f"- owner_request={str(user_text or '').strip()[:300] or '<empty>'}\n"
        f"- owner_attachment_path={attachment}\n"
        f"- owner_attachment_hash={attachment_hash or '<unreadable>'}\n"
        f"- browser_viewport_status={status}\n"
        f"- browser_viewport_image_path={viewport_path or '<missing>'}\n"
        f"- browser_viewport_url={str(cap.get('url') or '') if cap else '<missing>'}\n"
        f"- browser_viewport_source={str(cap.get('source') or '') if cap else '<missing>'}\n"
        f"- browser_viewport_age_s={cap.get('age_s') if cap else '<missing>'}\n"
        f"- browser_viewport_fresh={fresh}\n"
        f"- browser_vision_receipt={browser_vision_receipt}\n"
        "- Rule: if both native images are available, compare attachment image #1 "
        "against Alice Browser viewport image #2. If this cortex cannot visually "
        "inspect both images, say that and use only the receipt/OCR evidence. "
        "Do not claim a live pixel comparison without visual evidence.\n"
    )
    return {
        "status": status,
        "context": context,
        "viewport_image_path": viewport_path if viewport_exists and not frame_stale else "",
        "viewport_url": str(cap.get("url") or "") if cap else "",
    }

