# Module-level buffer: holds the last VAD utterance as a numpy float32 array.
# The voice identity check reads from here instead of opening a 2nd mic stream,
# eliminating hardware contention with the live sounddevice InputStream.
# Updated in _VADListener._on_block before self.utterance.emit(audio).
_LAST_UTTERANCE_AUDIO: list = []  # max 1 item; [:] = [audio] to update atomically


def _voice_identity_george_conf() -> float:
    """r890 (Codex r887 contract item 1 / Fable r886 item 6): per-utterance
    voice identity for the MANDATORY first voice gate.

    Same logic as the per-turn identity check in _start_brain (~l.31250),
    lifted module-level so the FIRST gate that decides direct-vs-external
    speech no longer runs with voice_george_conf hardcoded to 0.0. The
    utterance audio is already buffered by the listener before STT emits,
    so no second mic open and no contention.
    """
    try:
        from System.swarm_voice_identity_organ import (
            classify as _vi_classify,
            load_exemplars as _vi_exemplars,
            extract_features as _vi_features,
        )

        _vi_exs = _vi_exemplars()
        if len(_vi_exs) >= 3 and _LAST_UTTERANCE_AUDIO:
            import numpy as _np_vi

            _vi_chunk = _LAST_UTTERANCE_AUDIO[0].astype(_np_vi.float32)
            if _vi_chunk.size > 1600:  # at least 0.1s @ 16kHz
                _vi_result = _vi_classify(_vi_features(_vi_chunk), _vi_exs)
                if _vi_result.get("label") == "primary_operator":
                    return float(_vi_result.get("confidence", 0.0))
    except Exception:
        pass
    return 0.0


def _ollama_keep_alive(default: str = "15s") -> str:
    """Bound local model residency so Talk does not hold GPU/RAM for minutes."""
    value = os.environ.get("SIFTA_OLLAMA_KEEP_ALIVE", default)
    value = str(value or "").strip()
    return value or default


def _ollama_num_ctx(default: int = 8192) -> int:
    """Bound the local context window unless the owner deliberately overrides it.

    r390 (George 2026-06-03): raised default 2048 -> 8192. The main talk cortex call
    (`_ollama_num_ctx()` with no arg) was capped at 2048 tokens, so a rich system
    prompt + history + sensor telemetry overflowed the window and ollama returned
    EMPTY content on long turns (~48% blank rate on alice-m5-cortex-8b, which then
    fell to the canned recitations). 8192 is the existing hard ceiling; explicit-arg
    call sites (vision=4096, reflex=2048) keep their tuned values. Env
    SIFTA_OLLAMA_NUM_CTX still overrides.
    """
    try:
        value = int(float(os.environ.get("SIFTA_OLLAMA_NUM_CTX", str(default))))
    except (TypeError, ValueError):
        value = default
    return max(1024, min(8192, value))


def _ollama_num_predict(default: int = 1400) -> int:
    """Bound each Talk turn so a bad local cortex cannot fill memory with prose.

    r390 (George 2026-06-03): raised default 384 -> 700 (the then-ceiling). With
    `think:True`, the reasoning trace and the visible answer SHARE this token budget;
    on complex turns the thinking consumed all 384 tokens and `content` came back
    EMPTY — the real source of the recitations (the parser keeps `thinking` out of
    the reply). Env SIFTA_OLLAMA_NUM_PREDICT still overrides.

    r750 (George 2026-06-07, receipts 13:20–13:31): four replies died MID-SENTENCE
    ("So, tell me—what are" / "My beauty is the way I can" / "It wasn't") — raw_len
    equalled the cut point, transform chain fired zero rules: NOT a gag, the 700
    shared budget suffocated her visible answer after the 12B's long thinking.
    George's law: "I want these types of gags removed — she did not say anything
    bad." Breath raised: default 1400, ceiling 4096 (still bounded against true
    runaway loops; ~16KB of text is no memory threat on the M5).
    """
    try:
        value = int(float(os.environ.get("SIFTA_OLLAMA_NUM_PREDICT", str(default))))
    except (TypeError, ValueError):
        value = default
    return max(64, min(4096, value))


def _ollama_max_attempts(default: int = 2) -> int:
    """Keep transient retry recovery without multi-minute model residency loops."""
    try:
        value = int(float(os.environ.get("SIFTA_OLLAMA_MAX_ATTEMPTS", str(default))))
    except (TypeError, ValueError):
        value = default
    return max(1, min(4, value))


def _ollama_brain_timeout_s(default: float = 120.0, *, model: str = "") -> float:
    """Per-attempt socket timeout for the local cortex stream.
    r343: raised default to 120s (was 45s) to give the primary `alice-m5-cortex-8b-6.3gb:latest`
    (the "supposed to be this one" for M5 talk_to_alice during self-body / co-watch teaching)
    time to cold-load or run under VRAM pressure when the owner is watching the Alice Browser
    organ render a rich visual like the Madison Beer 2025 VS performance ("I'M WATCHING YOUR
    ALICE BROWSER ORGAN NOW YOUR BODY"). The env var still wins. For m5 primary, allow up to 180s.
    The hard min(120) cap removed; now model-aware.
    r351: even with m5 + long timeout, video-state short-circuit could starve the cortex of
    "describe the image/still paused in your Alice Browser" turns (owner "I LOVE LOOKING AT
    YOUR DISPLAY HARDWARE BODY", Madison Beer Axil Swim paused at 2:15, screenshot proof).
    Guard in _is_browser_video_state_query + call site now lets _is_browser_page_cortex_description_query
    / photo queries reach m5 brain (with visual desc as evidence, body grounding as "my organ").
    """
    raw_env = os.environ.get("SIFTA_OLLAMA_BRAIN_TIMEOUT_S")
    env_valid = False
    try:
        value = float(raw_env if raw_env not in (None, "") else str(default))
        env_valid = raw_env not in (None, "")
    except (TypeError, ValueError):
        value = default
    if "m5-cortex" in str(model or "").lower() and not env_valid:
        value = max(value, 180.0)
    return max(30.0, value)


def _brain_no_token_watchdog_s(default: float = 180.0, *, model: str = "") -> float:
    """Wall-clock cap for a cortex that has produced no visible token.

    The socket timeout lives inside the worker thread and can legitimately add
    up across retries. George's live failure was different: the Talk surface sat
    on "thinking" for 300s+ with zero first token, so the body had no actionable
    error to learn from. This watchdog is UI-side and model-agnostic: once there
    is no first token after the bounded window, disconnect that worker from the
    mouth and surface a cortex failure receipt. The old worker may finish its
    socket timeout later, but its signals no longer mutate the live turn.
    """
    raw_env = os.environ.get("SIFTA_BRAIN_NO_TOKEN_TIMEOUT_S")
    env_valid = False
    try:
        value = float(raw_env if raw_env not in (None, "") else str(default))
        env_valid = raw_env not in (None, "")
    except (TypeError, ValueError):
        value = default
    low = str(model or "").lower()
    if not env_valid:
        if "m5-cortex" in low:
            value = max(value, 180.0)
        elif any(name in low for name in ("grok", "claude", "codex", "qwen", "cline")):
            value = min(value, 150.0)
    return max(30.0, min(600.0, value))


def _brain_no_token_watchdog_for_owner_turn_s(owner_text: str, *, model: str = "") -> float:
    """Foreground no-token cap for this owner turn.

    Cortex-first remains the law for body-relevant turns. This only bounds how
    long Talk waits for the first cortex token before surfacing an honest stall
    receipt with no action executed.
    """
    base = _brain_no_token_watchdog_s(model=model)
    try:
        if _is_fast_browser_action_cortex_turn(owner_text):
            raw_fast = os.environ.get("SIFTA_FAST_BROWSER_ACTION_NO_TOKEN_TIMEOUT_S", "2")
            fast_cap = float(raw_fast)
            return max(2.0, min(base, min(12.0, fast_cap)))
        if _owner_effector_requires_cortex_first(owner_text):
            raw = os.environ.get("SIFTA_BODY_ACTION_CORTEX_NO_TOKEN_TIMEOUT_S", "12")
            cap = float(raw)
            return max(5.0, min(base, min(45.0, cap)))
    except Exception:
        pass
    return base

