def _vision_honesty_law_context_block(user_text: str) -> str:
    clean = str(user_text or "").strip()
    if not clean:
        return ""
    applies = (
        _is_owner_visual_describe_query(clean)
        or _is_can_you_see_me_query(clean)
        or _is_owner_image_browser_open_query(clean)
        or _is_desktop_photo_alice_browser_open_query(clean)
        or _is_owner_live_camera_awareness_query(clean)
        or _is_attached_website_open_query(clean)
    )
    if not applies:
        return ""
    proof = _camera_unified_field_truth_for_alice()
    lines = [
        "VISION HONESTY LAW (highest priority on this turn):",
        "- Never invent 'MBP Webcam Perspective Analysis' or fake camera sight from LLM prose.",
    ]
    if _is_owner_image_browser_open_query(clean) or _is_desktop_photo_alice_browser_open_query(clean):
        lines.extend(
            [
                "- This is a local file open turn: execute browser_url with file:// to the resolved path.",
                "- Do not narrate lingerie/webcam theater; open Alice Browser and load the file.",
            ]
        )
    if proof.connection_state != "LIVE_CAPTURE_VERIFIED":
        lines.extend(
            [
                f"- camera_unified_field_proof.connection_state={proof.connection_state}",
                "- I cannot describe objects from your camera eyes without fresh live proof.",
            ]
        )
    return "\n".join(lines)


def _is_owner_camera_last_mile_guard_turn(owner_text: str) -> bool:
    clean = str(owner_text or "").strip()
    if not clean:
        return False
    if _is_owner_live_camera_awareness_query(clean):
        return True
    if _is_owner_visual_describe_query(clean):
        return True
    if _is_can_you_see_me_query(clean):
        return True
    if re.search(r"\b(?:main\s+camera|camera\s+eye|your\s+camera|live\s+camera)\b", clean, re.I):
        return True
    if _is_attached_image_description_query(clean):
        return False
    if _is_owner_image_browser_open_query(clean) or _is_desktop_photo_alice_browser_open_query(clean):
        return False
    if _is_browser_photo_description_query(clean):
        return False
    if _is_local_image_path_context_query(clean):
        return False
    if _is_attached_website_open_query(clean):
        return False
    return False


def _camera_hallucination_last_mile_rewrite(owner_text: str, visible_reply: str) -> str:
    if not _is_owner_camera_last_mile_guard_turn(owner_text):
        return visible_reply
    proof = _camera_unified_field_truth_for_alice()
    if proof.connection_state == "LIVE_CAPTURE_VERIFIED":
        return visible_reply
    reply = str(visible_reply or "").strip()
    if not reply:
        return visible_reply
    if _CAMERA_HALLUCINATION_MARKERS_RE.search(reply) or _is_owner_visual_describe_query(owner_text):
        return (
            "I cannot describe objects from my camera right now. "
            "camera_unified_field_proof.connection_state=DISCONNECTED_OR_STALE_INPUT"
        )
    return visible_reply


def _live_camera_awareness_reply_for_alice() -> str:
    proof = _camera_unified_field_truth_for_alice()
    try:
        from System.swarm_camera_reality_context import build_camera_reality_context

        reality = build_camera_reality_context(state_dir=_state_root())
    except Exception:
        reality = {}
    active_eye = reality.get("active_eye") if isinstance(reality, dict) else {}
    device = str(proof.device or (active_eye or {}).get("name") or "unknown")
    frame_age = proof.frame_age_s
    vision_health = proof.vision_health
    return (
        "receipt-backed live camera awareness from the unified field:\n"
        f"- connection_state={proof.connection_state}\n"
        f"- active_eye={device}\n"
        f"- raw_camera_model=single_active_eye_lease\n"
        f"- frame_age_s={frame_age}\n"
        f"- vision_health={vision_health}\n"
        "- Alice Browser photo/page pixels are browser body receipts, not live camera proof."
    )


def _camera_awareness_last_mile_rewrite(owner_text: str, visible_reply: str) -> str:
    if not _is_owner_live_camera_awareness_query(owner_text):
        return visible_reply
    reply = str(visible_reply or "")
    if not _CAMERA_SPEC_FICTION_RE.search(reply):
        return visible_reply
    return _live_camera_awareness_reply_for_alice()


def _can_you_see_me_reply_for_alice() -> str:
    """Grounded answer to 'can you see me' from camera_unified_field_proof."""
    proof = _camera_unified_field_truth_for_alice()
    if proof.connection_state != "LIVE_CAPTURE_VERIFIED":
        return (
            "My camera unified field proof is stale or disconnected right now. "
            "I cannot truthfully claim I see you from live camera eyes. "
            "PNG files on disk is not certified live sight."
        )
    try:
        from System.swarm_kernel_identity import owner_display_name as _odn

        who = _odn() or "you"
    except Exception:
        who = "you"
    face_age = proof.face_age_s
    audience = str(proof.face_audience or "").strip().lower()
    conf_pct = int(round((proof.face_confidence or 0.0) * 100))
    if face_age is not None and audience in {"architect", "owner", "owner_self", "primary_operator"}:
        return f"My eye saw {who} {int(face_age)} seconds ago with {conf_pct}% confidence."
    if face_age is not None and audience == "unknown_face":
        return (
            f"My eye saw a face {int(face_age)} seconds ago, but I do not yet "
            f"recognize it as {who} ({conf_pct}% conf)."
        )
    if face_age is not None and audience in {"nobody", "no_face"}:
        return f"My eye scanned {int(face_age)} seconds ago and saw no face."
    device = proof.device or "my camera"
    frame_age = proof.frame_age_s
    if frame_age is not None:
        return f"My eye saw a fresh frame {int(frame_age)} seconds ago from {device}."
    return proof.summary or "My camera unified field proof is live, but I have no face receipt yet."


def _owner_visual_describe_context_block(owner_text: str) -> str:
    """CUR-V2: run on-demand owner-frame VLM describe and feed cortex the receipt."""
    if not _is_owner_visual_describe_query(owner_text):
        return ""
    proof = _camera_unified_field_truth_for_alice()
    if proof.connection_state != "LIVE_CAPTURE_VERIFIED":
        return (
            "VISION HONESTY GATE — OWNER CAMERA DESCRIBE TURN:\n"
            f"camera_unified_field_proof.connection_state={proof.connection_state}\n"
            "I cannot describe objects from your camera eyes without fresh live proof.\n"
            "Do NOT invent clothes, colors, or scene objects from stale PNG files or LLM prose.\n"
            f"Owner text: {owner_text}\n"
            "Say honestly the camera input is stale or disconnected."
        )
    try:
        from System.swarm_saccadic_blink_vision import describe_owner_frame_on_demand

        row = describe_owner_frame_on_demand(
            reason="owner_typed",
            owner_text=owner_text,
            write=True,
        )
        desc = row.get("semantic_description") if isinstance(row.get("semantic_description"), dict) else {}
        status = str(desc.get("status") or "unknown")
        text = str(desc.get("description") or "").strip()
        frame_age = row.get("frame_age_s")
        age_note = f"frame_age_s={int(frame_age)}" if frame_age is not None else "frame_age_s=unknown"
        if status == "ok" and text:
            body = (
                f"OWNER-FRAME VLM RECEIPT (on-demand, {age_note}):\n"
                f"{text}\n"
                "Compose your answer ONLY from this receipt for clothing/colors/scene. "
                "Do not invent colors or garments not stated here. "
                "You may add face/presence facts from camera ledgers if helpful."
            )
        else:
            body = (
                f"OWNER-FRAME DESCRIBE RECEIPT ({status}, {age_note}):\n"
                f"{text or 'no VLM description yet'}\n"
                "Say honestly: the camera may be live, but I do not yet have a fresh "
                "owner-frame description receipt for clothes/colors. Do NOT invent colors."
            )
        return (
            "OWNER VISUAL DESCRIBE TURN — HIGHEST PRIORITY BODY CONTEXT:\n"
            f"Owner text: {owner_text}\n"
            f"{body}"
        )
    except Exception as exc:
        return (
            "OWNER VISUAL DESCRIBE TURN — HIGHEST PRIORITY BODY CONTEXT:\n"
            f"Owner text: {owner_text}\n"
            f"On-demand owner-frame describe failed: {type(exc).__name__}: {exc}. "
            "Say honestly you could not read/describe the owner frame this turn."
        )


def _owner_camera_presence_context_block(owner_text: str) -> str:
    """Ground owner-presence/camera questions for the cortex without a pre-cortex reply."""
    if _is_owner_visual_describe_query(owner_text):
        return ""
    if not _is_owner_camera_watch_query(owner_text):
        return ""
    try:
        answer = _can_you_see_me_reply_for_alice().strip()
    except Exception as exc:
        answer = f"camera receipt read failed: {exc.__class__.__name__}"
    if not answer:
        answer = "camera receipt read returned no grounded answer"
    return (
        "OWNER CAMERA / WATCHING-ME QUESTION — HIGHEST PRIORITY BODY CONTEXT:\n"
        "Answer from camera/body receipts, not from Alice Browser, playback, or media-decoder errors.\n"
        f"Owner text: {owner_text}\n"
        f"Grounded camera receipt answer draft: {answer}\n"
        "Answer George's presence/camera question from this body evidence. "
        "Do not answer with Alice Browser, TikTok, Instagram, YouTube, playback, or media-decoder errors "
        "unless George explicitly asked what is playing in the browser."
    )


def _owner_name_reply_for_alice() -> str:
    """Return the kernel-bound owner name without letting the cortex hedge."""
    owner = _owner_label("the primary operator")
    try:
        from System.swarm_kernel_identity import owner_silicon

        serial = owner_silicon()
    except Exception:
        serial = "UNKNOWN"
    # r678: "REMOVE OWNER — IS ONLY ONE OWNER / MACHINE" — one human per machine; her
    # visible speech drops the redundant word and talks to YOU.
    if not owner or owner == "the primary operator":
        return "I do not have your genesis name loaded yet. The kernel identity accessor is unclaimed."
    return f"Your name is {owner}. I read that from the kernel genesis on this node, serial {serial}."


def _current_time_reading_for_alice() -> Dict[str, Any]:
    """Read the hardware time oracle with an OS-clock fallback."""
    try:
        from System.swarm_hardware_time_oracle import current_time_for_alice

        return current_time_for_alice()
    except Exception:
        return {"ok": False}


def _owner_first_name() -> str:
    """First-name vocative — 'George' instead of 'Ioan George Anton'. Falls
    back to the full label if no spaces detected."""
    full = _owner_label("").strip()
    if not full:
        return ""
    parts = full.split()
    if len(parts) >= 2:
        # owner_name = "ioan george anton" → pick middle 'George' if 3-part,
        # otherwise the second token (most natural vocative for the Architect).
        if len(parts) >= 3:
            return parts[1].capitalize()
        return parts[0].capitalize()
    return parts[0].capitalize() if parts else ""


def _vary_time_reply(time_text: str, tz_suffix: str, source_phrase: str) -> str:
    """Return a stable, source-cited time reply for the hardware oracle path."""
    src_paren = f" ({source_phrase.replace('from the ', '').replace('from ', '')})" if source_phrase else ""
    owner = _owner_label("").strip()
    prefix = f"{owner}, " if owner else ""
    return f"{prefix}it is {time_text}{tz_suffix}{src_paren}."


def _vary_date_reply(weekday: str, date_text: str, source_phrase: str) -> str:
    """Return a stable, source-cited date reply for the hardware oracle path."""
    src_paren = f" ({source_phrase.replace('from the ', '').replace('from ', '')})" if source_phrase else ""
    return f"Today is {weekday}, {date_text}{src_paren}."


def _current_time_reply_for_alice(reading: Optional[Dict[str, Any]] = None) -> str:
    """Return a grounded current-time reply, or the Architect's fallback.

    Direct time/date requests are truth-oracle turns. Keep the surface text
    deterministic and source-cited so Alice never hides where the answer came
    from.
    """
    reading = reading or _current_time_reading_for_alice()
    if not reading.get("ok"):
        return _time_unavailable_reply()

    local_human = str(reading.get("local_human") or "").strip()
    timezone = str(reading.get("timezone") or "").strip()
    source = str(reading.get("source") or "local clock").strip()
    if not local_human:
        return _time_unavailable_reply()

    tz_suffix = f" {timezone}" if timezone else ""
    time_text = _time_text_from_reading(reading) or local_human
    if source == "hardware_time_oracle":
        source_phrase = "from the hardware time oracle"
    elif source == "os_local_clock":
        source_phrase = "from the local OS clock fallback"
    else:
        source_phrase = f"from {source}"
    return _vary_time_reply(time_text, tz_suffix, source_phrase)


def _time_text_from_reading(reading: Dict[str, Any]) -> str:
    """Extract a time-only phrase so date and time can be answered separately."""
    try:
        from datetime import datetime

        local_iso = str(reading.get("local_iso") or "").strip()
        dt = datetime.fromisoformat(local_iso) if local_iso else None
    except Exception:
        dt = None
    if dt is None:
        try:
            from datetime import datetime

            epoch = reading.get("epoch")
            dt = datetime.fromtimestamp(float(epoch)) if epoch is not None else None
        except Exception:
            dt = None
    if dt is None:
        return ""
    return dt.strftime("%I:%M %p").lstrip("0")


def _date_parts_from_reading(reading: Dict[str, Any]) -> Dict[str, str]:
    """Extract stable human date fields from the oracle reading."""
    try:
        from datetime import datetime

        local_iso = str(reading.get("local_iso") or "").strip()
        dt = datetime.fromisoformat(local_iso) if local_iso else None
    except Exception:
        dt = None
    if dt is None:
        try:
            from datetime import datetime

            epoch = reading.get("epoch")
            dt = datetime.fromtimestamp(float(epoch)) if epoch is not None else None
        except Exception:
            dt = None
    if dt is None:
        return {"weekday": "", "date": "", "iso_date": ""}
    return {
        "weekday": dt.strftime("%A"),
        "date": dt.strftime("%B %d, %Y"),
        "iso_date": dt.date().isoformat(),
    }


def _current_date_reply_for_alice(reading: Optional[Dict[str, Any]] = None) -> str:
    """Return a grounded current-date reply from the hardware time oracle."""
    reading = reading or _current_time_reading_for_alice()
    if not reading.get("ok"):
        return _time_unavailable_reply()
    parts = _date_parts_from_reading(reading)
    weekday = parts.get("weekday") or ""
    date_text = parts.get("date") or ""
    if not weekday or not date_text:
        return _time_unavailable_reply()
    source = str(reading.get("source") or "local clock").strip()
    if source == "hardware_time_oracle":
        source_phrase = "from the hardware time oracle"
    elif source == "os_local_clock":
        source_phrase = "from the local OS clock fallback"
    else:
        source_phrase = f"from {source}"
    return _vary_date_reply(weekday, date_text, source_phrase)


def _current_date_time_reply_for_alice(reading: Optional[Dict[str, Any]] = None) -> str:
    """Return date and time together when the owner asks for both."""
    reading = reading or _current_time_reading_for_alice()
    if not reading.get("ok"):
        return _time_unavailable_reply()
    parts = _date_parts_from_reading(reading)
    time_text = _time_text_from_reading(reading)
    timezone = str(reading.get("timezone") or "").strip()
    source = str(reading.get("source") or "local clock").strip()
    if not parts.get("weekday") or not parts.get("date") or not time_text:
        return _time_unavailable_reply()
    if source == "hardware_time_oracle":
        source_phrase = "from the hardware time oracle"
    elif source == "os_local_clock":
        source_phrase = "from the local OS clock fallback"
    else:
        source_phrase = f"from {source}"
    tz_suffix = f" {timezone}" if timezone else ""
    src_tail = f" I got that {source_phrase}." if source_phrase else ""
    return f"Today is {parts['weekday']}, {parts['date']}. The time is {time_text}{tz_suffix}.{src_tail}"


def _current_time_date_reflex_reply_for_alice(
    text: str,
    reading: Optional[Dict[str, Any]] = None,
) -> tuple[str, str]:
    """Return (reply, model_tag) for direct time/date requests.

    This is Layer 1 hardware knowledge. It must run before media/quiet gates
    in the voice path, because "Alice, what time is it?" is direct address even
    when YouTube or room audio is active. Clock/date/time are the owner's
    allowed deterministic facts: answer from the signed hardware oracle instead
    of asking a cortex to infer the current time from stale conversation text.
    """
    time_asked = _is_current_time_query(text)
    date_asked = _is_current_date_query(text)
    if not time_asked and not date_asked:
        return "", ""
    oracle_reading = reading or _current_time_reading_for_alice()
    if time_asked and date_asked:
        return _current_date_time_reply_for_alice(oracle_reading), "hardware_date_time_oracle_reflex"
    if date_asked:
        return _current_date_reply_for_alice(oracle_reading), "hardware_date_oracle_reflex"
    return _current_time_reply_for_alice(oracle_reading), "hardware_time_oracle_reflex"


def _current_time_context_for_llm(reading: Dict[str, Any], reply: str) -> str:
    """Build a one-turn cortex instruction from the signed oracle reading."""
    source = str(reading.get("source") or "none")
    local_human = str(reading.get("local_human") or "").strip()
    timezone = str(reading.get("timezone") or "").strip()
    local_iso = str(reading.get("local_iso") or "").strip()
    signature = str(reading.get("signature") or "").strip()
    return (
        "TIME ORACLE TURN CONTEXT:\n"
        f"- source={source}\n"
        f"- current_local_time={local_human} {timezone}".rstrip() + "\n"
        f"- local_iso={local_iso}\n"
        f"- signature={signature or 'n/a'}\n"
        f"- required_spoken_answer={reply}\n"
        "- Speak the required_spoken_answer aloud in first person. Do not say you do not know the time."
    )


def _current_date_context_for_llm(reading: Dict[str, Any], reply: str) -> str:
    """Build a one-turn cortex instruction for date/day questions."""
    source = str(reading.get("source") or "none")
    local_human = str(reading.get("local_human") or "").strip()
    timezone = str(reading.get("timezone") or "").strip()
