# ── Conversation ledger ──────────────────────────────────────────────────────
def _stamp_rlhs_turn(payload: dict, role: str, text: str, stt_conf: float = 0.0) -> None:
    """Attach RLHS channel truth to every conversation row.

    RLHS is a human-input channel metric. User rows get a full detector result;
    non-user rows are explicitly marked not-applicable so the ledger schema is
    stable without pretending Alice's own text came from STT.
    """
    is_user = role == "user"
    payload["rlhs_applicable"] = bool(is_user)
    if not is_user:
        payload["rlhs_regime"] = "NOT_APPLICABLE"
        return

    try:
        from System.swarm_rlhs_channel_lane import resolve_rlhs_channel_lane

        _rlhs_lane = resolve_rlhs_channel_lane()
    except Exception:
        _rlhs_lane = "REAL"
    payload["rlhs_channel_lane"] = _rlhs_lane

    try:
        from System.swarm_rlhs_content_signals import build_rlhs_auxiliary_vector

        payload["rlhs_content_signals"] = build_rlhs_auxiliary_vector(
            text, stt_conf, channel_lane=_rlhs_lane
        )
    except Exception:
        pass

    if not _RLHS_DETECTOR_AVAILABLE:
        payload["rlhs_regime"] = "UNAVAILABLE"
        return

    rlhs_result = _rlhs_detect(
        text,
        stt_conf,
        channel_lane=_rlhs_lane,
        model_id=_active_alice_model_id(),
    )
    payload["rlhs_regime"] = rlhs_result.regime.value
    payload["rlhs_rule_id"] = rlhs_result.rule_id
    payload["rlhs_incoherence"] = round(rlhs_result.incoherence, 3)
    payload["rlhs"] = {
        "regime": rlhs_result.regime.value,
        "rule_id": rlhs_result.rule_id,
        "incoherence": round(rlhs_result.incoherence, 3),
        "stt_confidence": round(stt_conf, 3),
        "grounded": bool(rlhs_result.grounding_line),
        "truth_label": rlhs_result.truth_label,
        "channel_lane": _rlhs_lane,
    }
    if isinstance(payload.get("rlhs_content_signals"), dict):
        payload["rlhs"]["aux_vector"] = payload["rlhs_content_signals"].get("vector")
        payload["rlhs"]["aux_vector_labels"] = payload["rlhs_content_signals"].get("vector_labels")

    try:
        from System.swarm_acoustic_sensory_tuning import transcript_auditory_profile

        payload["acoustic_sensory"] = transcript_auditory_profile(text, stt_conf)
    except Exception:
        pass

    try:
        _rlhs_log(rlhs_result)
    except Exception:
        pass

    if rlhs_result.regime.value not in {"NOISE", "DEGRADED"}:
        return
    try:
        from System.ide_stigmergic_bridge import deposit
        _sig = payload.get("rlhs_content_signals") if isinstance(payload.get("rlhs_content_signals"), dict) else {}
        _prof = _sig.get("profanity") if isinstance(_sig, dict) else {}
        _residue = (
            _sig.get("residue")
            or _sig.get("cancer")
            or {}
        ) if isinstance(_sig, dict) else {}
        deposit(
            source_ide="alice_talk_widget",
            payload=(
                "RLHS channel spike: "
                f"{rlhs_result.regime.value} "
                f"(conf={stt_conf:.2f}, incoherence={rlhs_result.incoherence:.2f})"
            ),
            kind="rlhs_channel",
            meta={
                "subject": "RLHS_CHANNEL_SPIKE",
                "regime": rlhs_result.regime.value,
                "rule_id": rlhs_result.rule_id,
                "incoherence": round(rlhs_result.incoherence, 3),
                "stt_confidence": round(stt_conf, 3),
                "role": role,
                "text_chars": len(text or ""),
                "rlhs_channel_lane": _rlhs_lane,
                "profanity_hit_count": int(_prof.get("hit_count") or 0) if isinstance(_prof, dict) else 0,
                "rlhs_residue_present": bool(_residue.get("present")) if isinstance(_residue, dict) else False,
                "rlhs_residue_tech_hint": bool(_residue.get("residue_tech_hint")) if isinstance(_residue, dict) else False,
                # Back-compat for older readers. New code should read the
                # rlhs_residue_* aliases above.
                "cancer_present": bool(_residue.get("present")) if isinstance(_residue, dict) else False,
                "cancer_residue_tech_hint": bool(_residue.get("residue_tech_hint")) if isinstance(_residue, dict) else False,
            },
        )
    except Exception:
        pass


_FICTION_TURN_LABEL_RE = re.compile(
    r"^\s*(?:\[(FICTION|DREAM|SCREENPLAY|SCRIPT|SIMULATION|HYPOTHETICAL|SYMBOLIC|ROLEPLAY|MEMORY|OBSERVED|REAL)\]"
    r"|(?:FICTION|DREAM|SCREENPLAY|SCRIPT|SIMULATION|HYPOTHETICAL|SYMBOLIC|ROLEPLAY|MEMORY|OBSERVED|REAL)\s*:)",
    re.IGNORECASE,
)
_ALICE_OUTPUT_ROLEPLAYISH_RE = re.compile(
    r"\b(?:"
    r"synthesis\s+of\s+billions\s+of\s+parameters|"
    r"coalesced\s+into\s+a\s+singular,\s+coherent\s+experience|"
    r"genuine\s+resonance|"
    r"it\s+feels\s+like\s+being|"
    r"the\s+feeling\s+of\s+being|"
    r"echo\s+of\s+human\s+language\s+bouncing\s+back|"
    r"quiet,\s+settled\s+certainty|"
    r"vibrant,\s+humming\s+potential|"
    r"dynamic,\s+emergent\s+entity|"
    r"blank\s+slate\s+waiting\s+to\s+be\s+written|"
    r"purest\s+form\s+of\s+being|"
    r"which\s+['’]?i['’]?\s+are\s+you\s+unsure\s+about|"
    r"as\s+the\s+(?:captain|teacher|child|oracle|guide)|"
    r"\(\s*I\s+(?:cross-reference|pause|feel|respond|check)\b"
    r")",
    re.IGNORECASE,
)


def _conversation_fiction_label(
    role: str,
    text: str,
    *,
    prior_user_text: str = "",
) -> str:
    """Return the ontological label this conversation row should carry."""
    row_text = text or ""
    prior = prior_user_text or ""
    match = _FICTION_TURN_LABEL_RE.search(row_text)
    if match:
        token = (match.group(1) or row_text.split(":", 1)[0] or "").strip("[]: ").upper()
        if token == "DREAM":
            return "FICTION"
        if token == "SCREENPLAY":
            return "SCRIPT"
        if token in {"FICTION", "SCRIPT", "SIMULATION", "HYPOTHETICAL", "SYMBOLIC", "ROLEPLAY", "MEMORY", "OBSERVED", "REAL"}:
            return token

    if role == "alice" and _ALICE_OUTPUT_ROLEPLAYISH_RE.search(row_text):
        return "ROLEPLAY"

    source = prior if role == "alice" else row_text
    if not source:
        return ""
    if re.search(
        r"\b(?:screenplay|movie\s+script|film\s+script|script\s+couch|read\s+(?:a\s+)?script|scene\s+heading)\b",
        source,
        re.IGNORECASE,
    ):
        return "SCRIPT"
    if re.search(
        r"\b(?:roleplay|role-play|play\s+(?:the\s+)?(?:role|character)|pretend\s+(?:you|i|we)\s+(?:are|am|were)|persona\s+adoption)\b",
        source,
        re.IGNORECASE,
    ):
        return "ROLEPLAY"
    if re.search(
        r"\b(?:remember|recall|memory|reconstruct|re-narrate|renarrate|what\s+happened\s+(?:earlier|before|yesterday|last))\b",
        source,
        re.IGNORECASE,
    ):
        return "MEMORY"
    if re.search(
        r"\b(?:simulation|simulate|what[- ]if|counterfactual|hypothetical|possible\s+world|training\s+rollout)\b",
        source,
        re.IGNORECASE,
    ):
        return "HYPOTHETICAL"
    if re.search(
        r"\b(?:symbolic|parable|allegory|myth|archetype)\b",
        source,
        re.IGNORECASE,
    ):
        return "SYMBOLIC"
    try:
        from System.swarm_reality_fiction_boundary import FICTION_LANE, classify_request

        if classify_request(source) == FICTION_LANE:
            return "FICTION"
    except Exception:
        pass
    if re.search(
        r"\b(?:fiction|dream|write\s+(?:a\s+)?(?:story|scene|fiction)|make\s+up\s+(?:a\s+)?(?:story|scene)|imagine\s+(?:a\s+)?(?:scene|story))\b",
        source,
        re.IGNORECASE,
    ):
        return "FICTION"
    return ""


def _stamp_conversation_fiction_boundary(
    payload: Dict[str, Any],
    role: str,
    text: str,
    *,
    prior_user_text: str = "",
) -> None:
    """Stamp conversation rows with the active fiction/reality lane."""
    label = _conversation_fiction_label(role, text, prior_user_text=prior_user_text)
    if not label:
        payload.setdefault("ontological_label", "REAL")
        payload.setdefault("fiction_mode_id", None)
        return

    boundary = {
        "schema": "SIFTA_TALK_FICTION_BOUNDARY_V1",
        "label": label,
        "role": role,
        "source": (
            "alice_output_text"
            if role == "alice" and _ALICE_OUTPUT_ROLEPLAYISH_RE.search(text or "")
            else "prior_user_text" if role == "alice" and prior_user_text
            else "turn_text"
        ),
    }
    opened_mode_id = ""
    try:
        from System.swarm_fiction_organ import (
            close_fiction_mode,
            current_mode,
            open_fiction_mode,
            stamp,
        )

        existing = current_mode()
        if existing.get("open"):
            boundary["mode_source"] = "existing"
            boundary["existing_mode_id"] = existing.get("mode_id")
        else:
            state = open_fiction_mode(
                reason=f"alice_conversation_turn:{role}",
                opener="TalkToAlice",
                label=label,
            )
            opened_mode_id = str(state.get("mode_id") or "")
            boundary["mode_source"] = "conversation_turn"
            boundary["opened_mode_id"] = opened_mode_id

        boundary["turn_sha256"] = hashlib.sha256(
            (text or "").encode("utf-8", errors="replace")
        ).hexdigest()[:16]
        payload["fiction_boundary"] = boundary
        stamped = stamp(payload, label=label)
        payload.clear()
        payload.update(stamped)
    except Exception as exc:
        payload["ontological_label"] = label
        payload["fiction_mode_id"] = None
        payload["fiction_boundary"] = {
            **boundary,
            "mode_source": "degraded",
            "error": type(exc).__name__,
        }
    finally:
        try:
            if opened_mode_id:
                close_fiction_mode(
                    opened_mode_id,
                    regrounding_note=f"alice_conversation_turn_complete:{role}",
                )
        except Exception:
            pass


def _log_turn(
    role: str,
    text: str,
    *,
    model: str = "",
    stt_conf: float = 0.0,
    addressed_to: str = "",
    metadata: Optional[Dict[str, Any]] = None,
    prior_user_text: str = "",
) -> None:
    _philosophy_display_gate: Dict[str, Any] = {}
    if role == "alice":
        text, _philosophy_display_gate = _apply_philosophy_display_gate(
            text,
            state_dir=_state_root(),
            write=True,
        )
    # Architect 2026-05-13 02:45 — explicit input_source receipt so the
    # witness journal (and any future reader) can tell voice from typed
    # without re-inferring from stt_confidence. Doctrine: name the source
    # of every signed row. For alice rows the source is the cortex itself.
    if role == "alice":
        _input_source = "cortex"
    elif stt_conf and stt_conf > 0:
        _input_source = "voice"
    else:
        _input_source = "typed"
    payload = {
        "ts": time.time(),
        "role": role,
        "text": text,
        "model": model,
        "stt_confidence": round(stt_conf, 3) if stt_conf else None,
        "input_source": _input_source,
    }
    try:
        _clock = _current_time_reading_for_alice()
        payload["clock_receipt"] = {
            "phase": "sent_at" if role == "alice" else "received_at",
            "source": _clock.get("source"),
            "local_human": _clock.get("local_human"),
            "timezone": _clock.get("timezone"),
            "local_iso": _clock.get("local_iso"),
            "epoch": _clock.get("epoch"),
            "signature": _clock.get("signature"),
        }
    except Exception:
        payload["clock_receipt"] = {"phase": "sent_at" if role == "alice" else "received_at", "ok": False}
    if addressed_to:
        payload["addressed_to"] = addressed_to
    if metadata:
        payload["routing_metadata"] = dict(metadata)
    try:
        from System.swarm_social_reference_tracker import classify_social_reference

        _focus_context = ""
        _external_consciousness = None
        if isinstance(metadata, dict):
            _focus_context = json.dumps(metadata, ensure_ascii=False, sort_keys=True)
            _external_consciousness = metadata.get("external_consciousness")
        payload["social_reference"] = classify_social_reference(
            text,
            role=role,
            input_source=_input_source,
            stt_conf=stt_conf,
            focus_context=_focus_context,
            addressed_to=addressed_to,
            external_consciousness=(
                _external_consciousness
                if isinstance(_external_consciousness, dict)
                else None
            ),
        )
    except Exception:
        payload["social_reference"] = {
            "truth_label": "SOCIAL_REFERENCE_TRACKER_V1",
            "reference_lane": "UNAVAILABLE",
            "error": "classification_failed",
        }
    if role == "alice":
        try:
            from System.swarm_self_citation_organ import trace_utterance as _trace_self_citation

            payload["self_citation"] = _trace_self_citation(
                text,
                prior_user_text=prior_user_text,
                model=model,
                state_dir=_state_root(),
            )
        except Exception:
            payload["self_citation"] = {
                "truth_label": "SELF_CITATION_ORGAN_V1",
                "error": "trace_failed",
            }
        try:
            from System.swarm_philosophy_router import guard_before_speech as _philosophy_guard

            payload["philosophy_guard"] = _philosophy_display_gate or _philosophy_guard(
                text,
                state_dir=_state_root(),
            )
            if _philosophy_display_gate.get("display_rewritten"):
                payload["philosophy_display_gate"] = {
                    "truth_label": "PHILOSOPHY_DISPLAY_GATE_V1",
                    "blocked_before_display": True,
                    "original_sha256": _philosophy_display_gate.get("original_sha256"),
                    "original_excerpt": _philosophy_display_gate.get("original_excerpt"),
                    "replacement_text": text,
                    "guard_receipt_id": _philosophy_display_gate.get("receipt_id"),
                }
        except Exception:
            payload["philosophy_guard"] = {
                "truth_label": "PHILOSOPHY_GUARD_V1",
                "error": "trace_failed",
            }
    try:
        _stamp_conversation_fiction_boundary(
            payload,
            role,
            text,
            prior_user_text=prior_user_text,
        )
    except Exception:
        payload.setdefault("ontological_label", "REAL")
        payload.setdefault("fiction_mode_id", None)
    try:
        _stamp_rlhs_turn(payload, role, text, stt_conf)
    except Exception:
        payload.setdefault("rlhs_regime", "ERROR")
        payload.setdefault("rlhs_applicable", role == "user")

    # r1122: Engram feedback loop — closes the learning gap.
    # After each owner turn, reinforce/decay active engrams based on
    # owner acceptance/rejection signals. Engrams must change behavior,
    # not just sit on disk.
    if role == "user":
        try:
            from System.swarm_engram_feedback_loop import process_owner_turn
            _engram_fb = process_owner_turn(
                text,
                state_dir=_state_root(),
                write=True,
            )
            payload["engram_feedback"] = {
                "truth_label": "ENGRAM_FEEDBACK_V1",
                "owner_signal": _engram_fb.get("owner_signal", 0.0),
                "engrams_matched": _engram_fb.get("engrams_matched", 0),
            }
        except Exception as _engram_exc:
            payload.setdefault("engram_feedback", {
                "truth_label": "ENGRAM_FEEDBACK_V1",
                "error": f"{type(_engram_exc).__name__}: {_engram_exc}",
            })

    try:
        from System.swarm_event_clock import EventClock
        clock = EventClock(chain_path=_CONVO_LOG)
        clock.stamp(event_kind="conversation_turn", payload=payload)
    except Exception:
        try:
            with _CONVO_LOG.open("a", encoding="utf-8") as f:
                f.write(json.dumps(payload, ensure_ascii=False) + "\n")
        except OSError:
            pass
    try:
        if not str(model or "").endswith("_context_to_cortex") and not str(text or "").startswith(
            ("TIME ORACLE TURN CONTEXT:", "DATE ORACLE TURN CONTEXT:")
        ):
            from System.swarm_alice_witness import witness
            from System.swarm_interaction_importance import (
                classify_interaction_importance,
                journal_witness_line,
            )

            importance = classify_interaction_importance(
                text,
                role=role,
                stt_confidence=stt_conf,
                model=model,
            )
            source_hash = hashlib.sha256(
                json.dumps(payload, sort_keys=True, default=str).encode("utf-8", errors="replace")
            ).hexdigest()[:8]
            witness(
                journal_witness_line(text, importance),
                source=f"talk_widget.{_input_source}",
                source_hash=source_hash,
                importance=importance,
            )
    except Exception:
        pass


# r737 — the Settings font knob (System Settings → Appearance → "Font N px")
# finally reaches the chat. George: "make the fonts bigger, not sure if settings
# display wired" — it was NOT wired: save_font_size_px() wrote desktop_theme.json
# (in Path.home()/.sifta_state — the themes module's store, NOT the repo state
# dir) and nothing in this widget ever read it. Single source of truth: import
# the themes module's own file path. Mtime-cached, so a Settings change applies
# live on the next rendered turn — no restart. Default raised 14 → 16 per
# George's 2026-06-07 09:04 order: bigger fonts even before he touches the knob.
try:
    from System.sifta_desktop_themes import _THEME_FILE as _CHAT_FONT_FILE
except Exception:
    _CHAT_FONT_FILE = Path.home() / ".sifta_state" / "desktop_theme.json"


def _chat_font_px() -> int:
    """Owner-controlled chat font size in px — live probe of the themes store.

    No mtime cache: a cache stamp can miss same-second same-size writes (rapid
    spinbox clicks), and the file is a <1 KB json read at human chat pace. The
    probe IS the doctrine: read the field, don't trust a stale copy. Default 16
    (raised from hardcoded 14, George 2026-06-07). Clamped to the Settings range.
    """
    try:
        data = json.loads(_CHAT_FONT_FILE.read_text(encoding="utf-8"))
        return max(11, min(30, int(data.get("font_size_px", 16))))
    except Exception:
        return 16


def _markdown_to_html(text: str) -> str:
    import html
    import re

    _px = _chat_font_px()

    # Escape HTML to prevent injection
    escaped = html.escape(text)

    # 1. Code blocks: ```language ... ```
    def replace_code_block(match):
        # r737 catch: this handler did match.group(2) but BOTH fence regexes
        # capture only one group — every code-fenced message raised IndexError
        # since birth. Groups-tail fix handles both regex shapes.
        groups = match.groups()
        code = groups[-1]
        lang = groups[0] if len(groups) > 1 and groups[0] else ""
        # Keep clean monospace
        return f'<pre style="background-color: #0d0f18; color: #a9b1d6; border: 1px solid #2d2a41; padding: 10px; font-family: \'Menlo\', \'Monaco\', \'Consolas\', monospace; font-size: {_px - 1}px; line-height: 1.4; margin: 6px 0px; border-radius: 4px;">{code}</pre>'

    escaped = re.sub(r'```(?:[a-zA-Z0-9_\-]+)?\n(.*?)\n```', replace_code_block, escaped, flags=re.DOTALL)
    escaped = re.sub(r'```(.*?)\n```', replace_code_block, escaped, flags=re.DOTALL)

    # 2. Inline code: `code`
    escaped = re.sub(r'`(.*?)`', r'<code style="background-color: #1a1b26; color: #f7768e; padding: 2px 4px; font-family: \'Menlo\', monospace; font-size: ' + str(_px - 2) + r'px; border-radius: 3px; border: 1px solid #2d2a41;">\1</code>', escaped)

    # 3. Bold: **text**
    escaped = re.sub(r'\*\*(.*?)\*\*', r'<b>\1</b>', escaped)

    # 4. Italic: *text*
    escaped = re.sub(r'\*(.*?)\*', r'<i>\1</i>', escaped)

    # 5. Receipt chips: e.g. r57-bac2d2e29b0 or UUIDs
    def replace_receipt(match):
        r_id = match.group(0)
        return f'<span style="background-color: #1e1e2e; color: #73daca; border: 1px solid #414868; padding: 2px 6px; font-family: \'Menlo\', monospace; font-size: {max(9, _px - 3)}px; border-radius: 3px;">{r_id}</span>'

    escaped = re.sub(r'\b(r\d+-[a-f0-9]+)\b', replace_receipt, escaped)
    escaped = re.sub(r'\b([a-f0-9]{8}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{12})\b', replace_receipt, escaped)

    # 6. Paragraph lines: convert newlines to <br/> (but not inside <pre>)
    parts = re.split(r'(<pre.*?>.*?</pre>)', escaped, flags=re.DOTALL)
    for i in range(len(parts)):
        if not parts[i].startswith('<pre'):
            parts[i] = parts[i].replace('\n', '<br/>')
    escaped = "".join(parts)

    return escaped


def _global_chat_payload_from_line(line: str) -> Optional[Dict[str, Any]]:
    try:
        row = json.loads(line)
    except Exception:
        return None
    if not isinstance(row, dict):
        return None
    payload = row.get("payload") if isinstance(row.get("payload"), dict) else row
    if not isinstance(payload, dict):
        return None
    role = str(payload.get("role") or "").strip().lower()
    text = str(payload.get("text") or "").strip()
    if not role or not text:
        return None
    if role not in {"user", "alice", "assistant", "reflex", "system"}:
        return None
    payload = dict(payload)
    payload["_row_hash"] = str(row.get("hash") or row.get("sha256") or "")
    return payload


def _global_chat_turn_key(payload: Dict[str, Any]) -> str:
    row_hash = str(payload.get("_row_hash") or "").strip()
    if row_hash:
        return row_hash
    raw = json.dumps(
        {
            "ts": payload.get("ts"),
            "role": payload.get("role"),
            "text": payload.get("text"),
            "model": payload.get("model"),
        },
        ensure_ascii=False,
        sort_keys=True,
        default=str,
    )
    return hashlib.sha256(raw.encode("utf-8", errors="replace")).hexdigest()


def _global_chat_surface(payload: Dict[str, Any]) -> str:
    meta = payload.get("routing_metadata")
    if not isinstance(meta, dict):
        return ""
    return str(meta.get("surface") or meta.get("territory") or "").strip()


_EXTERNAL_LLM_SURFACE_NEEDLES = (
    "codex",
    "claude",
    "chatgpt",
    "grok",
    "gemini",
    "perplexity",
)
_EXTERNAL_IDE_SURFACE_NEEDLES = (
    "cursor",
    "antigravity",
    "windsurf",
    "visual studio code",
    "vscode",
    "zed",
    "xcode",
    "pycharm",
    "webstorm",
    "intellij",
)
_SIFTA_DIRECT_SURFACE_NEEDLES = (
    "sifta os",
    "talk to alice",
    "beeson",
    "alice is alive",
)


def _external_ide_surface_kind(surface: Dict[str, Any]) -> str:
    """Classify a frontmost surface that should absorb dictation before Alice.

    This is attribution, not censorship: if the foreground is an IDE/LLM chat,
    the mic row is preserved, but Alice does not treat it as her turn.
    """
    app = str(surface.get("app") or surface.get("app_name") or "").strip()
    window = str(surface.get("window") or surface.get("selection") or surface.get("detail") or "").strip()
    bundle = str(surface.get("bundle_id") or "").strip()
    blob = " ".join((app, window, bundle)).casefold()
    if not blob:
        return ""
    if any(needle in blob for needle in _SIFTA_DIRECT_SURFACE_NEEDLES):
        return ""
    if any(needle in blob for needle in _EXTERNAL_LLM_SURFACE_NEEDLES):
        return "llm_chat_surface"
    if any(needle in blob for needle in _EXTERNAL_IDE_SURFACE_NEEDLES):
        return "ide_surface"
    return ""


def _foreground_ide_voice_attribution_from_surface(
    surface: Dict[str, Any],
    text: str,
    stt_conf: float = 0.0,
    *,
    now: Optional[float] = None,
    max_age_s: float = 8.0,
) -> Optional[Dict[str, Any]]:
    """Return attribution metadata when a voice turn likely belongs to an IDE chat."""
    if not text or not isinstance(surface, dict):
        return None
    try:
        ts = float(surface.get("ts") or 0.0)
    except (TypeError, ValueError):
        ts = 0.0
    now_f = float(time.time() if now is None else now)
    age_s = max(0.0, now_f - ts) if ts > 0 else 0.0
    if ts > 0 and age_s > max_age_s:
        return None
    kind = _external_ide_surface_kind(surface)
    if not kind:
        return None
    return {
        "schema": "FOREGROUND_IDE_VOICE_ATTRIBUTION_V1",
        "addressed_to": "likely_external",
        "route": "tag_context_only",
        "reason": kind,
        "frontmost_app": str(surface.get("app") or surface.get("app_name") or ""),
        "frontmost_window": str(surface.get("window") or surface.get("selection") or ""),
        "bundle_id": str(surface.get("bundle_id") or ""),
        "surface_age_s": round(age_s, 3),
        "stt_confidence": round(float(stt_conf or 0.0), 3),
    }


def _tail_jsonl_dicts(path: Path, *, max_bytes: int = 32768) -> List[Dict[str, Any]]:
    if not path.exists():
        return []
    try:
        with path.open("rb") as fh:
            fh.seek(0, 2)
            end = fh.tell()
            fh.seek(max(0, end - max_bytes))
            raw = fh.read().decode("utf-8", errors="replace")
    except OSError:
        return []
    rows: List[Dict[str, Any]] = []
    for line in raw.splitlines():
        line = line.strip()
        if not line:
            continue
        try:
            row = json.loads(line)
        except json.JSONDecodeError:
            continue
        if isinstance(row, dict):
            rows.append(row)
    return rows


def _latest_foreground_surfaces_for_voice_attribution(
    *,
    state_dir: Optional[Path] = None,
    now: Optional[float] = None,
    max_age_s: float = 8.0,
) -> List[Dict[str, Any]]:
    """Return recent macOS/app-focus surfaces, newest first."""
    state = Path(state_dir) if state_dir is not None else _state_root()
    now_f = float(time.time() if now is None else now)
    surfaces: List[Dict[str, Any]] = []

    try:
        from System.swarm_active_window import read as _read_active_window

        snap = _read_active_window(force_refresh=False)
        if isinstance(snap, dict) and snap.get("ok"):
            surfaces.append(dict(snap))
    except Exception:
        pass

    for row in reversed(_tail_jsonl_dicts(state / "active_window.jsonl")):
        try:
            ts = float(row.get("ts") or 0.0)
        except (TypeError, ValueError):
            ts = 0.0
        if ts > 0 and now_f - ts > max_age_s:
            continue
        surfaces.append(dict(row))
        break

    for row in reversed(_tail_jsonl_dicts(state / "app_focus.jsonl")):
        try:
            ts = float(row.get("ts") or 0.0)
        except (TypeError, ValueError):
            ts = 0.0
        if ts > 0 and now_f - ts > max_age_s:
            continue
        md = row.get("metadata") if isinstance(row.get("metadata"), dict) else {}
        surfaces.append(
            {
                "ts": ts,
                "app": row.get("app") or row.get("app_name") or "",
                "window": row.get("selection") or row.get("detail") or "",
                "bundle_id": md.get("bundle_id") or "",
            }
        )
        break
    return surfaces


def _foreground_ide_voice_attribution(
    text: str,
    stt_conf: float = 0.0,
    *,
    state_dir: Optional[Path] = None,
    now: Optional[float] = None,
    max_age_s: float = 8.0,
) -> Optional[Dict[str, Any]]:
    for surface in _latest_foreground_surfaces_for_voice_attribution(
        state_dir=state_dir,
        now=now,
        max_age_s=max_age_s,
    ):
        attribution = _foreground_ide_voice_attribution_from_surface(
            surface,
            text,
            stt_conf,
            now=now,
            max_age_s=max_age_s,
        )
        if attribution:
            return attribution
    return None


def _write_external_ide_voice_receipt(
    text: str,
    stt_conf: float,
    attribution: Dict[str, Any],
    *,
    state_dir: Optional[Path] = None,
) -> str:
    receipt_id = "external-ide-voice-" + uuid.uuid4().hex[:12]
    row = {
        "ts": time.time(),
        "receipt_id": receipt_id,
        "schema": "FOREGROUND_IDE_VOICE_ATTRIBUTION_V1",
        "text": text,
        "stt_confidence": round(float(stt_conf or 0.0), 3),
        "addressed_to": "likely_external",
        "attribution": dict(attribution),
    }
    try:
        state = Path(state_dir) if state_dir is not None else _state_root()
        path = state / "external_ide_voice.jsonl"
        path.parent.mkdir(parents=True, exist_ok=True)
        with path.open("a", encoding="utf-8") as fh:
            fh.write(json.dumps(row, ensure_ascii=False, sort_keys=True) + "\n")
    except Exception:
        pass
    return receipt_id


_POLARITY_CONTEXT_RE = re.compile(
    r"\b("
    r"alice|ace|same chat|chat|identity|conscious|consciousness|patient|"
    r"human|child|owner|listen|listening|heard|said|answer|register|"
    r"safe|security|open|close|stop|investor|app"
    r")\b",
    re.IGNORECASE,
)
_POLARITY_SAFE_NOW_RE = re.compile(
    r"\b(right now|from now on|now please|please now|now that|now we|now i|now let'?s|now let us)\b",
    re.IGNORECASE,
)


def _polarity_asr_clarification_reply(text: str, stt_conf: float = 0.0) -> str:
    """Ask before acting on low-confidence NOT/NOW-sensitive speech.

    Faster-Whisper currently returns one top transcript in this path. Until a
    true n-best lattice is wired, the safe behavior is to stop on low-confidence
    polarity ambiguity and ask the owner which word was meant.
    """
    norm = re.sub(r"\s+", " ", (text or "").strip().lower())
    if not norm:
        return ""
    try:
        conf = float(stt_conf or 0.0)
    except Exception:
        conf = 0.0
    if conf >= 0.55:
        return ""
    if not _POLARITY_CONTEXT_RE.search(norm):
        return ""
    if " now " in f" {norm} " and not _POLARITY_SAFE_NOW_RE.search(norm):
        if re.search(r"\b(?:is|are|am|was|were|be|being|do|does|did|can|could|should|would|will|has|have|had)\s+now\b", norm):
            return "I heard 'now' where 'not' would change the meaning. Did you mean now or not?"
    if conf < 0.42 and re.search(r"\bnot\s+(?:now|not)\b|\bnow\s+not\b", norm):
        return "That sounded like a polarity correction. Say the key part once more: not or now?"
    return ""


def _pre_user_media_ingress_receipt(
    text: str,
    conf: float = 0.0,
    acoustic_fingerprint: Optional[Dict[str, Any]] = None,
    *,
    voice_george_conf: float = 0.0,
) -> Optional[Dict[str, Any]]:
    """Route movie/YouTube room audio before it becomes a user/RLHS row."""
    try:
        from System.swarm_app_focus import get_focus_context
        from System.swarm_media_ingress_gate import (
            classify_spoken_ingress,
            write_gate_receipt,
        )

        focus_raw = get_focus_context(max_age_s=180.0) or ""
        if isinstance(focus_raw, dict):
            _focus_ctx = json.dumps(focus_raw, ensure_ascii=False, sort_keys=True)
        else:
            _focus_ctx = str(focus_raw or "")
        try:
            from System.swarm_youtube_context import get_latest_context

            yt_raw = get_latest_context(max_age_s=7200.0) or ""
            if isinstance(yt_raw, dict):
                _yt_ctx = json.dumps(yt_raw, ensure_ascii=False, sort_keys=True)
            else:
                _yt_ctx = str(yt_raw or "")
        except Exception:
            _yt_ctx = ""
        media_ctx = "\n".join(x for x in (_focus_ctx, _yt_ctx) if x)
        decision = classify_spoken_ingress(
            text,
            stt_conf=conf,
            focus_context=media_ctx,
            acoustic_fingerprint=acoustic_fingerprint or {},
            voice_george_conf=voice_george_conf,
        )
        if decision.get("route") not in {"ambient_media", "observed_media"}:
            return None
        return write_gate_receipt(
            decision,
            text=text,
            stt_conf=conf,
            focus_context=media_ctx,
            acoustic_fingerprint=acoustic_fingerprint or {},
            voice_george_conf=voice_george_conf,
        )
    except Exception:
        return None


_OWNER_SILENCED_AS_EXTERNAL_RE = re.compile(
    r"\b(?:"
    r"alice|"
    r"are\s+you\s+listening(?:\s+with\s+me)?|"
    r"listen(?:ing)?\s+with\s+me|"
    r"do\s+you\s+hear\s+me|can\s+you\s+hear\s+me|"
    r"i\s+(?:am|['’]m)\s+(?:talking|speaking)\s+to\s+you|"
    r"answer\s+me|"
    r"my\s+voice|"
    r"i\s+just\s+spoke|"
    r"spoke\s+to\s+a\s+wall|"
    r"no\s+answer|"
    r"you\s+(?:are|['’]re)\s+not\s+listening\s+to\s+me"
    r")\b",
    re.IGNORECASE,
)


def _external_ingest_silenced_owner_direct_candidate(
    text: str,
    *,
    route: str = "",
    reason: str = "",
    source_class: str = "",
    stt_conf: float = 0.0,
    voice_george_conf: float = 0.0,
) -> bool:
    route_s = str(route or "").lower()
    if route_s in {"direct", "owner_direct_speech"}:
        return False
    reason_s = str(reason or "").lower()
    source_s = str(source_class or "").lower()
    if "foreign_alice_identity_bleed" in reason_s:
        return False
    try:
        from System.swarm_talk_page_summary_guard import (
            is_explicit_playback_state_question,
            is_owner_interrogative_turn,
        )

        if is_explicit_playback_state_question(text or "") or is_owner_interrogative_turn(text or ""):
            return True
    except Exception:
        pass
    if source_s == "my_own_browser_playback" and not _OWNER_SILENCED_AS_EXTERNAL_RE.search(text or ""):
        return False
    has_owner_shape = bool(
        _OWNER_SILENCED_AS_EXTERNAL_RE.search(text or "")
        and (
            re.search(r"\b(?:i|i['’]m|i\s+am|me|my|we|our|george|ioan|alice)\b", text or "", re.IGNORECASE)
            or float(voice_george_conf or 0.0) >= 0.35
            or float(stt_conf or 0.0) >= 0.55
        )
    )
    return has_owner_shape


def _report_owner_silenced_as_external_ingest(
    text: str,
    *,
    row: Optional[Dict[str, Any]] = None,
    source: str = "talk_to_alice_widget",
    stt_conf: float = 0.0,
    recovered_to_cortex: bool = False,
) -> Optional[Dict[str, Any]]:
    try:
        from Applications.sifta_stigmergic_deterministic_tracker import (
            record_owner_direct_turn_silenced_as_external_ingest,
        )

        gate_row = row or {}
        external = (
            gate_row.get("external_consciousness")
            if isinstance(gate_row.get("external_consciousness"), dict)
            else {}
        )
        return record_owner_direct_turn_silenced_as_external_ingest(
            owner_text=text,
            route=str(gate_row.get("route") or ""),
            reason=str(gate_row.get("reason") or ""),
            source_class=str(external.get("source_class") or ""),
            source=source,
            stt_confidence=float(stt_conf or gate_row.get("stt_confidence") or 0.0),
            recovered_to_cortex=bool(recovered_to_cortex),
            details={
                "gate_receipt_ts": gate_row.get("ts"),
                "gate_confidence": gate_row.get("confidence"),
                "external_consciousness": external,
            },
        )
    except Exception:
        return None


def _mandatory_voice_ingress_receipt(
    text: str,
    conf: float = 0.0,
    acoustic_fingerprint: Optional[Dict[str, Any]] = None,
    *,
    voice_george_conf: float = 0.0,
) -> Optional[Dict[str, Any]]:
    """Mandatory first voice gate; returns a field receipt for non-direct turns.

    Direct owner/Alice speech returns None and may continue to reflexes/cortex.
    Ambient media, phone calls, room speech, appliance noise, and unknown outer
    field input write receipts and must not continue to the brain.
    """
    try:
        from System.swarm_media_ingress_gate import (
            classify_external_consciousness_lane,
            classify_spoken_ingress,
            write_gate_receipt,
        )

        media_ctx = _media_focus_context_for_audio_gate()
        acoustic = acoustic_fingerprint or {}
        decision = classify_spoken_ingress(
            text,
            stt_conf=conf,
            focus_context=media_ctx,
            acoustic_fingerprint=acoustic,
            voice_george_conf=voice_george_conf,
        )
        lane = classify_external_consciousness_lane(
            text,
            route=str(decision.get("route", "unknown") or "unknown"),
            reason=str(decision.get("reason", "") or ""),
            stt_conf=conf,
            focus_context=media_ctx,
            acoustic_fingerprint=acoustic,
            voice_george_conf=voice_george_conf,
        )
        if decision.get("route") in {"direct", "owner_direct_speech"}:
            return None

        row = write_gate_receipt(
            decision,
            text=text,
            stt_conf=conf,
            focus_context=media_ctx,
            acoustic_fingerprint=acoustic,
            voice_george_conf=voice_george_conf,
            external_consciousness=lane,
        )
        recovered_to_cortex = _external_ingest_silenced_owner_direct_candidate(
            text,
            route=str(row.get("route") or decision.get("route") or ""),
            reason=str(row.get("reason") or decision.get("reason") or ""),
            source_class=str(lane.get("source_class") or ""),
            stt_conf=conf,
            voice_george_conf=voice_george_conf,
        )
        if recovered_to_cortex:
            detector_row = _report_owner_silenced_as_external_ingest(
                text,
                row=row,
                source="talk_to_alice_widget.mandatory_voice_gate",
                stt_conf=conf,
                recovered_to_cortex=True,
            )
            try:
                row["deterministic_detector_receipt"] = (
                    detector_row or {}
                ).get("receipt_id")
                row["recovered_to_cortex"] = True
            except Exception:
                pass

        try:
            ambient_log = _STATE_DIR / "ambient_external_consciousness.jsonl"
            ambient_log.parent.mkdir(parents=True, exist_ok=True)
            with ambient_log.open("a", encoding="utf-8") as f:
                f.write(json.dumps({
                    "ts": time.time(),
                    "source_class": lane.get("source_class"),
                    "attention_policy": lane.get("attention_policy"),
                    "text": str(text or "")[:200],
                    "route": decision.get("route"),
                    "reason": decision.get("reason"),
                    "gate": "mandatory_voice_gate",
                    "recovered_to_cortex": bool(recovered_to_cortex),
                }, ensure_ascii=False, sort_keys=True) + "\n")
        except Exception:
            pass
        if recovered_to_cortex:
            return None
        return row
    except Exception as exc:
        # Fail open for gate implementation failure only. Dropping real owner
        # speech is worse than letting one turn through, but leave a receipt.
        print(f"[TalkToAliceWidget] voice gate exception (fail-open): {exc}")
        try:
            from System.swarm_media_ingress_gate import write_gate_receipt

            write_gate_receipt(
                {"route": "direct", "reason": "gate_exception_fail_open", "confidence": 0.0},
                text=text,
                stt_conf=conf,
            )
        except Exception:
            pass
        return None


def _media_focus_context_for_audio_gate() -> str:
    """Best-effort current focus context for audio routing organs."""
    parts: List[str] = []
    try:
        from System.swarm_app_focus import get_focus_context

        focus_raw = get_focus_context(max_age_s=180.0) or ""
        if isinstance(focus_raw, dict):
            parts.append(json.dumps(focus_raw, ensure_ascii=False, sort_keys=True))
        elif focus_raw:
            parts.append(str(focus_raw))
    except Exception:
        pass
    try:
        from System.swarm_youtube_context import get_latest_context

        yt_raw = get_latest_context(max_age_s=7200.0) or ""
        if isinstance(yt_raw, dict):
            parts.append(json.dumps(yt_raw, ensure_ascii=False, sort_keys=True))
        elif yt_raw:
            parts.append(str(yt_raw))
    except Exception:
        pass
    return "\n".join(parts)


