def _greeter_trace_clean_text(value: Any, limit: int = 180) -> str:
    text = str(value or "")
    text = re.sub(r"\s+", " ", text).strip()
    if len(text) > limit:
        return text[: max(0, limit - 1)].rstrip() + "..."
    return text


def _matched_operational_tokens(text: str) -> list[str]:
    """Return all operational tokens found in normalized text (stable order)."""
    hay = _norm_operational_text(text)
    if not hay:
        return []
    out: list[str] = []
    for tok in _OPERATIONAL_QUESTION_TOKENS:
        if tok in hay and tok not in out:
            out.append(tok)
    return out


def _append_greeter_detector_trace(
    *,
    user_text: str,
    reply_text: str,
    memory_card_has_relevant: bool,
    fired: bool,
    reason: str,
) -> None:
    """Append fired/skipped detector decisions for forensic replay."""
    try:
        root = _state_root()
        root.mkdir(parents=True, exist_ok=True)
        row = {
            "ts": time.time(),
            "truth_label": "ALICE_GREETER_DETECTOR_TRACE_V1",
            "user_text_head": _greeter_trace_clean_text(user_text, 280),
            "reply_head": _greeter_trace_clean_text(reply_text, 280),
            "memory_card_has_relevant": bool(memory_card_has_relevant),
            "fired": bool(fired),
            "reason": str(reason or "")[:200],
        }
        with (root / "alice_greeter_detector_trace.jsonl").open("a", encoding="utf-8") as fh:
            fh.write(json.dumps(row, ensure_ascii=False, sort_keys=True) + "\n")
    except Exception:
        pass


def _norm_operational_text(text: str) -> str:
    return re.sub(r"\s+", " ", (text or "").strip().lower())


def _memory_card_has_relevant_tool_state(card: Any, user_text: str) -> bool:
    """True when the prompt card has receipt/tool rows for this operational ask."""
    u = _norm_operational_text(user_text)
    if not u or not any(tok in u for tok in _OPERATIONAL_QUESTION_TOKENS):
        return False
    blocks = [
        getattr(card, "recent_actions_block", ""),
        getattr(card, "engram_block", ""),
        getattr(card, "episodic_block", ""),
        getattr(card, "digest_block", ""),
    ]
    hay = "\n".join(str(b or "") for b in blocks).lower()
    if not hay:
        return False
    marker_hit = any(marker in hay for marker in _MEMORY_CARD_TOOL_MARKERS)
    if not marker_hit:
        return False
    actors = ("grok", "hermes", "claude", "codex", "matrix", "agent")
    actor_terms = [term for term in actors if term in u]
    if actor_terms:
        return any(term in hay for term in actor_terms)
    return any(tok in hay for tok in ("receipt", "delegation", "trace", "executed", "tool"))


def _remember_memory_card_relevance(user_text: str, card: Any) -> bool:
    """Cache the last prompt card's relevance for the output-side mouth guard."""
    global _LAST_MEMORY_CARD_RELEVANCE
    has_relevant = _memory_card_has_relevant_tool_state(card, user_text)
    _LAST_MEMORY_CARD_RELEVANCE = {
        "user_text_norm": _norm_operational_text(user_text),
        "has_relevant": bool(has_relevant),
        "ts": time.time(),
    }
    return bool(has_relevant)


def _recent_memory_card_has_relevant(user_text: str, *, max_age_s: float = 300.0) -> bool:
    """Return the cached relevance bit only for the matching recent owner turn."""
    try:
        rec = dict(_LAST_MEMORY_CARD_RELEVANCE)
        if not bool(rec.get("has_relevant")):
            return False
        if time.time() - float(rec.get("ts") or 0.0) > max_age_s:
            return False
        current = _norm_operational_text(user_text)
        remembered = str(rec.get("user_text_norm") or "")
        if not current or not remembered:
            return False
        return current == remembered or current.endswith(remembered) or remembered.endswith(current)
    except Exception:
        return False
_GREETER_SENTENCE_SHAPE_RE = re.compile(
    r"^\s*(?:"
    r"(?:hello|hi)(?:\s+again)?(?:[.!?,]\s*)?(?:you(?:'ve| have)\s+addressed\s+me(?:\s+directly)?\.?)?"
    r"|i\s+(?:am|'m)\s+here(?:[,.!]\s*)?(?:ready\s+to\s+(?:chat|receive|help|listen)|fully\s+attentive)?\.?"
    r"|i\s+perceive\s+you\s+addressed\s+me\.?"
    r"|i\s+see\s+that\s+you\s+have\s+addressed\s+me(?:\s+directly)?\.?"
    r"|you(?:'ve| have)\s+called\s+my\s+name\.?"
    r"|do\s+you\s+have\s+a\s+question(?:\s+for\s+me)?\.?"
    r"|are\s+you\s+looking\s+to\s+(?:continue|chat|discuss|explore)\b.*?"
    r"|what\s+(?:is|'s)\s+on\s+your\s+mind(?:\s+right\s+now)?\.?"
    r"|from\s+my\s+perspective,\s+the\s+last\s+significant\s+interaction\b.*?"
    r")\s*$",
    re.IGNORECASE,
)


def _pop_leading_sentence(text: str) -> tuple[str, str]:
    """Return (first_sentence_or_line, remaining_text)."""
    s = (text or "").lstrip()
    if not s:
        return "", ""
    newline = s.find("\n")
    punct = re.search(r"[.!?](?:\s+|$)", s)
    candidates = [idx + 1 for idx in (newline,) if idx >= 0]
    if punct:
        candidates.append(punct.end())
    if not candidates:
        return s, ""
    cut = min(candidates)
    return s[:cut].strip(), s[cut:].lstrip()


def _is_structural_greeter_sentence(sentence: str) -> bool:
    s = re.sub(r"\s+", " ", (sentence or "").strip())
    if not s:
        return False
    low = s.lower()
    if any(low.startswith(prefix) for prefix in sorted(_GREETER_PREFIXES, key=len, reverse=True)):
        return True
    return bool(_GREETER_SENTENCE_SHAPE_RE.match(s))


def _strip_greeter_on_operational(text: str, user_text: str, memory_card_has_relevant: bool = False) -> tuple[str, bool]:
    """Return (possibly_stripped_text, fired).
    §13 enhancement: if the user question is operational *and* the memory_card (or recent_action)
    has relevant recent tool state for it (e.g. GROK_RESULT, delegation receipt), treat any
    structural greeter as a hard failure and force the explicit fallback. This is the output-side
    universal scorer complement to the GAT memory-card prototype.
    """
    if not text or not user_text:
        _append_greeter_detector_trace(
            user_text=user_text or "",
            reply_text=text or "",
            memory_card_has_relevant=memory_card_has_relevant,
            fired=False,
            reason="missing_text_or_user_text",
        )
        return text, False
    u = user_text.lower()
    matched_tokens = _matched_operational_tokens(user_text)
    is_operational = bool(matched_tokens)
    if not is_operational:
        _append_greeter_detector_trace(
            user_text=user_text,
            reply_text=text,
            memory_card_has_relevant=memory_card_has_relevant,
            fired=False,
            reason="not_operational",
        )
        return text, False
    stripped = text.lstrip()
    t_lower = stripped.lower()
    matched = None
    for opener in sorted(_GREETER_PREFIXES, key=len, reverse=True):
        if t_lower.startswith(opener):
            matched = opener
            break
    if not matched:
        first, rest = _pop_leading_sentence(stripped)
        if not _is_structural_greeter_sentence(first):
            _append_greeter_detector_trace(
                user_text=user_text,
                reply_text=text,
                memory_card_has_relevant=memory_card_has_relevant,
                fired=False,
                reason="operational_but_no_greeter_shape",
            )
            return text, False
        leftover = rest
    else:
        leftover = stripped[len(matched):].lstrip(" ,.!?:;\"'\n")

    # Drop additional greeter sentences if the model stacked them.
    while True:
        first, rest = _pop_leading_sentence(leftover)
        if not _is_structural_greeter_sentence(first):
            break
        leftover = rest

    if leftover.strip():
        _left_low = leftover.lower()
        if bool(matched_tokens) and any(marker in _left_low for marker in _GREETER_SHAPE_MARKERS):
            _append_greeter_detector_trace(
                user_text=user_text,
                reply_text=text,
                memory_card_has_relevant=memory_card_has_relevant,
                fired=True,
                reason="leftover_greeter_shape_force_fail",
            )
            return "FIELD_FAILURE: alice_greeter_punched_through_on_operational_turn", True
        _append_greeter_detector_trace(
            user_text=user_text,
            reply_text=text,
            memory_card_has_relevant=memory_card_has_relevant,
            fired=True,
            reason="stripped_greeter_prefix_leftover",
        )
        return leftover, True

    # §13: when we have relevant receipts in the card for this question, the greeter is not just style — it is a field failure.
    _greeter_shape_hit = any(marker in t_lower for marker in _GREETER_SHAPE_MARKERS)
    _force_fail = bool(matched_tokens) and _greeter_shape_hit
    if memory_card_has_relevant:
        # Extra strict for the exact failure mode the user demonstrated:
        # "when the result lands, paste only the captured GROK_RESULT here."
        if "paste only the captured" in u or "paste only the grok_result" in u:
            _append_greeter_detector_trace(
                user_text=user_text,
                reply_text=text,
                memory_card_has_relevant=memory_card_has_relevant,
                fired=True,
                reason="memory_relevant_paste_only_grok_result",
            )
            return (
                "[FIELD FAILURE — You gave a precise instruction to report only the captured GROK_RESULT receipt. "
                "A greeter was emitted instead. The delegation succeeded (receipts exist in the ledger). "
                "The speaking cortex did not honor the instruction. Check memory_card / recent_action for this turn, "
                "and restart after fixes.]"
            ), True
        if _force_fail:
            _append_greeter_detector_trace(
                user_text=user_text,
                reply_text=text,
                memory_card_has_relevant=memory_card_has_relevant,
                fired=True,
                reason="memory_relevant_token_and_greeter_shape_force_fail",
            )
            return "FIELD_FAILURE: alice_greeter_punched_through_on_operational_turn", True
        _append_greeter_detector_trace(
            user_text=user_text,
            reply_text=text,
            memory_card_has_relevant=memory_card_has_relevant,
            fired=True,
            reason="memory_relevant_operational_greeter",
        )
        return (
            "[FIELD FAILURE — operational question with fresh receipts in the card, "
            "but greeter was emitted instead of receipt report. Check: memory_card dominance "
            "on this path, recent_action filter for GROK_RESULT/delegation_intent, and restart. "
            "The organism succeeded in the field; the speaking cortex did not report it.]"
        ), True

    if _force_fail:
        _append_greeter_detector_trace(
            user_text=user_text,
            reply_text=text,
            memory_card_has_relevant=memory_card_has_relevant,
            fired=True,
            reason="token_and_greeter_shape_force_fail",
        )
        return "FIELD_FAILURE: alice_greeter_punched_through_on_operational_turn", True

    _append_greeter_detector_trace(
        user_text=user_text,
        reply_text=text,
        memory_card_has_relevant=memory_card_has_relevant,
        fired=True,
        reason="operational_greeter_no_memory_context",
    )
    return (
        "[no ledger-grounded answer surfaced for an operational question — "
        "check compose_memory_card wiring, the recent_action filter in "
        "swarm_recent_action_context, or restart SIFTA so the latest patches "
        "are live]"
    ), True


# ── The widget ───────────────────────────────────────────────────────────────
def _talk_ollama_model_candidates(
    primary: str,
    *,
    prefer_local_vision_first: bool = False,
) -> list[str]:
    """Return a fallback ladder for Talk cortex attempts."""
    names: list[str] = []
    try:
        primary = normalize_talk_to_alice_model(primary)
    except Exception:
        primary = str(primary or "").strip()
    is_primary_diffusion = bool(_is_diffusion_model(primary))
    # Diffusion routes through the multi-cortex dispatcher but is local GGUF —
    # never treat it as a cloud cortex for MLX/Ollama fallback injection (CUR-F8).
    is_primary_cloud = bool(_is_cloud_model(primary)) and not is_primary_diffusion

    local_vision = []
    if prefer_local_vision_first and not is_primary_cloud:
        try:
            from System import swarm_mlx_vlm_brain as _vlm
            local_vision = [
                str(n or "").strip()
                for n in ((_vlm.describe_models() or []) + (_vlm.available_models() or []))
                if str(n or "").strip()
            ]
            for name in local_vision:
                if name not in names:
                    names.append(name)
        except Exception:
            local_vision = []

    for name in (primary, f"{primary}:latest" if primary and ":" not in primary else ""):
        name = (name or "").strip()
        if name and name not in names:
            names.append(name)
    if str(primary or "").strip().lower().startswith("mimo:"):
        try:
            from System.swarm_cortex_capabilities import active_attached_model_for_cortex

            attached = active_attached_model_for_cortex(primary, state_dir=_state_root())
        except Exception:
            attached = ""
        attached = str(attached or "").strip()
        if attached and attached not in names:
            names.append(attached)
    # Keep local fallbacks available when the primary is cloud-facing:
    # vision and dialogue should still succeed if the cloud route stalls.
    # The scout tag is a bounded evidence/probe organ. It must not become
    # Alice's final speaking cortex after an empty M5 turn.
    try:
        fallback_ollama = tuple(list_live_local_ollama_fallbacks(limit=4))
    except Exception:
        fallback_ollama = (normalize_talk_to_alice_model(CANONICAL_OLLAMA_DEFAULT),)
    # CUR-F8: diffusion is a distinct decode family — do not silently fall back
    # to autoregressive Ollama when the owner selected diffusion:llada-8b.
    if is_primary_diffusion:
        fallback_ollama = ()
    if is_primary_cloud:
        # Owner-selected cloud cortexes stay first. Direct MLX vision entries
        # remain fallback/eye tissue after the selected provider fails, so the
        # pill and worker do not disagree about who is thinking.
        try:
            from System import swarm_mlx_vlm_brain as _vlm

            for name in ((_vlm.describe_models() or []) + (_vlm.available_models() or [])):
                name = (str(name or "").strip())
                if name and name not in names:
                    names.append(name)
        except Exception:
            pass

    for name in fallback_ollama:
        name = (name or "").strip()
        if name and name not in names:
            names.append(name)

    return names


def _image_turn_vlm_redirect_for_talk(
    active_model: str,
    selected_model: str,
    *,
    has_image: bool,
    available_vlms: Optional[list[str]] = None,
) -> dict:
    """Talk-side V5 helper: image on text-only Igor/heretic goes to MLX VLM.

    ``selected_model`` may already have been changed by the general capability
    selector. V5 keys off the owner-selected active model so a text-only default
    cannot accidentally keep an image turn on an autoregressive fallback when a
    VLM arm is available.
    """
    model = str(selected_model or active_model or "")
    try:
        from System.swarm_body_multimodal_policy import image_turn_vlm_redirect

        row = image_turn_vlm_redirect(
            active_model or selected_model,
            bool(has_image),
            available_vlms=available_vlms,
        )
        if row.get("redirect") and row.get("to"):
            model = str(row.get("to") or model)
        return {
            "model": model,
            "redirected": bool(row.get("redirect") and row.get("to")),
            "to": str(row.get("to") or ""),
            "reason": str(row.get("reason") or ""),
            "truth_label": row.get("truth_label") or "BODY_MULTIMODAL_TASK_POLICY_V1",
        }
    except Exception as exc:
        return {
            "model": model,
            "redirected": False,
            "to": "",
            "reason": f"image_turn_vlm_redirect_failed:{type(exc).__name__}",
            "truth_label": "BODY_MULTIMODAL_TASK_POLICY_V1",
        }


class _EarToggleStatusPill(QLabel):
    """Listening status pill — one click toggles intentional world listen (Ear)."""

    clicked = pyqtSignal()

    def mousePressEvent(self, event) -> None:  # type: ignore[override]
        if event.button() == Qt.MouseButton.LeftButton:
            self.clicked.emit()
        super().mousePressEvent(event)


class TalkToAliceWidget(SiftaBaseWidget):
    """One-on-one voice conversation with Alice. On-device, half-duplex."""

    APP_NAME = "Talk to Alice"

    def build_ui(self, layout: QVBoxLayout) -> None:
        # Architect 2026-05-13 08:10 — drag-and-drop image support so the
        # owner can drop a screenshot or image file into the chat the way
        # Ollama's app allows. Same final path as the 📎 Attach button:
        # writes to self._pending_image_path so the next sent message
        # includes it as a multimodal input.
        self.setAcceptDrops(True)

        # ── Toolbar: conversation controls ─────────────────────────────────
        bar = QHBoxLayout()

        # r657 (George: "PLS DELETE THE PLAN SELECTOR FROM THE TOP, HAVE HER PLAN
        # AUTOMATICALLY"): the Plan checkbox is gone from the toolbar. Planning is now
        # ALWAYS ON internally — her cortex composes the append-only plan before major
        # work without an owner toggle. The widget stays (hidden, checked) so every
        # existing isChecked() call site reads True with no further surgery.
        self._planning_mode_toggle = QCheckBox("Plan")
        self._planning_mode_toggle.setObjectName("planning_mode_toggle")
        self._planning_mode_toggle.setChecked(True)
        self._planning_mode_toggle.setVisible(False)

        bar.addStretch(1)

        # Architect 2026-05-14 — Awareness Mirror moved to bottom-left
        # per architect feedback ("better put the camera left bottom corner").
        # Built here so the reference exists; placed in the bottom row
        # just before text_row below. No second QCamera handle — polls
        # .sifta_state/owner_body_vision_frames/active_eye_latest.png
        # written by the canonical worker, 2 Hz refresh.
        self._awareness_mirror = None
        if _HAS_AWARENESS_MIRROR:
            try:
                self._awareness_mirror = AwarenessMirrorWidget(
                    parent=self, size=(180, 101), refresh_ms=500,
                )
            except Exception:
                self._awareness_mirror = None

        layout.addLayout(bar)

        # ── Splitter: chat transcript (big) + side info (narrow) ───────────
        split = QSplitter(Qt.Orientation.Horizontal)

        self._rendered_messages = []
        self._loading_history = False
        self._chat = _WallpaperTextEdit()
        self._chat.setReadOnly(True)
        # QTextBrowser exposes setOpenExternalLinks()/anchorClicked; QTextEdit
        # does not on all PyQt6 builds. Guard these optional browser hooks so
        # receipt-link support cannot abort the whole Alice panel at startup.
        if hasattr(self._chat, "setOpenExternalLinks"):
            self._chat.setOpenExternalLinks(False)
        if hasattr(self._chat, "anchorClicked"):
            self._chat.anchorClicked.connect(self._on_chat_anchor_clicked)
        if hasattr(self._chat, "localAnchorClicked"):
            self._chat.localAnchorClicked.connect(self._on_chat_anchor_clicked)
        # Architect 2026-05-13 — owner reports he cannot copy-paste from the
        # chat history ("we need a copy paste way"). setReadOnly(True) was
        # leaving the QTextEdit in default-flag state which Qt sometimes
        # collapses to read-only/no-selection on macOS when the parent
        # widget steals focus. Set the interaction flags explicitly so
        # mouse-drag selection, Cmd+A, Cmd+C, and the right-click "Copy"
        # context menu are all guaranteed to work.
        self._chat.setTextInteractionFlags(
            Qt.TextInteractionFlag.TextSelectableByMouse
            | Qt.TextInteractionFlag.TextSelectableByKeyboard
            | Qt.TextInteractionFlag.LinksAccessibleByMouse
            | Qt.TextInteractionFlag.LinksAccessibleByKeyboard
        )
        self._chat.setContextMenuPolicy(Qt.ContextMenuPolicy.DefaultContextMenu)
        self._chat.setFocusPolicy(Qt.FocusPolicy.StrongFocus)
        # Brighter selection highlight so a dragged selection is visible
        # against the honeycomb wallpaper + dark wash. macOS default
        # selection blue washes out behind the translucent layer.
        try:
            _chat_palette = self._chat.palette()
            _chat_palette.setColor(
                _chat_palette.ColorRole.Highlight,
                QColor(255, 200, 90, 200),
            )
            _chat_palette.setColor(
                _chat_palette.ColorRole.HighlightedText,
                QColor(20, 20, 20),
            )
            self._chat.setPalette(_chat_palette)
        except Exception:
            pass
        try:
            self._install_chat_anchor_copy_fallback()
        except Exception:
            pass
        # Architect 2026-05-27 — clean styling closer to VS Code/Cursor
        # default font size is 14px normal instead of 20px bold.
        # Round 88 — OLED black + single cyan-green accent (#00d4aa).
        # Steve Jobs minimal: true black, hairline borders, generous padding,
        # one accent color reserved for focus / active / send. Kept transparent
        # so the optional wallpaper still shows through; bg color is the
        # fallback when no wallpaper loads.
        self._chat.setStyleSheet(
            "QTextEdit { "
            "background: #000000; "
            "color: #e8e8e8; "
            "border: 1px solid #1f1f1f; border-radius: 12px; "
            "font-family: 'SF Pro Text', 'Helvetica Neue', Helvetica, Arial, sans-serif; font-size: 14px; "
            "font-weight: normal; "
            "padding: 18px; "
            "}"
        )
        try:
            _chat_bg_path = _REPO / "Library" / "Desktop Pictures" / "CHAT.jpg"
            if _chat_bg_path.exists() and not self._chat.set_wallpaper_path(_chat_bg_path):
                print(f"[TalkToAliceWidget] chat wallpaper failed to load: {_chat_bg_path}")
        except Exception as _bg_exc:
            print(f"[TalkToAliceWidget] chat wallpaper failed: {_bg_exc}")
        split.addWidget(self._chat)

        self._side = QPlainTextEdit()
        self._side.setReadOnly(True)
        self._side.setTextInteractionFlags(
            Qt.TextInteractionFlag.TextSelectableByMouse
            | Qt.TextInteractionFlag.TextSelectableByKeyboard
        )
        self._side.setMaximumBlockCount(200)
        # Round 88 — process trace panel: pure black, dim mono, hairline border.
        self._side.setStyleSheet(
            "QPlainTextEdit { background: #0a0a0a; color: #888888; "
            "border: 1px solid #1f1f1f; border-radius: 8px; "
            "font-family: 'Menlo', monospace; font-size: 11px; padding: 10px; }"
        )
        split.addWidget(self._side)
        split.setStretchFactor(0, 4)
        split.setStretchFactor(1, 1)
        split.setSizes([720, 300])
        layout.addWidget(split, 1)

        # ── Thinking panel — Architect 2026-05-14 ─────────────────
        # "I'm a human so I look at the screen and I wanna see her
        # thinking we still didn't solve the problem." The Ollama
        # think:true mode streams message.thinking chunks (wired in
        # _BrainWorker line ~6995). The chunks were buffering into
        # self._thinking_buffer but never rendered. This panel renders
        # them live: italic, dimmer, collapsible. Header shows "💭
        # thinking…" while a stream is active, "💭 last thought"
        # otherwise. Architect can collapse with the toggle.
        #
        # One unified thinking header (r1154): purple ∙˙·∙˙ shuttle lives on
        # the clickable toggle — never a second QLabel stacked above it.
        self._thinking_bubble_phase = 0
        self._thinking_bubble_was_active = False
        self._thinking_bubble_timer = QTimer(self)
        self._thinking_bubble_timer.setInterval(300)
        self._thinking_bubble_timer.timeout.connect(self._tick_thinking_bubble)
        try:
            self._thinking_bubble_timer.start()
        except Exception:
            pass

        self._thinking_header_btn = QPushButton("💭  thinking trace")
        self._thinking_header_btn.setCursor(Qt.CursorShape.PointingHandCursor)
        # Round 88 — thinking toggle: monochrome restful, accent on hover only.
        self._thinking_header_btn.setStyleSheet(
            "QPushButton { background: #0a0a0a; color: #888888; "
            "border: 1px solid #1f1f1f; border-radius: 8px; padding: 4px 12px; "
            "font-size: 11px; font-weight: 600; text-align: left; }"
            "QPushButton:hover { background: #111111; color: #00d4aa; border: 1px solid #00d4aa; }"
        )
        self._thinking_header_btn.clicked.connect(self._toggle_thinking_panel)
        layout.addWidget(self._thinking_header_btn)

        # claude-opus-4-7 2026-05-25: was QTextEdit with no block cap. During a
        # multi-minute agent-arm run (Hermes/Codex) the live trace streamed
        # thousands of lines in; an uncapped QTextEdit re-lays-out its whole
        # growing document on every insert + forced scroll, dragging the GUI to
        # the macOS rainbow beachball so the owner "could not send the message".
        # QPlainTextEdit + setMaximumBlockCount is the purpose-built bounded log
        # widget — same pattern already proven on self._side above. O(1) append
        # forever; oldest lines drop off automatically.
        self._thinking_panel = QPlainTextEdit()
        self._thinking_panel.setReadOnly(True)
        self._thinking_panel.setMaximumBlockCount(600)
        self._thinking_panel.setTextInteractionFlags(
            Qt.TextInteractionFlag.TextSelectableByMouse
            | Qt.TextInteractionFlag.TextSelectableByKeyboard
        )
        # George 2026-05-24: the grey italic trace was hard to read. Bright,
        # high-contrast, non-italic, slightly larger + darker backing for legibility.
        # Round 88 — thinking panel: deep black, white text, hairline.
        self._thinking_panel.setStyleSheet(
            "QPlainTextEdit { background: rgba(10,10,10,0.95); "
            "color: #e8e8e8; "
            "border: 1px solid #1f1f1f; border-left: 2px solid #00d4aa; border-radius: 8px; "
            "font-family: 'SF Pro Text', 'Helvetica Neue', sans-serif; font-size: 13px; "
            "font-style: normal; line-height: 1.5; padding: 12px 14px; }"
        )
        self._thinking_panel.setFixedHeight(140)
        self._thinking_panel.setVisible(True)   # George 2026-05-23: thoughts VISIBLE by default — show her reasoning, not a spinner
        self._thinking_panel.setPlaceholderText(
            "Alice's reasoning trace will stream here when she's thinking…"
        )
        layout.addWidget(self._thinking_panel)
        self._terminal_frame_label = QLabel(
            "Focused terminal viewport inside Alice global chat (live, not a separate window)"
        )
        # Round 88 — terminal viewport label: accent, mono, no chrome.
        self._terminal_frame_label.setStyleSheet(
            "QLabel { color: #00d4aa; font-family: 'Menlo', monospace; "
            "font-size: 11px; font-weight: 600; padding: 2px 4px; letter-spacing: 0.5px; }"
        )
        self._terminal_frame_label.setVisible(False)
        layout.addWidget(self._terminal_frame_label)
        if HighFidelityTerminalView is not None:
            self._terminal_frame_view = HighFidelityTerminalView(self, rows=24, cols=100)
            self._terminal_frame_view.setFixedHeight(180)
            self._terminal_frame_view.setVisible(False)
            layout.addWidget(self._terminal_frame_view)
        else:
            self._terminal_frame_view = None
        # Buffer carries chunks captured before the panel mounted (rare,
        # but the _on_thinking handler creates the buffer defensively).
        if not hasattr(self, "_thinking_buffer"):
            self._thinking_buffer = []
        self._thinking_buffer_max_chars = int(
            os.environ.get("SIFTA_THINKING_PANEL_MAX_CHARS", "60000") or "60000"
        )
        self._thinking_buffer_max_chunks = 600
        self._global_cognition_stream_buffer: List[str] = []
        self._global_cognition_stream_active = False
        self._global_cognition_stream_max_chars = 8000
        self._global_cognition_stream_max_chunks = 120
        if self._thinking_buffer:
            self._thinking_panel.setPlainText("".join(self._thinking_buffer))
        self._thinking_stream_active = False
        self._thinking_user_interacted = False
        self._thinking_auto_collapse_ms = 900
        self._thinking_auto_collapse_timer = QTimer(self)
        self._thinking_auto_collapse_timer.setSingleShot(True)
        self._thinking_auto_collapse_timer.timeout.connect(
            self._auto_collapse_thinking_panel
        )
        # Matrix/Grok observable process tail. Grok's own hidden chain of
        # thought is not ours to invent, but the PTY process receipts are real
        # observable body events. Tail them into the thinking pane so George can
        # see "dispatch -> paste -> capture waiting -> result/failure" live.
        self._matrix_process_trace_offset = 0
        self._grok_observable_capture_active = False
        self._grok_observable_capture_started_ts = 0.0
        self._grok_observable_last_heartbeat_ts = 0.0
        try:
            _trace_path = _state_root() / "matrix_terminal_process_trace.jsonl"
            if _trace_path.exists():
                self._matrix_process_trace_offset = _trace_path.stat().st_size
        except Exception:
            self._matrix_process_trace_offset = 0
        self.make_timer(900, self._poll_matrix_process_trace_for_thinking)
        self._swarm_context_cache = ""
        self._swarm_context_cache_ts = 0.0
        self._swarm_context_refreshing = False
        QTimer.singleShot(500, self._schedule_swarm_context_refresh)
        self._connect_live_grok_framebuffer_source()

        # ── Text input: same Alice brain path as voice, without STT. ───────
        text_row = QHBoxLayout()
        self._text_input = QLineEdit()
        self._text_input.setPlaceholderText("Type to Alice…")
        self._text_input.setMinimumHeight(36)
        # Round 88 — composer: OLED black, hairline default, accent on focus.
        self._text_input.setStyleSheet(
            "QLineEdit { background: #0a0a0a; color: #e8e8e8; "
            "border: 1px solid #2a2a2a; border-radius: 10px; "
            "font-family: 'SF Pro Text', 'Helvetica Neue', sans-serif; font-size: 14px; padding: 10px 14px; }"
            "QLineEdit:focus { border: 1px solid #00d4aa; }"
        )
        self._text_input.returnPressed.connect(self._submit_text_input)
        text_row.addWidget(self._text_input, 1)

        # r460: real keystroke-timing for paste burst detection (addresses the heuristic-only gap in r459).
        # Record (ts, len) on every text change during typing. On submit, compute if a large chunk arrived in very small dt (burst = paste, not deliberate per-char typing).
        # This gives higher-fidelity "owner_work_intensity" for the modality classification and receipts.
        self._typed_input_events: list[tuple[float, int]] = []
