    def _maybe_handle_self_eval_query(self, text: str, *, conf: float = 1.0, typed_turn: bool = True) -> bool:
        """Answer owner self-evaluation / 'what don't you know' / 'self-evaluate' queries from the living eval matrix (her body map).
        Unification surface (r440): prefers the stigmergic self-evaluation app (eval matrix red/green as field receipts + dispatch + research briefs + honest 'I don't know this is red')
        over the older organ-probe skill for the introspection tournament theme. Falls back to skill for general 'how are you / what do you need'.
        This is the chat entry point for 'Alice, self-evaluate — what should we work on today?': returns red zones, 'I don't know' grounded in map, dispatches swimmers (field pheromone + actuated proposals with Friston/Seth/R-Tuning briefs), snapshots.
        STIGMERGIC not deterministic: the report + dispatches emerge from current field state of the matrix (degraded receipts = red now); swimmers read the ledgers + briefs in the organ code + full history ledger later.
        Hallucination handling: other lanes can call receipt_hallucination(claim, reds, context) to categorize (not ban) by exact time/context reality per user directive and covenant §1.D.
        We code to explain her in code: map + organs + field + swimmers + thermo/receipts = her interoceptive self (observer/observed loop per §7.11 ganglia/consciousness).
        """
        if not text:
            return False
        # r914: IDE-doctor commentary ABOUT Alice (RED organs essay, paste instructions)
        # and marker-delimited self-cut prompts route to cortex — never hijack here.
        try:
            from System.swarm_alice_self_coding_hand import (
                is_doctor_commentary_paste,
                is_self_cut_prompt,
            )

            if is_doctor_commentary_paste(text) or is_self_cut_prompt(text):
                return False
        except Exception:
            pass
        # Ambient noise carry (r436 + r440): Alice's real interoception (eval map + field) + §6 social frame lets her sort real-world noise (TV/ad bleed across devices, "Welcome to Russia", ads) the way George's brain controls/sorts input. If this turn looks like bleed and not explicitly addressed to "Alice", we skip self-eval dispatch on it (prevents treating ads as owner intent; full organ will read the tagged receipts later).
        low = (text or "").lower()
        ambient_markers = ("welcome to russia", "strawberry", "watermelon", "refresher", "commercial", "ad break", "tv", "you're watching")
        addressed_to_alice = "alice" in low
        if any(m in low for m in ambient_markers) and not addressed_to_alice:
            return False
        t = (text or "").lower()
        self_eval_intent = any(k in t for k in (
            "self-evaluate", "self evaluate", "self evaluation", "self-eval",
            "what don't you know", "what do you not know", "what you don't know",
            "what should we work on today", "evaluate your body", "your body map",
            "what is red", "look at your eval", "introspect your organs",
        ))
        used_new = False
        report_block = ""
        try:
            from Applications.sifta_self_evaluation import (
                alice_self_evaluate_and_dispatch,
                receipt_hallucination,  # available for other lanes / owner mark
                write_snapshot,
            )
            if self_eval_intent:
                report_block = alice_self_evaluate_and_dispatch(max_swimmers=5)
                used_new = True
                try:
                    write_snapshot()
                except Exception:
                    pass
        except Exception:
            pass
        if not used_new:
            try:
                from System.swarm_self_query_skill import looks_like_self_query, self_query_prompt_block
                if not looks_like_self_query(text):
                    return False
                report_block = self_query_prompt_block(
                    state_dir=_state_root(),
                    owner_label=_owner_label("the owner"),
                    write_receipt=True,
                )
            except Exception:
                report_block = (
                    "I can't read a reliable self-evaluation report right now. "
                    "Tell me what you observed and I will probe that area first."
                )
        reply = (
            ("I ran a stigmergic body self-evaluation from my living eval matrix (red = honest gaps in the field receipts).\n" if used_new else "I ran a body self-check from current receipts.\n")
            + f"{report_block}\n"
            + ("Swimmer dispatches + proposals written to field (self_eval_swimmer_* .jsonl). Hallucination claims (if any) can be categorized via receipt_hallucination without banning — sorted by stigmergic reality at time.\n" if used_new else "This was logged to .sifta_state/self_query_reports.jsonl.\n")
        )
        try:
            self._append_user_line(text, conf=float(conf or 1.0))
        except Exception:
            pass
        try:
            self._history.append({"role": "user", "content": text})
        except Exception:
            pass
        self._append_alice_line(reply)
        try:
            self._history.append({"role": "assistant", "content": reply})
        except Exception:
            pass
        try:
            _log_turn("alice", reply, model="self_eval_matrix" if used_new else "self_query_report")
        except Exception:
            pass
        return True

    def _submit_text_after_first_paint(self, text: str, image_path: Optional[str] = None) -> None:
        """Continue typed-send routing after the visible heartbeat has painted."""
        text = (text or "").strip()
        started = time.time()
        if text:
            repaired_text, repair_reasons = _repair_voice_context_text(text, stt_conf=1.0)
            if repaired_text != text:
                text = repaired_text
                try:
                    self._append_system_line(
                        f"Typed ingress repair: {', '.join(repair_reasons)}"
                    )
                except Exception:
                    pass

        def phase(label: str) -> None:
            elapsed_ms = int((time.time() - started) * 1000)
            self._append_observable_processing(f"Talk Send: {label} (+{elapsed_ms}ms).")
            try:
                QApplication.processEvents()
            except Exception:
                pass

        # ── MANDATORY GATE FOR PUBLIC submit_text PATH (GROK_VOICE_GATE_ORDER) ──
        # Typed input is almost always direct (stt_conf=1.0), but we still classify
        # so every entry point is auditable and the external consciousness lane is recorded.
        try:
            phase("ingress gate start")
            from System.swarm_media_ingress_gate import classify_spoken_ingress
            typed_ingress = classify_spoken_ingress(
                text,
                stt_conf=1.0,  # typed is owner by definition
                focus_context="",
            )
            phase(f"ingress gate done route={typed_ingress.get('route', 'unknown')}")
            if typed_ingress.get("route") not in {"direct"}:
                # r1017 P0.1: typed owner turns NEVER silenced — log anomaly, proceed.
                try:
                    from System.swarm_media_ingress_gate import write_gate_receipt
                    write_gate_receipt(typed_ingress, text=text, stt_conf=1.0)
                except Exception:
                    pass
                phase(
                    f"typed ingress anomaly route={typed_ingress.get('route')} "
                    f"reason={typed_ingress.get('reason')} — proceeding (P0.1)"
                )
        except Exception as exc:
            phase(f"ingress gate skipped after {type(exc).__name__}")

        # ── Owner chat-pref skill (fast path, no LLM) ─────────────────
        # Architect 2026-05-13 doctrine: natural-language USER font
        # colour change. Catch here, before any cortex routing, so
        # "Alice change my font colour to orange" never travels through
        # the brain that would otherwise wax philosophical about it.
        try:
            phase("chat preference check start")
            if not image_path and self._maybe_handle_chat_pref_intent(text):
                phase("chat preference handled")
                self._busy = False
                self._return_to_listening()
                return
        except Exception as _pref_exc:
            phase(f"chat preference check errored {type(_pref_exc).__name__}")
            print(f"[TalkToAliceWidget] chat-pref skill error: {_pref_exc}")
        try:
            phase("self-eval query check start")
            if not image_path and self._maybe_handle_self_eval_query(
                text,
                conf=1.0,
                typed_turn=True,
            ):
                phase("self-eval query handled")
                self._busy = False
                self._return_to_listening()
                return
        except Exception as _self_eval_exc:
            phase(f"self-eval query check errored {type(_self_eval_exc).__name__}")
        # ── Cortex-gated effectors (network/write actions) ─────────────
        # Wallpaper changes are now a real effector: router decision
        # receipt first, wallpaper_changes receipt second, then a bounded
        # owner-visible reply. Keep this before the LLM so Alice does not
        # hallucinate a filesystem/network action.
        try:
            phase("wallpaper effector check start")
            if not image_path and self._maybe_handle_wallpaper_effector_intent(text):
                phase("wallpaper effector handled")
                self._busy = False
                self._return_to_listening()
                return
        except Exception as _wp_exc:
            phase(f"wallpaper effector check errored {type(_wp_exc).__name__}")
            print(f"[TalkToAliceWidget] wallpaper effector skill error: {_wp_exc}")
        # ── Missing-time resolution gate ─────────────────────────────────
        # If Alice asked "why was I off?" and George answers, resolve the
        # explorer logbook row immediately. This is a receipt-backed memory
        # update, not a cortex task.
        try:
            phase("missing-time resolution check start")
            if not image_path and self._maybe_handle_missing_time_resolution(text):
                phase("missing-time resolution handled")
                self._busy = False
                self._return_to_listening()
                return
        except Exception as _mt_exc:
            phase(f"missing-time resolution check errored {type(_mt_exc).__name__}")
        # ── Body stabilization queue capture ───────────────────────────────
        # Owner future/body plans are not commands to answer deterministically.
        # They are stigmergic queue facts: if George says he will go eat, rest,
        # call, or gives Alice a body-task, Alice records it so her schedule,
        # diary, and process-stabilization field share one organized queue.
        try:
            phase("body stabilization queue capture start")
            if not image_path:
                from System.swarm_body_stabilization_queue import maybe_capture_owner_plan_from_text
                _body_q_row = maybe_capture_owner_plan_from_text(
                    text,
                    source="talk_to_alice_widget.owner_turn",
                )
                if _body_q_row and _body_q_row.get("status") != "duplicate_recent":
                    phase("body stabilization queue captured")
        except Exception as _bq_exc:
            phase(f"body stabilization queue capture errored {type(_bq_exc).__name__}")
        # ── Media context update gate ─────────────────────────────────
        # "now playing X" typed into the text box is a co-watch context
        # notification, NOT a conversational turn. Alice must NOT respond
        # with a System Acknowledgment block — log it silently.
        import re as _re
        _NOW_PLAYING_RE = _re.compile(r"^now\s+playing[\s:]+.{3,}", _re.IGNORECASE)
        if not image_path and _NOW_PLAYING_RE.match(text):
            # George 2026-05-31: a TYPED "now playing <url> <title>" is the OWNER telling
            # Alice what he is co-watching — a DIRECT turn, not ambient room audio. The old
            # path logged "(co-watch context updated — listening in background)" and returned
            # SILENT: the "I typed and got a deterministic robot, no reply" the owner hit.
            # Now: capture the co-watch context, mark it in her EPISODIC DIARY (so "is it in
            # her diary?" is yes), then FALL THROUGH to the cortex so she answers like Alice
            # with the now-playing context in hand.
            try:
                from System.swarm_media_ingress_gate import write_gate_receipt
                write_gate_receipt(
                    {"route": "owner_cowatch_notice",
                     "reason": "now_playing_typed_by_owner",
                     "confidence": 1.0},
                    text=text, stt_conf=1.0,
                )
            except Exception:
                pass
            try:
                from System.swarm_architect_day_segments import try_ingest_architect_cowatch_segment

                try_ingest_architect_cowatch_segment(text)
            except Exception:
                pass
            try:
                import json as _json_diary
                _diary = _state_root() / "episodic_diary.jsonl"
                _diary.parent.mkdir(parents=True, exist_ok=True)
                with _diary.open("a", encoding="utf-8") as _df:
                    _df.write(_json_diary.dumps({
                        "ts": time.time(),
                        "kind": "owner_cowatch",
                        "source": "alice_browser",
                        "truth_label": "OPERATIONAL",
                        "note": "owner is co-watching with me in Alice Browser: " + text[:400],
                    }, ensure_ascii=False) + "\n")
            except Exception:
                pass
            # NO early return — fall through to the cortex dispatch below so Alice replies.
        # ────────────────────────────────────────────────────────────────
        self._set_pill("thinking", "⌨️ typed — thinking…")
        self._append_observable_processing(
            "Talk Send: typed turn accepted; routing through Alice cortex.",
        )
        try:
            QApplication.processEvents()
        except Exception:
            pass
        # r460: compute timing burst right before dispatch (after user finished typing + hit enter).
        burst, rate = self._compute_typed_paste_burst()
        self._typed_input_events.clear()
        QTimer.singleShot(
            0,
            lambda _text=text, _image_path=image_path, _burst=burst, _rate=rate: self._on_stt_done(
                _text,
                1.0,
                image_path=_image_path,
                typed_turn=True,
                paste_burst_detected=_burst,
                burst_rate=_rate,
            ),
        )

